function isFeatureEnabled(flag) {
  try {
    return !!window.UniversoRealFeatureFlags?.[flag];
  } catch (e) {
    return false;
  }
}
// Semente de dados de teste só por opt-in explícito (query param/localStorage).
const shouldSeedWorkSamples = (() => {
  try {
    const params = new URLSearchParams(window.location.search || '');
    if (params.get('seedWorkSamples') === '1') return true;
    return localStorage.getItem('oracle_seed_work_samples') === '1';
  } catch (e) {
    return false;
  }
})();

if (shouldSeedWorkSamples && !window._workTestInsertedImmediate) {
  window._workTestInsertedImmediate = true;
  setTimeout(() => {
    try {
      if (typeof window._insertSampleWorkDataForTesting === 'function') {
        window._insertSampleWorkDataForTesting();
        console.log('[TEST] Inserção de amostras habilitada por flag.');
      }
    } catch (e) {
      console.warn('[TEST] Falha ao inserir amostras:', e);
    }
  }, 250);
}

// Telemetria leve (console + localStorage)
window.OracleTelemetry = window.OracleTelemetry || {
  log(event, data = {}) {
    try {
      const cfg = window.OracleConfig || {};
      if (!cfg.telemetry) return;
      if (Math.random() > (cfg.telemetrySample ?? 1.0)) return;

      const payload = {
        t: new Date().toISOString(),
        event,
        ...data
      };

      console.debug('[OracleTelemetry]', payload);

      const key = 'oracle_telemetry';
      const arr = JSON.parse(localStorage.getItem(key) || '[]');
      arr.push(payload);
      while (arr.length > 200) arr.shift();
      localStorage.setItem(key, JSON.stringify(arr));
    } catch (_) {}
  }
};

// ---------- Helper de teste: insere dados de produção de massas para validar agrupamento por mês/semana
window._insertSampleWorkDataForTesting = function() {
  // Sincroniza estado local/global para evitar erro quando apenas `gameState` existe.
  let state = null;
  if (typeof gameState !== 'undefined' && gameState && typeof gameState === 'object') {
    state = gameState;
  } else if (window.gameState && typeof window.gameState === 'object') {
    state = window.gameState;
  } else {
    state = {};
  }

  window.gameState = state;
  if (typeof gameState !== 'undefined') {
    gameState = state;
  }

  if (!Array.isArray(state.workLog)) state.workLog = [];

  // Limpa amostras anteriores marcadas como test (mantém registros reais)
  state.workLog = state.workLog.filter((r) => !r._isTestSample);

  const samples = [
    // Mês 2026-01 (testar semanas 1..4)
    { date: '2026-01-03', inputVal: 10, type: 'pizzaria', isUnpaid: false, financialVal: 0, week: '1', month: '2026-01' },
    { date: '2026-01-05', inputVal: 8, type: 'pizzaria', isUnpaid: false, financialVal: 0, week: '1', month: '2026-01' },
    { date: '2026-01-10', inputVal: 12, type: 'pizzaria', isUnpaid: false, financialVal: 0, week: '2', month: '2026-01' },
    { date: '2026-01-12', inputVal: 7, type: 'pizzaria', isUnpaid: true, financialVal: 0, week: '2', month: '2026-01' },
    { date: '2026-01-18', inputVal: 15, type: 'pizzaria', isUnpaid: false, financialVal: 0, week: '3', month: '2026-01' },
    { date: '2026-01-21', inputVal: 9, type: 'pizzaria', isUnpaid: false, financialVal: 0, week: '3', month: '2026-01' },
    { date: '2026-01-25', inputVal: 20, type: 'pizzaria', isUnpaid: false, financialVal: 0, week: '4', month: '2026-01' },
    { date: '2026-01-30', inputVal: 5, type: 'pizzaria', isUnpaid: true, financialVal: 0, week: '4', month: '2026-01' },
    // Mês 2026-02 (para verificar filtro)
    { date: '2026-02-02', inputVal: 11, type: 'pizzaria', isUnpaid: false, financialVal: 0, week: '1', month: '2026-02' },
    { date: '2026-02-09', inputVal: 14, type: 'pizzaria', isUnpaid: false, financialVal: 0, week: '2', month: '2026-02' },
    { date: '2026-02-16', inputVal: 6, type: 'pizzaria', isUnpaid: false, financialVal: 0, week: '3', month: '2026-02' },
    { date: '2026-02-24', inputVal: 13, type: 'pizzaria', isUnpaid: false, financialVal: 0, week: '4', month: '2026-02' }
  ];

  const now = Date.now();
  samples.forEach(s => {
    state.workLog.push(Object.assign({
      timestamp: Date.parse(s.date) || now,
      _isTestSample: true
    }, s));
  });

  try {
    if (typeof saveGame === 'function') saveGame(true);
  } catch (e) {}

  if (typeof renderWorkHistory === 'function') {
    try {
      renderWorkHistory();
      console.log('[TEST] Inseridos', samples.length, 'registros de teste e renderWorkHistory() chamado.');
    } catch (e) {
      console.warn('[TEST] Inseridos amostras, mas renderWorkHistory() falhou:', e);
    }
  } else {
    console.log('[TEST] Inseridos', samples.length, 'registros de teste. Abra a aba Trabalho e chame renderWorkHistory() manualmente.');
  }
};
// Sistema de Som (Web Audio API) - Inicializado sob demanda
let audioCtx = null;

function getAudioContext() {
  if (!audioCtx) {
    try {
      audioCtx = new (window.AudioContext || window.webkitAudioContext)();
    } catch (e) {
      console.warn('AudioContext não suportado:', e);
      return null;
    }
  }
  return audioCtx;
}

const sounds = {
  click: () => {
    const ctx = getAudioContext();
    if (!ctx) return;
    if (ctx.state === 'suspended') ctx.resume();
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.connect(gain);
    gain.connect(ctx.destination);
    
    osc.type = 'sine';
    osc.frequency.setValueAtTime(600, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(100, ctx.currentTime + 0.1);
    
    gain.gain.setValueAtTime(0.05, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.1);
    
    osc.start();
    osc.stop(ctx.currentTime + 0.1);
  },
  
  levelUp: () => {
    const ctx = getAudioContext();
    if (!ctx) return;
    if (ctx.state === 'suspended') ctx.resume();
    const now = ctx.currentTime;
    
    [440, 554, 659, 880].forEach((freq, i) => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);
      
      osc.type = 'triangle';
      osc.frequency.value = freq;
      
      const startTime = now + i * 0.1;
      gain.gain.setValueAtTime(0, startTime);
      gain.gain.linearRampToValueAtTime(0.1, startTime + 0.05);
      gain.gain.exponentialRampToValueAtTime(0.01, startTime + 0.5);
      
      osc.start(startTime);
      osc.stop(startTime + 0.5);
    });
  },
  
  achievement: () => {
    const ctx = getAudioContext();
    if (!ctx) return;
    if (ctx.state === 'suspended') ctx.resume();
    const now = ctx.currentTime;
    
    [523.25, 659.25, 783.99, 1046.50].forEach((freq) => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);
      
      osc.type = 'square';
      osc.frequency.value = freq;
      
      gain.gain.setValueAtTime(0.05, now);
      gain.gain.exponentialRampToValueAtTime(0.01, now + 0.8);
      
      osc.start(now);
      osc.stop(now + 0.8);
    });
  }
};

function playSound(type) {
  try {
    if (sounds[type]) sounds[type]();
  } catch (e) {
    console.error("Audio error:", e);
  }
}

// Função para converter valores monetários (BR e Texto)
function parseMoney(input) {
  if (typeof input === 'number') return input;
  if (!input) return 0;
  
  let str = input.toString().toLowerCase().trim();
  
  // Multiplicadores (mil, k)
  let multiplier = 1;
  if (str.includes('mil') || str.includes('k')) {
    multiplier = 1000;
  }
  
  // Remove tudo que não é número, vírgula, ponto ou sinal
  str = str.replace(/[^0-9,.-]/g, '');
  
  // Lógica Brasileira: Ponto é milhar, Vírgula é decimal
  if (str.includes(',')) {
    // Tem vírgula - formato BR (ex: 1.234,56)
    str = str.replace(/\./g, '').replace(',', '.');
  } else if (str.includes('.')) {
    // Só tem ponto - verificar se é decimal ou milhar
    const parts = str.split('.');
    // Se a parte após o ponto tem 1 ou 2 dígitos, é decimal (ex: 1.5 ou 3.50)
    // Se tem 3 dígitos, é milhar (ex: 1.000)
    if (parts.length === 2 && parts[1].length <= 2) {
      // Mantém como decimal (1.5 = 1.5)
    } else {
      // Remove pontos de milhar (1.000 = 1000)
      str = str.replace(/\./g, '');
    }
  }
  
  return (parseFloat(str) || 0) * multiplier;
}

function sanitizePdfText(value) {
  return String(value ?? '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^\x20-\x7E]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function wrapPdfLine(text, maxLen = 90) {
  const normalized = sanitizePdfText(text);
  if (!normalized) return [''];
  if (normalized.length <= maxLen) return [normalized];

  const words = normalized.split(' ');
  const lines = [];
  let current = '';

  words.forEach((word) => {
    if (!current) {
      current = word;
      return;
    }
    if ((current.length + 1 + word.length) <= maxLen) {
      current += ` ${word}`;
    } else {
      lines.push(current);
      current = word;
    }
  });

  if (current) lines.push(current);
  return lines.length ? lines : [normalized.slice(0, maxLen)];
}

function escapePdfLiteral(text) {
  return String(text || '')
    .replace(/\\/g, '\\\\')
    .replace(/\(/g, '\\(')
    .replace(/\)/g, '\\)');
}

function buildSimplePdfDocument(title, lines) {
  const pageWidth = 595;
  const pageHeight = 842;
  const left = 48;
  const top = 800;
  const lineStep = 15;
  const maxLinesPerPage = 46;

  const titleLines = wrapPdfLine(title, 70);
  const bodyLines = [];
  (Array.isArray(lines) ? lines : []).forEach((line) => {
    wrapPdfLine(line, 95).forEach((part) => bodyLines.push(part));
  });

  const allLines = [...titleLines, '', ...bodyLines];
  const pages = [];
  for (let i = 0; i < allLines.length; i += maxLinesPerPage) {
    pages.push(allLines.slice(i, i + maxLinesPerPage));
  }
  if (!pages.length) pages.push(['Relatorio sem dados.']);

  const objects = {};
  objects[1] = '<< /Type /Catalog /Pages 2 0 R >>';
  objects[3] = '<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>';

  let nextObjId = 4;
  const pageIds = [];

  pages.forEach((pageLines) => {
    const pageId = nextObjId++;
    const contentId = nextObjId++;
    pageIds.push(pageId);

    const streamParts = ['BT', '/F1 11 Tf', `${left} ${top} Td`];
    pageLines.forEach((line, index) => {
      if (index > 0) streamParts.push(`0 -${lineStep} Td`);
      streamParts.push(`(${escapePdfLiteral(line)}) Tj`);
    });
    streamParts.push('ET');

    const stream = streamParts.join('\n');
    objects[contentId] = `<< /Length ${stream.length} >>\nstream\n${stream}\nendstream`;
    objects[pageId] = `<< /Type /Page /Parent 2 0 R /MediaBox [0 0 ${pageWidth} ${pageHeight}] /Resources << /Font << /F1 3 0 R >> >> /Contents ${contentId} 0 R >>`;
  });

  objects[2] = `<< /Type /Pages /Count ${pageIds.length} /Kids [${pageIds.map((id) => `${id} 0 R`).join(' ')}] >>`;

  const maxObjId = Math.max(...Object.keys(objects).map((k) => Number(k)));
  const offsets = new Array(maxObjId + 1).fill(0);

  let pdf = '%PDF-1.4\n';
  for (let id = 1; id <= maxObjId; id++) {
    const body = objects[id];
    if (!body) continue;
    offsets[id] = pdf.length;
    pdf += `${id} 0 obj\n${body}\nendobj\n`;
  }

  const xrefPos = pdf.length;
  pdf += `xref\n0 ${maxObjId + 1}\n`;
  pdf += '0000000000 65535 f \n';
  for (let id = 1; id <= maxObjId; id++) {
    const off = offsets[id] || 0;
    pdf += `${String(off).padStart(10, '0')} 00000 n \n`;
  }

  pdf += `trailer\n<< /Size ${maxObjId + 1} /Root 1 0 R >>\nstartxref\n${xrefPos}\n%%EOF`;
  return pdf;
}

function downloadPdfContent(fileName, pdfContent) {
  const blob = new Blob([pdfContent], { type: 'application/pdf' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = fileName;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  setTimeout(() => URL.revokeObjectURL(url), 3000);
}

function downloadPdfBytes(fileName, pdfBytes) {
  try {
    const hasArrayBuffer = (typeof ArrayBuffer !== 'undefined' && pdfBytes instanceof ArrayBuffer);
    const hasTypedArray = !!(pdfBytes && typeof pdfBytes === 'object' && pdfBytes.buffer instanceof ArrayBuffer);
    if (!hasArrayBuffer && !hasTypedArray) return false;

    const raw = hasArrayBuffer ? pdfBytes : pdfBytes.buffer;
    const blob = new Blob([raw], { type: 'application/pdf' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = String(fileName || 'relatorio.pdf').trim() || 'relatorio.pdf';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    setTimeout(() => URL.revokeObjectURL(url), 3000);
    return true;
  } catch (e) {
    return false;
  }
}

function arrayBufferToBase64String(sourceBuffer = null) {
  try {
    const hasArrayBuffer = (typeof ArrayBuffer !== 'undefined' && sourceBuffer instanceof ArrayBuffer);
    const hasTypedArray = !!(sourceBuffer && typeof sourceBuffer === 'object' && sourceBuffer.buffer instanceof ArrayBuffer);
    if (!hasArrayBuffer && !hasTypedArray) return '';
    const bytes = hasArrayBuffer
      ? new Uint8Array(sourceBuffer)
      : new Uint8Array(sourceBuffer.buffer, sourceBuffer.byteOffset || 0, sourceBuffer.byteLength || sourceBuffer.length || 0);
    if (!bytes.length) return '';
    let binary = '';
    const chunkSize = 0x8000;
    for (let i = 0; i < bytes.length; i += chunkSize) {
      const chunk = bytes.subarray(i, i + chunkSize);
      binary += String.fromCharCode.apply(null, chunk);
    }
    return btoa(binary);
  } catch (e) {
    return '';
  }
}

function base64StringToArrayBuffer(base64Data = '') {
  try {
    const raw = String(base64Data || '').trim();
    if (!raw) return null;
    const cleaned = raw
      .replace(/^data:application\/pdf;base64,/i, '')
      .replace(/^data:.*;base64,/i, '')
      .replace(/\s+/g, '');
    if (!cleaned) return null;
    const binary = atob(cleaned);
    const len = binary.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i += 1) {
      bytes[i] = binary.charCodeAt(i) & 0xff;
    }
    return bytes.buffer;
  } catch (e) {
    return null;
  }
}

