function getCurrentSessionEmail() {
  const fromSession = (typeof getSession === 'function')
    ? normalizeAuthEmail(getSession())
    : '';
  const fromState = normalizeAuthEmail(gameState?.username || '');
  return fromSession || fromState;
}

async function verifyPdfDownloadCredentials(email, password) {
  const safeEmail = normalizeAuthEmail(email);
  const safePassword = String(password || '');
  if (!safeEmail || !safePassword) {
    return { ok: false, message: 'Preencha email e senha.' };
  }

  const currentEmail = getCurrentSessionEmail();
  if (currentEmail && safeEmail !== currentEmail) {
    return { ok: false, message: 'Use o email da conta já logada no app.' };
  }

  try {
    const users = (typeof getUsers === 'function') ? getUsers() : {};
    const localKey = Object.keys(users || {}).find((k) => normalizeAuthEmail(k) === safeEmail) || '';
    if (localKey && users[localKey] && String(users[localKey].password || '') === safePassword) {
      return { ok: true };
    }
  } catch (e) {
    // Continua para validação na nuvem
  }

  if (useSupabase() && typeof SupabaseService !== 'undefined' && typeof SupabaseService.signIn === 'function') {
    let lastError = null;
    const candidates = (typeof buildAuthPasswordCandidates === 'function')
      ? buildAuthPasswordCandidates(safePassword)
      : [safePassword];
    for (const candidate of candidates) {
      try {
        await SupabaseService.signIn(safeEmail, candidate);
        return { ok: true };
      } catch (err) {
        lastError = err;
        if (typeof isInvalidCredentialsSupabaseAuthError === 'function' && isInvalidCredentialsSupabaseAuthError(err)) break;
      }
    }
    const mapped = (typeof mapSupabaseAuthError === 'function')
      ? mapSupabaseAuthError(lastError, 'Email ou senha inválidos.')
      : 'Email ou senha inválidos.';
    return { ok: false, message: mapped };
  }

  return { ok: false, message: 'Não consegui validar seu login agora.' };
}

function openPdfDownloadLoginModal(fileName = 'relatorio.pdf') {
  ensurePdfDownloadAuthStyles();
  return new Promise((resolve) => {
    let settled = false;
    const finish = (result) => {
      if (settled) return;
      settled = true;
      try { overlay.remove(); } catch (e) {}
      resolve(!!result);
    };

    const overlay = document.createElement('div');
    overlay.className = 'ur-pdf-auth-overlay';

    const orbA = document.createElement('div');
    orbA.className = 'ur-pdf-auth-orb a';
    const orbB = document.createElement('div');
    orbB.className = 'ur-pdf-auth-orb b';

    const card = document.createElement('div');
    card.className = 'ur-pdf-auth-card';

    const badge = document.createElement('div');
    badge.className = 'ur-pdf-auth-badge';
    badge.textContent = '🔐 Acesso protegido';

    const title = document.createElement('h3');
    title.className = 'ur-pdf-auth-title';
    title.textContent = 'Entrar para baixar PDF';

    const subtitle = document.createElement('p');
    subtitle.className = 'ur-pdf-auth-subtitle';
    subtitle.textContent = `Confirme sua conta para baixar: ${String(fileName || 'relatorio.pdf')}`;

    const form = document.createElement('form');
    form.className = 'ur-pdf-auth-form';

    const emailInput = document.createElement('input');
    emailInput.type = 'email';
    emailInput.className = 'ur-pdf-auth-input';
    emailInput.placeholder = 'Seu email';
    emailInput.required = true;

    const currentEmail = getCurrentSessionEmail();
    if (currentEmail) emailInput.value = currentEmail;

    const passwordInput = document.createElement('input');
    passwordInput.type = 'password';
    passwordInput.className = 'ur-pdf-auth-input';
    passwordInput.placeholder = 'Sua senha';
    passwordInput.required = true;
    passwordInput.autocomplete = 'current-password';

    const errorText = document.createElement('div');
    errorText.className = 'ur-pdf-auth-error';
    errorText.textContent = ' ';

    const actions = document.createElement('div');
    actions.className = 'ur-pdf-auth-actions';

    const cancelBtn = document.createElement('button');
    cancelBtn.type = 'button';
    cancelBtn.className = 'ur-pdf-auth-btn cancel';
    cancelBtn.textContent = 'Cancelar';

    const loginBtn = document.createElement('button');
    loginBtn.type = 'submit';
    loginBtn.className = 'ur-pdf-auth-btn login';
    loginBtn.textContent = 'Entrar e baixar';

    const setError = (message = '') => {
      const safe = String(message || '').trim();
      errorText.textContent = safe || ' ';
      errorText.classList.toggle('show', !!safe);
      if (safe) {
        card.classList.remove('shake');
        void card.offsetWidth;
        card.classList.add('shake');
      }
    };

    cancelBtn.addEventListener('click', () => finish(false));
    overlay.addEventListener('click', (ev) => {
      if (ev.target === overlay) finish(false);
    });

    form.addEventListener('submit', async (ev) => {
      ev.preventDefault();
      setError('');
      loginBtn.disabled = true;
      cancelBtn.disabled = true;
      loginBtn.textContent = 'Validando...';
      try {
        const result = await verifyPdfDownloadCredentials(emailInput.value, passwordInput.value);
        if (!result?.ok) {
          setError(result?.message || 'Não foi possível autenticar.');
          loginBtn.disabled = false;
          cancelBtn.disabled = false;
          loginBtn.textContent = 'Entrar e baixar';
          return;
        }
        finish(true);
      } catch (e) {
        setError('Falha ao validar login. Tente novamente.');
        loginBtn.disabled = false;
        cancelBtn.disabled = false;
        loginBtn.textContent = 'Entrar e baixar';
      }
    });

    actions.appendChild(cancelBtn);
    actions.appendChild(loginBtn);

    form.appendChild(emailInput);
    form.appendChild(passwordInput);
    form.appendChild(errorText);
    form.appendChild(actions);

    card.appendChild(badge);
    card.appendChild(title);
    card.appendChild(subtitle);
    card.appendChild(form);

    overlay.appendChild(orbA);
    overlay.appendChild(orbB);
    overlay.appendChild(card);

    document.body.appendChild(overlay);
    setTimeout(() => {
      try {
        if (currentEmail) {
          passwordInput.focus();
        } else {
          emailInput.focus();
        }
      } catch (e) {}
    }, 80);
  });
}

function pdfContentToUint8Array(pdfContent) {
  const safe = String(pdfContent || '');
  if (!safe) return new Uint8Array();
  try {
    if (typeof TextEncoder !== 'undefined') {
      return new TextEncoder().encode(safe);
    }
  } catch (e) {}
  const out = new Uint8Array(safe.length);
  for (let i = 0; i < safe.length; i += 1) {
    out[i] = safe.charCodeAt(i) & 0xff;
  }
  return out;
}

function openPdfPreviewInApp(fileName, pdfContent, savedPath = '', previewLines = [], binarySource = null) {
  try {
    const existing = document.getElementById('urPdfPreviewModal');
    if (existing) {
      try { existing.remove(); } catch (e) {}
    }

    const previousResize = window.__urPdfPreviewResizeHandler;
    if (typeof previousResize === 'function') {
      try { window.removeEventListener('resize', previousResize); } catch (e) {}
      window.__urPdfPreviewResizeHandler = null;
    }

    const overlay = document.createElement('div');
    overlay.id = 'urPdfPreviewModal';
    overlay.style.cssText = [
      'position:fixed',
      'inset:0',
      'z-index:99999',
      'background:rgba(0,0,0,0.86)',
      'display:flex',
      'align-items:center',
      'justify-content:center',
      'padding:12px'
    ].join(';');

    const card = document.createElement('div');
    card.style.cssText = [
      'width:min(980px,100%)',
      'height:min(92vh,100%)',
      'background:#111',
      'border:1px solid rgba(255,255,255,0.14)',
      'border-radius:12px',
      'overflow:hidden',
      'display:flex',
      'flex-direction:column'
    ].join(';');

    const header = document.createElement('div');
    header.style.cssText = [
      'display:flex',
      'align-items:center',
      'justify-content:space-between',
      'gap:8px',
      'padding:10px 12px',
      'background:rgba(255,255,255,0.06)',
      'border-bottom:1px solid rgba(255,255,255,0.12)'
    ].join(';');

    const title = document.createElement('div');
    title.style.cssText = 'font-weight:700; color:#fff; font-size:13px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;';
    title.textContent = `📄 ${fileName || 'Relatório PDF'}`;

    const closeBtn = document.createElement('button');
    closeBtn.type = 'button';
    closeBtn.textContent = 'Fechar';
    closeBtn.style.cssText = 'border:none; background:#d32f2f; color:#fff; border-radius:8px; padding:6px 10px; font-weight:700; cursor:pointer;';

    const body = document.createElement('div');
    body.style.cssText = 'position:relative; flex:1; background:#181818; display:flex; flex-direction:column; min-height:0;';

    const info = document.createElement('div');
    info.style.cssText = 'font-size:11px; color:#ddd; background:rgba(0,0,0,0.45); padding:8px 10px; border-radius:8px; margin:8px 8px 0;';
    info.textContent = savedPath
      ? `PDF salvo em: ${savedPath}`
      : 'PDF gerado agora.';

    const actionsRow = document.createElement('div');
    actionsRow.style.cssText = 'display:flex; gap:8px; margin:8px; align-items:center; flex-wrap:wrap;';

    const prevBtn = document.createElement('button');
    prevBtn.type = 'button';
    prevBtn.textContent = '◀ Página';
    prevBtn.style.cssText = 'border:none; background:#263238; color:#fff; border-radius:8px; padding:6px 10px; font-weight:700; cursor:pointer;';

    const pageLabel = document.createElement('span');
    pageLabel.style.cssText = 'font-size:12px; color:#ddd; font-weight:700; min-width:110px; text-align:center;';
    pageLabel.textContent = 'Carregando...';

    const nextBtn = document.createElement('button');
    nextBtn.type = 'button';
    nextBtn.textContent = 'Página ▶';
    nextBtn.style.cssText = 'border:none; background:#263238; color:#fff; border-radius:8px; padding:6px 10px; font-weight:700; cursor:pointer;';

    const downloadBtn = document.createElement('button');
    downloadBtn.type = 'button';
    downloadBtn.textContent = 'Baixar PDF';
    downloadBtn.style.cssText = 'border:none; background:#2e7d32; color:#fff; border-radius:8px; padding:6px 10px; font-weight:700; cursor:pointer; margin-left:auto;';
    downloadBtn.addEventListener('click', async () => {
      const allowed = await openPdfDownloadLoginModal(fileName || 'relatorio.pdf');
      if (!allowed) return;
      try {
        const downloadedBytes = downloadPdfBytes(fileName || 'relatorio.pdf', binarySource);
        if (!downloadedBytes) {
          downloadPdfContent(fileName || 'relatorio.pdf', pdfContent || '');
        }
      } catch (e) {
        showToast('⚠️ Não consegui baixar o PDF agora.');
      }
    });

    actionsRow.appendChild(prevBtn);
    actionsRow.appendChild(pageLabel);
    actionsRow.appendChild(nextBtn);
    actionsRow.appendChild(downloadBtn);

    const viewerWrap = document.createElement('div');
    viewerWrap.style.cssText = 'flex:1; min-height:0; margin:0 8px 8px; background:#0f0f0f; border:1px solid rgba(255,255,255,0.1); border-radius:10px; overflow:auto; padding:10px; display:flex; align-items:flex-start; justify-content:center;';

    const canvas = document.createElement('canvas');
    canvas.style.cssText = 'max-width:100%; background:#fff; border-radius:4px; box-shadow:0 8px 20px rgba(0,0,0,0.45);';

    const frame = document.createElement('iframe');
    frame.style.cssText = 'display:none; width:100%; height:100%; min-height:300px; border:none; background:#fff; border-radius:6px;';
    frame.title = 'Visualização de PDF';

    const fallbackText = document.createElement('pre');
    fallbackText.style.cssText = 'display:none; margin:0; width:100%; color:#f1f1f1; font-family:monospace; font-size:12px; line-height:1.5; white-space:pre-wrap; word-break:break-word;';
    const normalizedLines = Array.isArray(previewLines) ? previewLines : [];
    fallbackText.textContent = normalizedLines.length
      ? normalizedLines.join('\n')
      : 'Pré-visualização indisponível.';

    viewerWrap.appendChild(canvas);
    viewerWrap.appendChild(frame);
    viewerWrap.appendChild(fallbackText);

    let objectUrl = '';
    let pdfDoc = null;
    let pageNum = 1;
    let rendering = false;
    let pendingRender = false;
    let closed = false;
    let renderTimer = null;

    const setPageControls = () => {
      if (pdfDoc && Number(pdfDoc.numPages) > 0) {
        pageLabel.textContent = `Página ${pageNum} de ${pdfDoc.numPages}`;
        prevBtn.disabled = pageNum <= 1;
        nextBtn.disabled = pageNum >= pdfDoc.numPages;
      } else {
        pageLabel.textContent = 'Pré-visualização';
        prevBtn.disabled = true;
        nextBtn.disabled = true;
      }
    };

    const cleanupPreviewResources = () => {
      if (renderTimer) {
        clearTimeout(renderTimer);
        renderTimer = null;
      }
      const handler = window.__urPdfPreviewResizeHandler;
      if (typeof handler === 'function') {
        try { window.removeEventListener('resize', handler); } catch (e) {}
      }
      window.__urPdfPreviewResizeHandler = null;
      if (objectUrl) {
        try { URL.revokeObjectURL(objectUrl); } catch (e) {}
        objectUrl = '';
      }
    };

    const closeModal = () => {
      closed = true;
      cleanupPreviewResources();
      try { overlay.remove(); } catch (e) {}
    };

    const scheduleRender = () => {
      if (closed || !pdfDoc) return;
      if (renderTimer) clearTimeout(renderTimer);
      renderTimer = setTimeout(() => {
        renderCurrentPage().catch(() => {});
      }, 90);
    };

    const renderCurrentPage = async () => {
      if (!pdfDoc || closed) return;
      if (rendering) {
        pendingRender = true;
        return;
      }
      rendering = true;
      pendingRender = false;
      try {
        const page = await pdfDoc.getPage(pageNum);
        const viewportBase = page.getViewport({ scale: 1 });
        const availableWidth = Math.max(220, (viewerWrap.clientWidth || 720) - 24);
        const scale = Math.max(0.6, Math.min(2.6, availableWidth / Math.max(1, viewportBase.width)));
        const viewport = page.getViewport({ scale });
        const dpr = Math.max(1, Math.min(2, Number(window.devicePixelRatio) || 1));
        const ctx = canvas.getContext('2d', { alpha: false });
        if (!ctx) throw new Error('Canvas indisponível');

        canvas.width = Math.max(1, Math.floor(viewport.width * dpr));
        canvas.height = Math.max(1, Math.floor(viewport.height * dpr));
        canvas.style.width = `${Math.floor(viewport.width)}px`;
        canvas.style.height = `${Math.floor(viewport.height)}px`;

        ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
        ctx.imageSmoothingEnabled = true;
        await page.render({ canvasContext: ctx, viewport }).promise;
        setPageControls();
      } catch (e) {
        console.warn('Falha ao renderizar página do PDF:', e);
      } finally {
        rendering = false;
        if (pendingRender && !closed) {
          renderCurrentPage().catch(() => {});
        }
      }
    };

    prevBtn.addEventListener('click', () => {
      if (!pdfDoc || pageNum <= 1) return;
      pageNum -= 1;
      renderCurrentPage().catch(() => {});
    });

    nextBtn.addEventListener('click', () => {
      if (!pdfDoc || pageNum >= pdfDoc.numPages) return;
      pageNum += 1;
      renderCurrentPage().catch(() => {});
    });

    const resizeHandler = () => scheduleRender();
    window.__urPdfPreviewResizeHandler = resizeHandler;
    window.addEventListener('resize', resizeHandler);

    closeBtn.addEventListener('click', closeModal);
    overlay.addEventListener('click', (e) => {
      if (e.target === overlay) closeModal();
    });

    header.appendChild(title);
    header.appendChild(closeBtn);
    body.appendChild(info);
    body.appendChild(actionsRow);
    body.appendChild(viewerWrap);
    card.appendChild(header);
    card.appendChild(body);
    overlay.appendChild(card);
    document.body.appendChild(overlay);

    const startPreview = async () => {
      try {
        const bytes = (
          (typeof ArrayBuffer !== 'undefined' && binarySource instanceof ArrayBuffer)
            ? new Uint8Array(binarySource)
            : (binarySource && typeof binarySource === 'object' && binarySource.buffer instanceof ArrayBuffer)
              ? new Uint8Array(binarySource.buffer, binarySource.byteOffset || 0, binarySource.byteLength || binarySource.length || 0)
              : pdfContentToUint8Array(pdfContent)
        );

        if (typeof pdfjsLib !== 'undefined' && pdfjsLib && typeof pdfjsLib.getDocument === 'function') {
          try {
            if (pdfjsLib?.GlobalWorkerOptions && !pdfjsLib.GlobalWorkerOptions.workerSrc) {
              pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/2.16.105/pdf.worker.min.js';
            }
          } catch (_) {}

          const loadingTask = pdfjsLib.getDocument({ data: bytes, disableWorker: true });
          pdfDoc = await loadingTask.promise;
          frame.style.display = 'none';
          fallbackText.style.display = 'none';
          canvas.style.display = 'block';
          setPageControls();
          await renderCurrentPage();
          return;
        }
      } catch (err) {
        console.warn('Falha no preview via pdf.js, aplicando fallback:', err);
      }

      try {
        objectUrl = URL.createObjectURL(new Blob([(
          (typeof ArrayBuffer !== 'undefined' && binarySource instanceof ArrayBuffer)
            ? binarySource
            : (binarySource && typeof binarySource === 'object' && binarySource.buffer instanceof ArrayBuffer)
              ? binarySource.buffer
              : String(pdfContent || '')
        )], { type: 'application/pdf' }));
        canvas.style.display = 'none';
        fallbackText.style.display = 'none';
        frame.style.display = 'block';
        frame.src = `${objectUrl}#toolbar=1&navpanes=0&statusbar=0&view=FitH`;
        setPageControls();
      } catch (e) {
        frame.style.display = 'none';
        canvas.style.display = 'none';
        fallbackText.style.display = 'block';
        pageLabel.textContent = 'Pré-visualização em texto';
        prevBtn.disabled = true;
        nextBtn.disabled = true;
      }
    };

    startPreview().catch((e) => {
      console.warn('Falha ao iniciar preview interno do PDF:', e);
    });

    return true;
  } catch (e) {
    console.warn('Falha ao abrir pré-visualização interna do PDF:', e);
    return false;
  }
}

function pdfContentToBase64(pdfContent) {
  try {
    return btoa(String(pdfContent || ''));
  } catch (e) {
    // Fallback defensivo para ambientes com caracteres fora do ASCII
    const safe = unescape(encodeURIComponent(String(pdfContent || '')));
    return btoa(safe);
  }
}

async function tryOpenPdfPreviewUrl(url) {
  if (!url) return false;

  try {
    const cap = window.Capacitor;
    let browser = cap?.Plugins?.Browser || null;
    if (!browser && cap && typeof cap.registerPlugin === 'function') {
      browser = cap.registerPlugin('Browser');
    }
    if (browser && typeof browser.open === 'function') {
      await browser.open({ url });
      return true;
    }
  } catch (e) {
    console.warn('Falha ao abrir preview de PDF via Browser plugin:', e);
  }

  try {
    const popup = window.open(url, '_blank');
    return !!popup;
  } catch (e) {
    return false;
  }
}

async function tryNativePdfExport(fileName, pdfContent) {
  try {
    const cap = window.Capacitor;
    if (!cap || typeof cap.getPlatform !== 'function' || cap.getPlatform() === 'web') return null;

    let fs = null;
    if (typeof getFilesystemPlugin === 'function') fs = getFilesystemPlugin();
    if (!fs && cap.Plugins?.Filesystem) fs = cap.Plugins.Filesystem;
    if (!fs && typeof cap.registerPlugin === 'function') fs = cap.registerPlugin('Filesystem');
    if (!fs || typeof fs.writeFile !== 'function') return null;

    const dirCandidates = [
      cap.FilesystemDirectory?.ExternalStorage,
      cap.FilesystemDirectory?.External,
      cap.FilesystemDirectory?.Documents,
      'DOCUMENTS'
    ].filter(Boolean);

    const base64Data = pdfContentToBase64(pdfContent);
    let lastError = null;

    for (const dir of dirCandidates) {
      const isExternalDir = (
        dir === cap.FilesystemDirectory?.ExternalStorage ||
        dir === cap.FilesystemDirectory?.External
      );
      const folder = isExternalDir ? 'Download/UniversoReal/Relatorios' : 'UniversoReal/Relatorios';

      try {
        if (typeof fs.mkdir === 'function') {
          try {
            await fs.mkdir({ path: folder, directory: dir, recursive: true });
          } catch (e) {}
        }

        const path = `${folder}/${fileName}`;
        await fs.writeFile({
          path,
          data: base64Data,
          directory: dir,
          recursive: true
        });

        let uri = null;
        if (typeof fs.getUri === 'function') {
          try {
            const out = await fs.getUri({ path, directory: dir });
            uri = out?.uri || null;
          } catch (e) {}
        }

        return { path, uri };
      } catch (e) {
        lastError = e;
      }
    }

    if (lastError) throw lastError;
    return null;
  } catch (e) {
    console.warn('Falha ao exportar PDF no Android:', e);
    return null;
  }
}

function formatCurrencyForPdf(value) {
  const amount = Number(value) || 0;
  return amount.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

async function exportTextLinesAsPdf({ title, lines, filePrefix, openAfterSave = false } = {}) {
  const safeTitle = sanitizePdfText(title || 'Relatorio');
  const safeLines = (Array.isArray(lines) ? lines : [])
    .map((line) => sanitizePdfText(line))
    .filter(Boolean);
  const cap = window.Capacitor;
  const isNativePlatform = !!(cap && typeof cap.getPlatform === 'function' && cap.getPlatform() !== 'web');

  const now = new Date();
  const stampIso = now.toISOString().replace(/[:.]/g, '-');
  const fileName = `${filePrefix || 'relatorio'}-${stampIso}.pdf`;
  const meta = `Gerado em: ${now.toLocaleString('pt-BR')}`;
  const pdfContent = buildSimplePdfDocument(safeTitle, [meta, '', ...safeLines]);
  const nativeResult = await tryNativePdfExport(fileName, pdfContent);
  const previewLines = [safeTitle, meta, '', ...safeLines];

  if (openAfterSave) {
    const openedInApp = openPdfPreviewInApp(fileName, pdfContent, nativeResult?.path || '', previewLines);
    if (openedInApp) {
      if (nativeResult && nativeResult.path) {
        showToast(`📄 PDF salvo e aberto: ${nativeResult.path}`);
      } else {
        showToast('📄 PDF aberto para visualização.');
      }
      return { fileName, path: nativeResult?.path || null, opened: true };
    }
  }

  if (nativeResult && nativeResult.path) {
    showToast(`📄 PDF salvo em: ${nativeResult.path}`);
    return { fileName, path: nativeResult.path, opened: false };
  }

  let opened = false;
  if (openAfterSave && !isNativePlatform) {
    const previewDataUrl = `data:application/pdf;base64,${pdfContentToBase64(pdfContent)}`;
    opened = await tryOpenPdfPreviewUrl(previewDataUrl);
  }
  downloadPdfContent(fileName, pdfContent);
  showToast(opened ? '📄 PDF aberto e exportado.' : '📄 PDF exportado com sucesso.');
  return { fileName, path: null, opened };
}

function triggerHaptic(pattern = 15) {
  if (navigator.vibrate) {
    try {
      navigator.vibrate(pattern);
    } catch (e) {
      // Silencioso em caso de erro ou falta de suporte
    }
  }
}

function deferTask(fn, timeout = 800) {
  if (typeof requestIdleCallback === 'function') {
    requestIdleCallback(() => {
      try { fn(); } catch (e) { console.warn('deferTask falhou:', e); }
    }, { timeout });
  } else {
    setTimeout(() => {
      try { fn(); } catch (e) { console.warn('deferTask falhou:', e); }
    }, timeout);
  }
}

// ===================================
// Sistema de Estrelas do Universo
// ===================================
let currentStarColor = '#ffffff';
const VISUAL_PREFS_KEY = 'ur_visual_prefs_v1';
const DEFAULT_VISUAL_PREFS = Object.freeze({
  starsEnabled: true
});
let visualPrefs = { ...DEFAULT_VISUAL_PREFS };

function normalizeVisualPrefs(raw = {}) {
  return {
    starsEnabled: raw?.starsEnabled !== false
  };
}

function loadVisualPrefs() {
  try {
    const raw = localStorage.getItem(VISUAL_PREFS_KEY);
    if (!raw) {
      visualPrefs = { ...DEFAULT_VISUAL_PREFS };
      return visualPrefs;
    }
    visualPrefs = normalizeVisualPrefs(JSON.parse(raw));
  } catch (e) {
    visualPrefs = { ...DEFAULT_VISUAL_PREFS };
  }
  return visualPrefs;
}

function saveVisualPrefs() {
  try {
    localStorage.setItem(VISUAL_PREFS_KEY, JSON.stringify(visualPrefs));
  } catch (e) {}
}

function isStarsEnabled() {
  return visualPrefs?.starsEnabled !== false;
}

function isLowEndDeviceForStars() {
  try {
    const memory = Number(navigator.deviceMemory || 0);
    const cores = Number(navigator.hardwareConcurrency || 0);
    const lowMemory = Number.isFinite(memory) && memory > 0 && memory <= 4;
    const lowCpu = Number.isFinite(cores) && cores > 0 && cores <= 4;
    return lowMemory || lowCpu;
  } catch (e) {
    return false;
  }
}

function prefersReducedMotion() {
  try {
    return !!(window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches);
  } catch (e) {
    return false;
  }
}

function shouldUseLiteStars() {
  return isLowEndDeviceForStars() || prefersReducedMotion();
}

function updateStarsSettingsUI() {
  const enabled = isStarsEnabled();
  const lite = enabled && shouldUseLiteStars();
  const label = enabled ? (lite ? '✨ Fundo Leve: Ligado' : '✨ Fundo: Ligado') : '✨ Fundo: Desligado';
  if (elements?.starsToggleBtn) elements.starsToggleBtn.textContent = label;
  if (elements?.drawerStarsToggleBtn) elements.drawerStarsToggleBtn.textContent = label;
}

function applyStarPerformanceMode({ recreate = true } = {}) {
  const starsContainer = document.querySelector('.stars');
  if (!starsContainer) return;

  const enabled = isStarsEnabled();
  const lite = enabled && shouldUseLiteStars();

  document.body.classList.toggle('stars-disabled', !enabled);
  document.body.classList.toggle('stars-lite', lite);
  updateStarsSettingsUI();

  if (!enabled) {
    starsContainer.querySelectorAll('.star').forEach((s) => s.remove());
    return;
  }

  if (recreate) createStars(currentStarColor);
}

function setStarsEnabled(nextValue) {
  visualPrefs.starsEnabled = !!nextValue;
  saveVisualPrefs();
  applyStarPerformanceMode({ recreate: true });
  showToast(visualPrefs.starsEnabled ? '✨ Fundo estrelado ativado.' : '🌑 Fundo estrelado desativado.');
}

function createStars(color = '#ffffff') {
  const starsContainer = document.querySelector('.stars');
  if (!starsContainer) return;

  if (!isStarsEnabled()) {
    starsContainer.querySelectorAll('.star').forEach((s) => s.remove());
    return;
  }
  
  // Limpa estrelas existentes (exceto o ::before e ::after do CSS)
  starsContainer.querySelectorAll('.star').forEach(s => s.remove());
  
  // Define a cor das estrelas
  currentStarColor = color;
  starsContainer.style.setProperty('--star-color', color);
  
  // Cria estrelas com modo leve automático em aparelhos mais fracos
  const isMobile = window.innerWidth <= 900;
  const liteMode = shouldUseLiteStars();
  const density = liteMode
    ? (isMobile ? 26000 : 12000)
    : (isMobile ? 8000 : 3000);
  const baseCount = Math.floor(window.innerWidth * window.innerHeight / density);
  const starCount = liteMode
    ? (isMobile ? Math.min(80, Math.max(24, baseCount)) : Math.min(180, Math.max(50, baseCount)))
    : (isMobile ? Math.min(220, Math.max(80, baseCount)) : Math.min(600, Math.max(160, baseCount)));
  
  for (let i = 0; i < starCount; i++) {
    const star = document.createElement('div');
    star.className = 'star';
    
    // Distribuição de tamanhos: mais estrelas pequenas, poucas grandes
    const sizeRand = Math.random();
    if (sizeRand < 0.3) star.classList.add('tiny');
    else if (sizeRand < 0.72) star.classList.add('small');
    else if (sizeRand < (liteMode ? 1 : 0.9)) star.classList.add('medium');
    else if (sizeRand < 0.98) star.classList.add('large');
    else star.classList.add('bright');
    
    // Posição aleatória
    star.style.left = `${Math.random() * 100}%`;
    star.style.top = `${Math.random() * 100}%`;
    
    // Duração e delay de piscagem aleatórios para efeito natural
    const duration = liteMode
      ? 2.6 + Math.random() * 4.8
      : 0.8 + Math.random() * 5.5;
    const delay = Math.random() * 10; // delay 0-10s
    star.style.setProperty('--twinkle-duration', `${duration}s`);
    star.style.setProperty('--twinkle-delay', `${delay}s`);
    
    starsContainer.appendChild(star);
  }
}

function updateStarColor(color) {
  const starsContainer = document.querySelector('.stars');
  if (!starsContainer) return;

  const next = String(color || '#ffffff');
  if (next === currentStarColor) return;
  currentStarColor = next;
  starsContainer.style.setProperty('--star-color', next);
}

// Inicializa estrelas quando a página carrega
window.addEventListener('load', () => {
  loadVisualPrefs();
  applyStarPerformanceMode({ recreate: false });
  deferTask(() => applyStarPerformanceMode({ recreate: true }), 500);
  
  // Recria estrelas se a janela for redimensionada (debounced)
  let resizeTimeout;
  window.addEventListener('resize', () => {
    clearTimeout(resizeTimeout);
    resizeTimeout = setTimeout(() => applyStarPerformanceMode({ recreate: true }), 500);
  });
});

