function getShopItemAbilityText(item = {}) {
  const safeItem = item && typeof item === 'object' ? item : {};
  const explicit = String(safeItem.ability || '').trim();
  if (explicit) return explicit;
  const key = String(safeItem.key || '').trim();
  return String(SHOP_FUNCTIONAL_ABILITY_BY_KEY[key] || '').trim();
}

function isShopItemVisible(item = {}) {
  const safeItem = item && typeof item === 'object' ? item : {};
  return getShopItemAbilityText(safeItem).length > 0;
}

const SHOP_VISIBLE_ITEMS = Object.freeze(SHOP_ITEMS.filter((item) => isShopItemVisible(item)));

const SHOP_SPECIAL_EVENTS = Object.freeze({
  crown: { label: 'Festival da Coroa', description: 'Cashback de +25 moedas na compra.', coinsBonus: 25 },
  heroFrame: { label: 'Semana do Herói', description: 'Cashback de +18 moedas na compra.', coinsBonus: 18 },
  chatThemeAurora: { label: 'Noite Aurora', description: 'Cashback de +10 moedas na compra.', coinsBonus: 10 },
  stickerPackFe: { label: 'Evento da Fé', description: 'Cashback de +12 moedas na compra.', coinsBonus: 12 },
  entradaSagrada: { label: 'Portal Sagrado', description: 'Cashback de +20 moedas na compra.', coinsBonus: 20 },
  musicaSalaEpic: { label: 'Concerto Épico', description: 'Cashback de +16 moedas na compra.', coinsBonus: 16 },
  emblemaFamilia: { label: 'Laços de Família', description: 'Cashback de +8 moedas na compra.', coinsBonus: 8 },
  cofrePrime: { label: 'Cofre Premiado', description: 'Cashback de +30 moedas na compra.', coinsBonus: 30 },
  tituloSoberano: { label: 'Trono Supremo', description: 'Cashback de +35 moedas na compra.', coinsBonus: 35 },
  pacoteCinemaAnime: { label: 'Maratona Anime', description: 'Cashback de +14 moedas na compra.', coinsBonus: 14 }
});

function getShopSpecialEvent(itemKey = '') {
  const key = String(itemKey || '').trim();
  if (!key) return null;
  const raw = SHOP_SPECIAL_EVENTS[key];
  if (!raw || typeof raw !== 'object') return null;
  const label = String(raw.label || 'Evento especial').trim() || 'Evento especial';
  const description = String(raw.description || 'Bônus por tempo limitado.').trim() || 'Bônus por tempo limitado.';
  const coinsBonus = Math.max(0, Math.floor(Number(raw.coinsBonus || 0) || 0));
  return { label, description, coinsBonus };
}

function applyShopSpecialEventPurchaseBonus(itemKey = '') {
  if (!gameState) return null;
  const eventCfg = getShopSpecialEvent(itemKey);
  if (!eventCfg || !eventCfg.coinsBonus) {
    return eventCfg ? { event: eventCfg, coinsBonus: 0 } : null;
  }
  const bonus = Math.max(0, Number(eventCfg.coinsBonus || 0) || 0);
  if (!bonus) return { event: eventCfg, coinsBonus: 0 };
  gameState.coins = Math.max(0, Number(gameState.coins || 0) + bonus);
  const wallet = ensureWalletState(gameState);
  wallet.totalEarned = Math.max(0, Number(wallet.totalEarned || 0) + bonus);
  return { event: eventCfg, coinsBonus: bonus };
}

