// Instância do Gráfico
let xpChartInstance = null;
let financeChartInstance = null;
let financeMonthlyChartInstance = null;
let workChartInstance = null;
let attributesChartInstance = null;
let xpChartRetryTimer = null;
let attributesChartRetryTimer = null;

function isChartJsReady() {
  return typeof Chart === 'function';
}

function paintCanvasFallbackMessage(canvas, message = 'Gráfico carregando...') {
  if (!canvas || typeof canvas.getContext !== 'function') return;
  const ctx = canvas.getContext('2d');
  if (!ctx) return;

  const cssWidth = Math.max(220, Number(canvas.clientWidth || canvas.width || 320));
  const cssHeight = Math.max(130, Number(canvas.clientHeight || canvas.height || 180));
  const ratio = Math.max(1, Number(window.devicePixelRatio || 1));
  const renderWidth = Math.floor(cssWidth * ratio);
  const renderHeight = Math.floor(cssHeight * ratio);

  if (canvas.width !== renderWidth || canvas.height !== renderHeight) {
    canvas.width = renderWidth;
    canvas.height = renderHeight;
  }
  canvas.style.width = `${cssWidth}px`;
  canvas.style.height = `${cssHeight}px`;

  ctx.save();
  ctx.scale(ratio, ratio);
  ctx.clearRect(0, 0, cssWidth, cssHeight);

  const bg = ctx.createLinearGradient(0, 0, 0, cssHeight);
  bg.addColorStop(0, 'rgba(255,255,255,0.03)');
  bg.addColorStop(1, 'rgba(255,255,255,0.01)');
  ctx.fillStyle = bg;
  ctx.fillRect(0, 0, cssWidth, cssHeight);

  ctx.fillStyle = 'rgba(230,238,248,0.72)';
  ctx.font = '600 12px Inter, system-ui, sans-serif';
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.fillText(String(message || 'Carregando...'), cssWidth / 2, cssHeight / 2);
  ctx.restore();
}

function scheduleXpChartRetry(delayMs = 1200) {
  if (xpChartRetryTimer) return;
  xpChartRetryTimer = setTimeout(() => {
    xpChartRetryTimer = null;
    renderXpChart();
  }, Math.max(300, Number(delayMs) || 1200));
}

function scheduleAttributesChartRetry(delayMs = 1200) {
  if (attributesChartRetryTimer) return;
  attributesChartRetryTimer = setTimeout(() => {
    attributesChartRetryTimer = null;
    renderAttributesChart();
  }, Math.max(300, Number(delayMs) || 1200));
}

