function applyPlayerRoomTheme(nextTheme, { persist = true } = {}) {
  const safeTheme = normalizePlayerRoomTheme(nextTheme);
  playerRoomTheme = safeTheme;

  const tabRoom = document.getElementById('tab-room');
  if (tabRoom) {
    PLAYER_ROOM_THEMES.forEach((theme) => tabRoom.classList.remove(`room-theme-${theme}`));
    tabRoom.classList.add(`room-theme-${safeTheme}`);
  }

  if (elements.playerRoomThemeSelector) {
    elements.playerRoomThemeSelector.querySelectorAll('[data-room-theme]').forEach((btn) => {
      const isActive = normalizePlayerRoomTheme(btn.getAttribute('data-room-theme')) === safeTheme;
      btn.classList.toggle('active', isActive);
    });
  }

  if (persist) savePlayerRoomTheme();
}

