function loadPlayerRoomHistory() {
  try {
    const raw = localStorage.getItem(PLAYER_ROOM_STORAGE_KEY);
    if (!raw) {
      playerRoomHistory = [];
      return;
    }
    const parsed = JSON.parse(raw);
    if (!Array.isArray(parsed)) {
      playerRoomHistory = [];
      return;
    }
    playerRoomHistory = parsed
      .map((item) => normalizePlayerRoomMessage(item))
      .filter((item) => isValidPlayerRoomMessage(item))
      .filter((item) => !isPlayerRoomAdminNewsExpiredMessage(item))
      .slice(-PLAYER_ROOM_MAX_MESSAGES);
  } catch (e) {
    console.warn('Falha ao carregar histórico local da sala:', e);
    playerRoomHistory = [];
  }
}

function savePlayerRoomHistory() {
  try {
    const safeHistory = playerRoomHistory
      .slice(-PLAYER_ROOM_MAX_MESSAGES)
      .filter((item) => !isPlayerRoomAdminNewsExpiredMessage(item))
      .map((item) => {
        const copy = { ...item };
        if (copy.mediaData) copy.mediaData = '';
        return copy;
      });
    localStorage.setItem(PLAYER_ROOM_STORAGE_KEY, JSON.stringify(safeHistory));
  } catch (e) {
    console.warn('Falha ao salvar histórico local da sala:', e);
  }
}

