const WORK_LOCATION_DEFAULT_RADIUS_METERS = 220;
const WORK_LOCATION_CHECK_INTERVAL_MS = 20 * 1000;
const WORK_LOCATION_PROMPT_COOLDOWN_MS = 30 * 60 * 1000;
const WORK_LOCATION_PERMISSION_PROMPT_COOLDOWN_MS = 10 * 60 * 1000;
const WORK_TIMER_AUTO_STOP_DISTANCE_METERS = 1;
const WORK_WEEKLY_BASE_XP_REWARD = 25;
const WORK_WEEKLY_BASE_XP_PENALTY = 12;
const WORK_WEEK_PLAN_MAX_ITEMS = 420;
const WORK_WEEK_DAYS = Object.freeze([
  { index: 1, key: 'segunda', label: 'Segunda-feira' },
  { index: 2, key: 'terca', label: 'Terça-feira' },
  { index: 3, key: 'quarta', label: 'Quarta-feira' },
  { index: 4, key: 'quinta', label: 'Quinta-feira' },
  { index: 5, key: 'sexta', label: 'Sexta-feira' },
  { index: 6, key: 'sabado', label: 'Sábado' },
  { index: 7, key: 'domingo', label: 'Domingo' }
]);
let _workLocationMonitorInterval = null;
let _workLocationMonitorBusy = false;
let _workLocationMonitorLastDistanceMeters = null;
let _workLocationMonitorLastCheckAt = 0;
let _workLocationLastActionAt = 0;
let _workLocationPermissionPromptAt = 0;
let _nativeWorkLocationMonitorPlugin = null;
let _nativeWorkLocationSyncPromise = null;

function toIsoLocalDate(dateObj) {
  if (!(dateObj instanceof Date) || !Number.isFinite(dateObj.getTime())) return '';
  const year = dateObj.getFullYear();
  const month = String(dateObj.getMonth() + 1).padStart(2, '0');
  const day = String(dateObj.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
}

function parseIsoLocalDate(value = '') {
  const match = String(value || '').trim().match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (!match) return null;
  const year = Number(match[1]);
  const month = Number(match[2]);
  const day = Number(match[3]);
  if (!Number.isFinite(year) || !Number.isFinite(month) || !Number.isFinite(day)) return null;
  const parsed = new Date(year, month - 1, day, 0, 0, 0, 0);
  if (!Number.isFinite(parsed.getTime())) return null;
  if (parsed.getFullYear() !== year || (parsed.getMonth() + 1) !== month || parsed.getDate() !== day) return null;
  return parsed;
}

function getCurrentTimeHHMM() {
  const now = new Date();
  return `${String(now.getHours()).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`;
}

function getWorkWeekStartIso(baseDate = new Date()) {
  const source = baseDate instanceof Date
    ? new Date(baseDate.getTime())
    : (parseIsoLocalDate(baseDate) || new Date());
  source.setHours(0, 0, 0, 0);
  const day = source.getDay(); // 0 domingo ... 6 sábado
  const diffToMonday = day === 0 ? -6 : 1 - day;
  source.setDate(source.getDate() + diffToMonday);
  return toIsoLocalDate(source) || getTodayIsoLocalDate();
}

function getWorkWeekRangeLabel(weekStartIso = '') {
  const start = parseIsoLocalDate(weekStartIso) || parseIsoLocalDate(getWorkWeekStartIso(new Date()));
  if (!start) return 'Semana atual';
  const end = new Date(start.getTime());
  end.setDate(end.getDate() + 6);
  const startLabel = start.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' });
  const endLabel = end.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' });
  return `${startLabel} até ${endLabel}`;
}

function sanitizeWorkWeekTime(value = '') {
  const raw = String(value || '').trim();
  if (!raw) return '';
  const match = raw.match(/^(\d{2}):(\d{2})/);
  if (!match) return '';
  const hh = Number(match[1]);
  const mm = Number(match[2]);
  if (!Number.isFinite(hh) || !Number.isFinite(mm)) return '';
  if (hh < 0 || hh > 23 || mm < 0 || mm > 59) return '';
  return `${String(hh).padStart(2, '0')}:${String(mm).padStart(2, '0')}`;
}

function getMinutesFromTimeLabel(timeLabel = '') {
  const safe = sanitizeWorkWeekTime(timeLabel);
  if (!safe) return NaN;
  const [hh, mm] = safe.split(':').map(Number);
  return (hh * 60) + mm;
}

function computeWorkDurationHours(startTime = '', endTime = '') {
  const startMinutes = getMinutesFromTimeLabel(startTime);
  const endMinutes = getMinutesFromTimeLabel(endTime);
  if (!Number.isFinite(startMinutes) || !Number.isFinite(endMinutes)) return 0;
  let diff = endMinutes - startMinutes;
  if (diff < 0) diff += 24 * 60;
  if (diff < 0 || diff > 24 * 60) return 0;
  const hours = diff / 60;
  return Math.max(0, Math.round(hours * 100) / 100);
}

function formatWorkDurationLabel(hours = 0) {
  const safe = Math.max(0, Number(hours) || 0);
  if (!safe) return '0h';
  const totalMinutes = Math.round(safe * 60);
  const fullHours = Math.floor(totalMinutes / 60);
  const mins = totalMinutes % 60;
  if (fullHours <= 0) return `${mins}min`;
  if (mins <= 0) return `${fullHours}h`;
  return `${fullHours}h ${String(mins).padStart(2, '0')}min`;
}

function clampWorkWeeklyProgress(value = 0) {
  const parsed = Number(value);
  if (!Number.isFinite(parsed)) return 0;
  return Math.min(100, Math.max(0, Math.round(parsed)));
}

function getWorkWeeklyProgressValue(task = {}) {
  if (!task || typeof task !== 'object') return 0;
  if (Number.isFinite(Number(task.progress))) {
    return clampWorkWeeklyProgress(task.progress);
  }
  return String(task.status || '').trim().toLowerCase() === 'completed' ? 100 : 0;
}

function normalizeWorkWeekPlanEntries(list = [], maxItems = WORK_WEEK_PLAN_MAX_ITEMS) {
  const source = Array.isArray(list) ? list : [];
  const fallbackWeekStart = getWorkWeekStartIso(new Date());
  const stamp = Date.now();
  const normalized = source
    .filter((entry) => entry && typeof entry === 'object')
    .map((entry, index) => {
      const rawId = String(entry.id || '').trim();
      const id = rawId || `ww_${stamp}_${index}_${Math.random().toString(36).slice(2, 7)}`;

      const weekRaw = String(entry.weekStart || '').trim();
      const weekParsed = parseIsoLocalDate(weekRaw);
      const weekStart = weekParsed ? getWorkWeekStartIso(weekParsed) : fallbackWeekStart;

      const dayRaw = Number(entry.dayIndex);
      const dayIndex = Number.isFinite(dayRaw)
        ? Math.min(7, Math.max(1, Math.round(dayRaw)))
        : 1;

      const plannedText = String(entry.plannedText || entry.text || '').trim().slice(0, 200);
      const doneText = String(entry.doneText || entry.note || '').trim().slice(0, 220);

      const startTime = sanitizeWorkWeekTime(entry.startTime || '');
      const endTime = sanitizeWorkWeekTime(entry.endTime || '');
      const autoDuration = computeWorkDurationHours(startTime, endTime);
      const manualDuration = Math.max(0, Number(entry.durationHours) || 0);
      const durationHours = Math.round(((autoDuration > 0 || (startTime && endTime)) ? autoDuration : manualDuration) * 100) / 100;

      const createdAtRaw = String(entry.createdAt || '').trim();
      const createdAt = Number.isFinite(Date.parse(createdAtRaw)) ? createdAtRaw : new Date().toISOString();
      const updatedAtRaw = String(entry.updatedAt || '').trim();
      const updatedAt = Number.isFinite(Date.parse(updatedAtRaw)) ? updatedAtRaw : createdAt;

      const statusRaw = String(entry.status || '').trim().toLowerCase();
      let status = ['pending', 'completed', 'missed'].includes(statusRaw) ? statusRaw : 'pending';
      let progress = Number.isFinite(Number(entry.progress))
        ? clampWorkWeeklyProgress(entry.progress)
        : (status === 'completed' ? 100 : 0);

      if (progress >= 100) {
        progress = 100;
        status = 'completed';
      } else if (status === 'completed') {
        status = 'pending';
      }

      let completedAt = '';
      const completedAtRaw = String(entry.completedAt || '').trim();
      if (Number.isFinite(Date.parse(completedAtRaw))) completedAt = completedAtRaw;

      let penalizedAt = '';
      const penalizedAtRaw = String(entry.penalizedAt || '').trim();
      if (Number.isFinite(Date.parse(penalizedAtRaw))) penalizedAt = penalizedAtRaw;

      let xpAwardedAt = '';
      const xpAwardedAtRaw = String(entry.xpAwardedAt || '').trim();
      if (Number.isFinite(Date.parse(xpAwardedAtRaw))) xpAwardedAt = xpAwardedAtRaw;

      if (status === 'completed' && !completedAt) completedAt = updatedAt || createdAt;
      if (status === 'completed') progress = 100;

      const xpReward = Math.max(1, Math.round(Number(entry.xpReward) || WORK_WEEKLY_BASE_XP_REWARD));
      const xpPenalty = Math.max(1, Math.round(Number(entry.xpPenalty) || WORK_WEEKLY_BASE_XP_PENALTY));

      return {
        id,
        weekStart,
        dayIndex,
        plannedText,
        doneText,
        startTime,
        endTime,
        durationHours,
        progress,
        status,
        xpReward,
        xpPenalty,
        createdAt,
        updatedAt,
        completedAt,
        penalizedAt,
        xpAwardedAt
      };
    });

  const deduped = [];
  const seen = new Set();
  normalized.forEach((entry, idx) => {
    let safeId = String(entry.id || '').trim() || `ww_${stamp}_${idx}`;
    if (seen.has(safeId)) {
      safeId = `${safeId}_${idx}`;
    }
    seen.add(safeId);
    deduped.push({ ...entry, id: safeId });
  });

  if (deduped.length <= maxItems) return deduped;
  return deduped.slice(-maxItems);
}

function ensureWorkWeekPlanDefaults(state = gameState) {
  if (!state || typeof state !== 'object') return [];
  state.workWeekPlan = normalizeWorkWeekPlanEntries(state.workWeekPlan, WORK_WEEK_PLAN_MAX_ITEMS);
  return state.workWeekPlan;
}

function getWorkWeekDayMeta(dayIndex = 1) {
  const safeIndex = Math.min(7, Math.max(1, Math.round(Number(dayIndex) || 1)));
  return WORK_WEEK_DAYS.find((day) => day.index === safeIndex) || WORK_WEEK_DAYS[0];
}

function getWorkWeekDayLabel(dayIndex = 1) {
  return getWorkWeekDayMeta(dayIndex).label;
}

function getWorkWeeklyTaskDueDate(task = {}) {
  const weekStartRaw = String(task.weekStart || '').trim();
  const weekStartDate = parseIsoLocalDate(weekStartRaw) || parseIsoLocalDate(getWorkWeekStartIso(new Date()));
  if (!weekStartDate) return '';
  const dayIndex = Math.min(7, Math.max(1, Math.round(Number(task.dayIndex) || 1)));
  const dueDate = new Date(weekStartDate.getTime());
  dueDate.setDate(dueDate.getDate() + (dayIndex - 1));
  return toIsoLocalDate(dueDate);
}

function getWorkWeeklyTaskById(taskId = '') {
  const safeId = String(taskId || '').trim();
  if (!safeId) return null;
  const plan = ensureWorkWeekPlanDefaults();
  return plan.find((task) => String(task?.id || '') === safeId) || null;
}

function applyWorkWeeklyOverduePenalties({ showToastOnChange = true, persist = true } = {}) {
  if (!gameState) return { changed: false, penalizedCount: 0, totalPenalty: 0 };

  const plan = ensureWorkWeekPlanDefaults();
  if (!plan.length) return { changed: false, penalizedCount: 0, totalPenalty: 0 };

  const todayIso = getTodayIsoLocalDate();
  const nowIso = new Date().toISOString();
  let penalizedCount = 0;
  let totalPenalty = 0;

  plan.forEach((task) => {
    if (!task || task.status === 'completed') return;
    if (task.penalizedAt) return;
    const dueDate = getWorkWeeklyTaskDueDate(task);
    if (!dueDate || dueDate >= todayIso) return;
    const penalty = Math.max(1, Math.round(Number(task.xpPenalty) || WORK_WEEKLY_BASE_XP_PENALTY));
    totalPenalty += penalty;
    penalizedCount += 1;
    task.status = 'missed';
    task.penalizedAt = nowIso;
    task.updatedAt = nowIso;
  });

  if (!penalizedCount) {
    return { changed: false, penalizedCount: 0, totalPenalty: 0 };
  }

  awardXp(-totalPenalty, { silent: true, showLevelUpToast: false });
  if (persist) saveGame(true);
  if (showToastOnChange) {
    showToast(`⚠️ ${penalizedCount} tarefa(s) da semana não concluídas. -${totalPenalty} XP`);
  }

  return { changed: true, penalizedCount, totalPenalty };
}

function ensureWorkJobDefaults() {
  if (!gameState) return null;
  if (!gameState.job || typeof gameState.job !== 'object') {
    gameState.job = {};
  }
  const job = gameState.job;
  if (typeof job.name !== 'string' && job.name !== null) job.name = null;
  if (typeof job.type !== 'string' && job.type !== null) job.type = null;
  if (typeof job.address !== 'string') job.address = '';
  if (!job.config || typeof job.config !== 'object') {
    job.config = { rate: 0 };
  }

  if (!job.geoMonitor || typeof job.geoMonitor !== 'object') {
    job.geoMonitor = { enabled: true, radiusMeters: WORK_LOCATION_DEFAULT_RADIUS_METERS, lastPromptAt: null };
  }
  job.geoMonitor.enabled = job.geoMonitor.enabled !== false;
  const radius = Number(job.geoMonitor.radiusMeters);
  job.geoMonitor.radiusMeters = Number.isFinite(radius) && radius >= 80 && radius <= 5000
    ? Math.round(radius)
    : WORK_LOCATION_DEFAULT_RADIUS_METERS;
  if (job.geoMonitor.lastPromptAt && !Number.isFinite(Date.parse(job.geoMonitor.lastPromptAt))) {
    job.geoMonitor.lastPromptAt = null;
  }

  if (job.location && typeof job.location === 'object') {
    const lat = Number(job.location.lat);
    const lng = Number(job.location.lng);
    const valid =
      Number.isFinite(lat) &&
      Number.isFinite(lng) &&
      Math.abs(lat) <= 90 &&
      Math.abs(lng) <= 180;
    if (valid) {
      job.location = {
        lat,
        lng,
        source: String(job.location.source || 'manual'),
        updatedAt: Number.isFinite(Date.parse(job.location.updatedAt)) ? job.location.updatedAt : new Date().toISOString(),
        addressSnapshot: String(job.location.addressSnapshot || '').trim()
      };
    } else {
      job.location = null;
    }
  } else {
    job.location = null;
  }

  return job;
}

function getWorkAddress() {
  return String(gameState?.job?.address || '').trim();
}

function getWorkLocationPoint() {
  const job = ensureWorkJobDefaults();
  if (!job || !job.location) return null;
  return job.location;
}

function hasWorkLocationPoint() {
  return !!getWorkLocationPoint();
}

function getWorkLocationRadiusMeters() {
  const job = ensureWorkJobDefaults();
  if (!job || !job.geoMonitor) return WORK_LOCATION_DEFAULT_RADIUS_METERS;
  return Math.max(80, Math.min(5000, Number(job.geoMonitor.radiusMeters || WORK_LOCATION_DEFAULT_RADIUS_METERS) || WORK_LOCATION_DEFAULT_RADIUS_METERS));
}

function formatDistanceMeters(distanceMeters) {
  const safe = Math.max(0, Number(distanceMeters) || 0);
  if (safe < 1000) return `${Math.round(safe)} m`;
  return `${(safe / 1000).toFixed(2).replace('.', ',')} km`;
}

function haversineDistanceMeters(lat1, lng1, lat2, lng2) {
  const toRad = (deg) => (deg * Math.PI) / 180;
  const R = 6371000;
  const dLat = toRad(lat2 - lat1);
  const dLng = toRad(lng2 - lng1);
  const a =
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) *
    Math.sin(dLng / 2) * Math.sin(dLng / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
}

function parseLatLngFromAddressText(raw = '') {
  const text = String(raw || '').trim();
  if (!text) return null;
  const match = text.match(/(-?\d{1,2}(?:[.,]\d+))\s*[;,]\s*(-?\d{1,3}(?:[.,]\d+))/);
  if (!match) return null;
  const lat = Number(String(match[1]).replace(',', '.'));
  const lng = Number(String(match[2]).replace(',', '.'));
  if (!Number.isFinite(lat) || !Number.isFinite(lng)) return null;
  if (Math.abs(lat) > 90 || Math.abs(lng) > 180) return null;
  return { lat, lng };
}

function setWorkLocationPoint(point = null, { source = 'manual', addressSnapshot = '', persist = true } = {}) {
  const job = ensureWorkJobDefaults();
  if (!job) return;
  if (!point || !Number.isFinite(point.lat) || !Number.isFinite(point.lng)) {
    job.location = null;
  } else {
    job.location = {
      lat: Number(point.lat),
      lng: Number(point.lng),
      source: String(source || 'manual'),
      updatedAt: new Date().toISOString(),
      addressSnapshot: String(addressSnapshot || getWorkAddress()).trim()
    };
  }
  if (persist) saveGame(true);
}

async function getCurrentDevicePosition(options = {}) {
  const enableHighAccuracy = options.enableHighAccuracy !== false;
  const timeout = Number(options.timeout || 15000);
  const maximumAge = Number(options.maximumAge || 30000);
  const requestPermission = options.requestPermission === true;
  let lastError = null;

  // 1) Tenta plugin nativo do Capacitor primeiro (mais estável no APK)
  const capGeo = window.Capacitor?.Plugins?.Geolocation;
  if (capGeo && typeof capGeo.getCurrentPosition === 'function') {
    try {
      let isGranted = true;
      if (typeof capGeo.checkPermissions === 'function') {
        const status = await capGeo.checkPermissions();
        const locationStatus = String(status?.location || '').toLowerCase();
        const coarseStatus = String(status?.coarseLocation || '').toLowerCase();
        isGranted = locationStatus === 'granted' || coarseStatus === 'granted';
        if (!isGranted && typeof capGeo.requestPermissions === 'function') {
          if (requestPermission) {
            const requested = await capGeo.requestPermissions();
            const reqLocation = String(requested?.location || '').toLowerCase();
            const reqCoarse = String(requested?.coarseLocation || '').toLowerCase();
            isGranted = reqLocation === 'granted' || reqCoarse === 'granted';
          }
        }
      }
      if (!isGranted) {
        const err = new Error('Permissão de localização não concedida.');
        err.code = 'LOCATION_PERMISSION_NOT_GRANTED';
        throw err;
      }
      const nativePos = await capGeo.getCurrentPosition({
        enableHighAccuracy,
        timeout,
        maximumAge
      });
      const lat = Number(nativePos?.coords?.latitude);
      const lng = Number(nativePos?.coords?.longitude);
      if (Number.isFinite(lat) && Number.isFinite(lng)) {
        return {
          coords: {
            latitude: lat,
            longitude: lng,
            accuracy: Number(nativePos?.coords?.accuracy || 0) || 0
          }
        };
      }
      throw new Error('GPS nativo retornou coordenadas inválidas.');
    } catch (e) {
      lastError = e;
      console.warn('Falha no Geolocation nativo, tentando navegador:', e);
    }
  }

  // 2) Fallback para geolocation do navegador/webview
  if (navigator.geolocation && typeof navigator.geolocation.getCurrentPosition === 'function') {
    try {
      if (!requestPermission) {
        if (navigator.permissions && typeof navigator.permissions.query === 'function') {
          const permissionStatus = await navigator.permissions.query({ name: 'geolocation' });
          const state = String(permissionStatus?.state || '').toLowerCase();
          if (state !== 'granted') {
            const err = new Error('Permissão de localização não concedida.');
            err.code = 'LOCATION_PERMISSION_NOT_GRANTED';
            throw err;
          }
        } else {
          const err = new Error('Permissão de localização não concedida.');
          err.code = 'LOCATION_PERMISSION_NOT_GRANTED';
          throw err;
        }
      }
      return await new Promise((resolve, reject) => {
        navigator.geolocation.getCurrentPosition(resolve, reject, {
          enableHighAccuracy,
          timeout,
          maximumAge
        });
      });
    } catch (e) {
      lastError = e;
    }
  }

  if (lastError) throw lastError;
  throw new Error('GPS indisponível neste aparelho.');
}

async function geocodeWorkAddress(address = '') {
  const raw = String(address || '').trim();
  if (!raw) return null;

  const direct = parseLatLngFromAddressText(raw);
  if (direct) return direct;

  const normalized = raw.replace(/\s+/g, ' ').trim();
  const compact = normalized
    .replace(/[.,;]+/g, ' ')
    .replace(/\s*-\s*/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  const primaryToken = normalized.split('-')[0]?.trim() || '';

  const queries = [normalized, compact, primaryToken]
    .map((item) => String(item || '').trim())
    .filter((item, idx, arr) => item && arr.indexOf(item) === idx);

  const providers = [
    (q) => `https://nominatim.openstreetmap.org/search?format=jsonv2&limit=1&q=${encodeURIComponent(q)}`,
    (q) => `https://geocode.maps.co/search?q=${encodeURIComponent(q)}`
  ];

  for (const query of queries) {
    for (const provider of providers) {
      const controller = typeof AbortController !== 'undefined' ? new AbortController() : null;
      const timeoutId = controller ? setTimeout(() => controller.abort(), 8000) : null;
      try {
        const response = await fetch(provider(query), {
          method: 'GET',
          signal: controller ? controller.signal : undefined,
          headers: { Accept: 'application/json' }
        });
        if (!response.ok) continue;
        const data = await response.json();
        const first = Array.isArray(data) ? data[0] : null;
        if (!first) continue;
        const lat = Number(first.lat);
        const lng = Number(first.lon ?? first.lng);
        if (!Number.isFinite(lat) || !Number.isFinite(lng)) continue;
        if (Math.abs(lat) > 90 || Math.abs(lng) > 180) continue;
        return { lat, lng };
      } catch (e) {
        // tenta o próximo provedor/consulta
      } finally {
        if (timeoutId) clearTimeout(timeoutId);
      }
    }
  }

  return null;
}

async function ensureWorkAddressCoordinates({ address = '', force = false, silent = true } = {}) {
  const job = ensureWorkJobDefaults();
  if (!job) return null;
  const rawAddress = String(address || job.address || '').trim();
  if (!rawAddress) return null;

  if (!force && job.location && String(job.location.addressSnapshot || '').trim() === rawAddress) {
    return job.location;
  }

  const point = await geocodeWorkAddress(rawAddress);
  if (!point) {
    if (!silent) {
      showToast('⚠️ Não consegui achar esse endereço automaticamente. Use "Usar local atual".');
    }
    return null;
  }

  setWorkLocationPoint(point, {
    source: 'address-geocode',
    addressSnapshot: rawAddress,
    persist: true
  });
  return getWorkLocationPoint();
}

async function setWorkLocationFromCurrentPosition() {
  console.log('[WORK-LOC] setWorkLocationFromCurrentPosition acionado');
  if (!gameState) {
    showToast('⚠️ Faça login para usar localização de trabalho.');
    return;
  }
  ensureWorkJobDefaults();

  try {
    showToast('📡 Capturando sua localização atual...');
    const position = await getCurrentDevicePosition({
      enableHighAccuracy: true,
      timeout: 18000,
      maximumAge: 10000,
      requestPermission: true
    });
    const lat = Number(position?.coords?.latitude);
    const lng = Number(position?.coords?.longitude);
    if (!Number.isFinite(lat) || !Number.isFinite(lng)) {
      throw new Error('Não consegui ler latitude/longitude do GPS.');
    }

    setWorkLocationPoint({ lat, lng }, {
      source: 'gps-current',
      addressSnapshot: getWorkAddress(),
      persist: true
    });

    renderWorkTab();
    startWorkLocationMonitor();
    showToast('✅ Local de trabalho salvo pelo GPS.');
  } catch (error) {
    console.warn('Falha ao capturar localização de trabalho:', error);
    const msg = String(error?.message || '');
    if (msg.toLowerCase().includes('denied') || msg.toLowerCase().includes('permission')) {
      showToast('❌ Permita localização no app para usar esse recurso.');
    } else {
      showToast('❌ Não consegui capturar sua localização agora.');
    }
    const fallbackAddress = String(getWorkAddress() || '').trim();
    if (fallbackAddress) {
      const point = await ensureWorkAddressCoordinates({ address: fallbackAddress, force: true, silent: true });
      if (point) {
        renderWorkTab();
        startWorkLocationMonitor();
        showToast('📍 Usei o endereço salvo como local aproximado.');
      }
    }
  }
}

function getWorkMapUrls(value = '') {
  const raw = String(value || '').trim();
  const point = getWorkLocationPoint();
  const urls = [];

  if (point) {
    const lat = Number(point.lat).toFixed(6);
    const lng = Number(point.lng).toFixed(6);
    const label = encodeURIComponent(raw || 'Trabalho');
    urls.push(`geo:${lat},${lng}?q=${lat},${lng}(${label})`);
    urls.push(`https://www.google.com/maps/search/?api=1&query=${lat},${lng}`);
    urls.push(`https://maps.google.com/?q=${lat},${lng}`);
  }

  if (raw) {
    const normalized = raw.replace(/\s+/g, ' ').trim();
    const compact = normalized
      .replace(/[.,;]+/g, ' ')
      .replace(/\s*-\s*/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();
    const queryPrimary = encodeURIComponent(normalized);
    const queryCompact = encodeURIComponent(compact);
    urls.push(`geo:0,0?q=${queryPrimary}`);
    urls.push(`https://www.google.com/maps/search/?api=1&query=${queryPrimary}`);
    urls.push(`https://maps.google.com/?q=${queryPrimary}`);
    if (compact && queryCompact !== queryPrimary) {
      urls.push(`https://www.google.com/maps/search/?api=1&query=${queryCompact}`);
    }
  }

  return urls.filter((item, idx, arr) => item && arr.indexOf(item) === idx);
}

async function openUrlWithDeviceFallback(candidates = []) {
  const list = (Array.isArray(candidates) ? candidates : [candidates])
    .map((item) => String(item || '').trim())
    .filter(Boolean);
  if (!list.length) return false;

  const uniqueUrls = [...new Set(list)];
  const appLauncherOpen = window.Capacitor?.Plugins?.AppLauncher?.openUrl;
  const browserOpen = window.Capacitor?.Plugins?.Browser?.open;
  const cordovaSystemOpen = window?.cordova?.InAppBrowser?.open;

  for (const url of uniqueUrls) {
    if (appLauncherOpen) {
      try {
        const result = await appLauncherOpen({ url });
        if (!result || result.completed !== false) return true;
      } catch (e) {
        console.warn('Falha no AppLauncher ao abrir URL:', url, e);
      }
    }

    if (browserOpen && /^https?:/i.test(url)) {
      try {
        await browserOpen({ url });
        return true;
      } catch (e) {
        console.warn('Falha no Browser plugin ao abrir URL:', url, e);
      }
    }

    if (cordovaSystemOpen && /^https?:/i.test(url)) {
      try {
        cordovaSystemOpen(url, '_system', 'location=yes');
        return true;
      } catch (e) {
        console.warn('Falha no InAppBrowser ao abrir URL:', url, e);
      }
    }

    try {
      const popup = window.open(url, '_blank', 'noopener,noreferrer');
      if (popup) return true;
    } catch (e) {
      console.warn('Falha em window.open para URL:', url, e);
    }

    try {
      window.location.assign(url);
      return true;
    } catch (e) {
      console.warn('Falha em window.location.assign para URL:', url, e);
    }
  }

  return false;
}

async function openWorkLocationMapFrom(value = '') {
  const raw = String(value || '').trim();
  if (!raw && !hasWorkLocationPoint()) {
    showToast('⚠️ Defina um endereço de trabalho primeiro.');
    return;
  }
  showToast('🗺️ Abrindo mapa...');
  const urls = getWorkMapUrls(raw);

  const opened = await openUrlWithDeviceFallback(urls);
  if (!opened) {
    showToast('❌ Não consegui abrir o mapa neste aparelho.');
  }
}

async function openWorkLocationMap() {
  const setupAddress = String(elements.jobAddressInput?.value || '').trim();
  const savedAddress = getWorkAddress();
  const targetAddress = setupAddress || savedAddress;
  if (!targetAddress && !hasWorkLocationPoint()) {
    showToast('⚠️ Digite o endereço ou toque em "Usar local atual".');
    return;
  }
  if (targetAddress && !hasWorkLocationPoint()) {
    await ensureWorkAddressCoordinates({ address: targetAddress, force: false, silent: true });
  }
  await openWorkLocationMapFrom(targetAddress);
}

function keepWorkLocationButtonsInteractive() {
  const btns = [
    elements.jobOpenMapBtn,
    elements.jobUseCurrentLocationBtn,
    elements.workOpenMapBtn,
    elements.workCheckNearbyBtn,
    elements.workUseCurrentLocationBtn
  ];
  btns.forEach((btn) => {
    if (!btn) return;
    btn.disabled = false;
    btn.style.pointerEvents = 'auto';
    btn.style.touchAction = 'manipulation';
  });
}

function syncWorkLocationStatusUI() {
  const job = ensureWorkJobDefaults();
  if (!job) return;
  const point = getWorkLocationPoint();
  const hasPoint = !!point;
  const hasAddress = !!String(getWorkAddress() || '').trim();
  const radius = getWorkLocationRadiusMeters();
  const monitorEnabled = !!job.geoMonitor?.enabled;
  const canCheck = hasPoint || hasAddress;

  if (elements.jobLocationStatus) {
    if (hasPoint) {
      const sourceLabel = point.source === 'gps-current' ? 'GPS atual' : 'endereço';
      elements.jobLocationStatus.textContent = `📡 Local ativo (${sourceLabel}) • raio ${radius}m`;
    } else if (hasAddress) {
      elements.jobLocationStatus.textContent = '📍 Endereço salvo. Toque em "Usar local atual" para precisão máxima.';
    } else {
      elements.jobLocationStatus.textContent = '📡 Local automático desativado. Toque em "Usar local atual".';
    }
  }

  if (elements.workCheckNearbyBtn) {
    elements.workCheckNearbyBtn.disabled = false;
    elements.workCheckNearbyBtn.title = canCheck
      ? 'Verificar distância até o trabalho.'
      : 'Defina endereço ou toque em "Atualizar GPS".';
  }
  if (elements.workOpenMapBtn) {
    elements.workOpenMapBtn.disabled = false;
    elements.workOpenMapBtn.title = (hasPoint || hasAddress)
      ? 'Abrir local de trabalho no mapa.'
      : 'Defina endereço ou toque em "Atualizar GPS".';
  }
  if (elements.workUseCurrentLocationBtn) {
    elements.workUseCurrentLocationBtn.disabled = false;
    elements.workUseCurrentLocationBtn.title = monitorEnabled
      ? 'Atualizar localização pelo GPS.'
      : 'Reativar localização automática e atualizar GPS.';
  }
  keepWorkLocationButtonsInteractive();
}

function shouldRequestWorkLocationPermissionAutomatically() {
  const now = Date.now();
  if (
    _workLocationPermissionPromptAt > 0 &&
    (now - _workLocationPermissionPromptAt) < WORK_LOCATION_PERMISSION_PROMPT_COOLDOWN_MS
  ) {
    return false;
  }
  _workLocationPermissionPromptAt = now;
  return true;
}

function getNativeWorkLocationMonitorPlugin() {
  try {
    const cap = window.Capacitor;
    if (!cap || !isNativeCapacitorPlatform()) return null;
    if (cap.Plugins?.WorkLocationMonitor) return cap.Plugins.WorkLocationMonitor;
    if (!_nativeWorkLocationMonitorPlugin && typeof cap.registerPlugin === 'function') {
      _nativeWorkLocationMonitorPlugin = cap.registerPlugin('WorkLocationMonitor');
    }
    return _nativeWorkLocationMonitorPlugin || null;
  } catch (e) {
    return null;
  }
}

function getStoredWorkTimerStartTime() {
  try {
    const value = Number(localStorage.getItem('work_start_time') || 0);
    return Number.isFinite(value) && value > 0 ? value : 0;
  } catch (e) {
    return 0;
  }
}

async function syncNativeWorkTimerStateWithMonitor({ running = null, startTime = null } = {}) {
  if (!isNativeCapacitorPlatform()) return false;
  const plugin = getNativeWorkLocationMonitorPlugin();
  if (!plugin || typeof plugin.syncTimerState !== 'function') return false;

  const fallbackStart = getStoredWorkTimerStartTime();
  const parsedStart = Number(startTime);
  const safeStart = Number.isFinite(parsedStart) && parsedStart > 0
    ? parsedStart
    : fallbackStart;
  const safeRunning = typeof running === 'boolean' ? running : (safeStart > 0);

  try {
    await plugin.syncTimerState({
      running: !!safeRunning,
      startTime: safeRunning ? safeStart : 0
    });
    return true;
  } catch (e) {
    console.warn('Falha ao sincronizar timer no monitor nativo:', e);
    return false;
  }
}

async function resolveWorkLocationPointForNativeMonitor(job = ensureWorkJobDefaults()) {
  const hasAddress = !!String(job?.address || '').trim();
  let point = getWorkLocationPoint();
  if (!point && hasAddress) {
    point = await ensureWorkAddressCoordinates({ address: job.address, force: false, silent: true });
  }
  if (!point) return null;
  const lat = Number(point.lat);
  const lng = Number(point.lng);
  if (!Number.isFinite(lat) || !Number.isFinite(lng)) return null;
  if (Math.abs(lat) > 90 || Math.abs(lng) > 180) return null;
  return { lat, lng };
}

function stopWorkLocationMonitorIntervalOnly() {
  if (_workLocationMonitorInterval) {
    clearInterval(_workLocationMonitorInterval);
    _workLocationMonitorInterval = null;
  }
}

async function syncNativeWorkLocationMonitorState({ requestPermission = false, forceDisable = false } = {}) {
  if (!isNativeCapacitorPlatform()) return false;
  if (_nativeWorkLocationSyncPromise) return _nativeWorkLocationSyncPromise;

  _nativeWorkLocationSyncPromise = (async () => {
    const plugin = getNativeWorkLocationMonitorPlugin();
    if (!plugin) return false;

    // Timer sempre sincronizado, mesmo se o monitor estiver desativado.
    await syncNativeWorkTimerStateWithMonitor();

    if (forceDisable) {
      if (typeof plugin.stopMonitor === 'function') {
        try { await plugin.stopMonitor(); } catch (e) {}
      }
      return true;
    }

    const job = ensureWorkJobDefaults();
    const hasAddress = !!String(job?.address || '').trim();
    const isEligible = !!(job?.name && job?.geoMonitor?.enabled && (hasWorkLocationPoint() || hasAddress));
    if (!isEligible) {
      if (typeof plugin.stopMonitor === 'function') {
        try { await plugin.stopMonitor(); } catch (e) {}
      }
      return true;
    }

    const point = await resolveWorkLocationPointForNativeMonitor(job);
    if (!point) {
      if (typeof plugin.stopMonitor === 'function') {
        try { await plugin.stopMonitor(); } catch (e) {}
      }
      return false;
    }

    if (typeof plugin.checkPermissions === 'function') {
      try {
        let perm = await plugin.checkPermissions();
        const grantedDirect = parseNativeBooleanResult(perm?.granted);
        const locationDirect = parseNativeBooleanResult(perm?.locationGranted);
        let hasLocationPermission = (locationDirect !== false) && (grantedDirect !== false);

        if (!hasLocationPermission && requestPermission && typeof plugin.requestPermission === 'function') {
          perm = await plugin.requestPermission();
          const grantedAfter = parseNativeBooleanResult(perm?.granted);
          const locationAfter = parseNativeBooleanResult(perm?.locationGranted);
          hasLocationPermission = (locationAfter !== false) && (grantedAfter !== false);
        }

        if (!hasLocationPermission) {
          return false;
        }
      } catch (e) {
        console.warn('Falha ao validar permissões do monitor nativo:', e);
        return false;
      }
    }

    if (typeof plugin.startMonitor === 'function') {
      try {
        await plugin.startMonitor({
          workLat: point.lat,
          workLng: point.lng,
          radiusMeters: getWorkLocationRadiusMeters(),
          promptCooldownMs: WORK_LOCATION_PROMPT_COOLDOWN_MS,
          autoStopDistanceMeters: WORK_TIMER_AUTO_STOP_DISTANCE_METERS
        });
      } catch (e) {
        console.warn('Falha ao iniciar monitor nativo de trabalho:', e);
        return false;
      }
    }

    return true;
  })().finally(() => {
    _nativeWorkLocationSyncPromise = null;
  });

  return _nativeWorkLocationSyncPromise;
}

async function consumePendingNativeWorkLocationActions({ silent = true } = {}) {
  if (!isNativeCapacitorPlatform()) return false;
  const plugin = getNativeWorkLocationMonitorPlugin();
  if (!plugin || typeof plugin.consumePendingActions !== 'function') return false;

  try {
    const result = await plugin.consumePendingActions();
    const pendingStart = Number(result?.pendingStartTime || 0);
    const pendingStop = Number(result?.pendingStopTime || 0);
    const pendingStopStart = Number(result?.pendingStopStartTime || 0);
    let changed = false;

    if (pendingStart > 0) {
      if (window.WorkTimer && typeof window.WorkTimer.start === 'function') {
        window.WorkTimer.start({ startTime: pendingStart, source: 'native-notification' });
      } else {
        localStorage.setItem('work_start_time', String(pendingStart));
        window.dispatchEvent(new CustomEvent('workTimerStarted', {
          detail: { startTime: pendingStart, source: 'native-notification' }
        }));
      }
      changed = true;
      if (!silent) showToast('⏱️ Ponto iniciado pela notificação.');
    }

    if (pendingStop > 0) {
      const fallbackStart = getStoredWorkTimerStartTime();
      const stopStart = pendingStopStart > 0 ? pendingStopStart : fallbackStart;
      if (window.WorkTimer && typeof window.WorkTimer.stop === 'function') {
        window.WorkTimer.stop({
          startTime: stopStart,
          endTime: pendingStop,
          source: 'native-auto-stop'
        });
      } else {
        if (typeof window.finishWorkSession === 'function') {
          window.finishWorkSession(stopStart, pendingStop);
        }
        localStorage.removeItem('work_start_time');
        window.dispatchEvent(new CustomEvent('workTimerStopped', {
          detail: { startTime: stopStart, endTime: pendingStop, source: 'native-auto-stop' }
        }));
      }
      changed = true;
      if (!silent) showToast('⏹️ Ponto encerrado automaticamente.');
    }

    await syncNativeWorkTimerStateWithMonitor();
    return changed;
  } catch (e) {
    console.warn('Falha ao consumir ações pendentes do monitor nativo:', e);
    return false;
  }
}

async function checkWorkLocationProximity({ manual = false, allowPermissionPrompt = false } = {}) {
  console.log('[WORK-LOC] checkWorkLocationProximity', { manual, allowPermissionPrompt });
  if (_workLocationMonitorBusy) {
    if (manual) showToast('⏳ Aguarde a verificação atual terminar.');
    return null;
  }
  const job = ensureWorkJobDefaults();
  if (!job || !job.name) {
    if (manual) showToast('⚠️ Configure seu trabalho primeiro.');
    return null;
  }
  if (!job.geoMonitor?.enabled) {
    if (manual) {
      job.geoMonitor.enabled = true;
      saveGame(true);
      showToast('📡 Local automático reativado. Toque novamente para verificar.');
    }
    return null;
  }
  if (manual) showToast('📡 Verificando localização...');

  let point = getWorkLocationPoint();
  if (!point && job.address) {
    point = await ensureWorkAddressCoordinates({ address: job.address, force: false, silent: true });
  }

  if (!point) {
    if (manual) showToast('⚠️ Defina o local de trabalho (GPS) para usar a proximidade.');
    return null;
  }

  _workLocationMonitorBusy = true;
  try {
    const shouldRequestPermission = manual || (
      allowPermissionPrompt && shouldRequestWorkLocationPermissionAutomatically()
    );
    const pos = await getCurrentDevicePosition({
      enableHighAccuracy: true,
      timeout: 12000,
      maximumAge: 30000,
      requestPermission: shouldRequestPermission
    });
    const currentLat = Number(pos?.coords?.latitude);
    const currentLng = Number(pos?.coords?.longitude);
    if (!Number.isFinite(currentLat) || !Number.isFinite(currentLng)) {
      throw new Error('Posição atual inválida.');
    }

    const distance = haversineDistanceMeters(currentLat, currentLng, Number(point.lat), Number(point.lng));
    const radius = getWorkLocationRadiusMeters();
    const isInside = distance <= radius;

    _workLocationMonitorLastDistanceMeters = distance;
    _workLocationMonitorLastCheckAt = Date.now();

    if (manual) {
      const insideTxt = isInside ? '✅ Você está no local de trabalho.' : '📍 Você ainda não chegou no local.';
      showToast(`${insideTxt} Distância: ${formatDistanceMeters(distance)}.`);
    }

    const timerRunning = !!window.WorkTimer?.isRunning?.();
    if (!isInside) {
      if (timerRunning && distance > WORK_TIMER_AUTO_STOP_DISTANCE_METERS && window.WorkTimer && typeof window.WorkTimer.stop === 'function') {
        window.WorkTimer.stop();
        showToast(`⏹️ Ponto encerrado automaticamente. Você saiu ${formatDistanceMeters(distance)} do trabalho.`);
        return { distance, inside: false, timerStopped: true, autoStopped: true };
      }
      return { distance, inside: false };
    }

    if (timerRunning) {
      if (manual) showToast('⏱️ O ponto já está em andamento.');
      return { distance, inside: true, timerRunning: true };
    }

    const now = Date.now();
    const lastPromptAt = Number.isFinite(Date.parse(job.geoMonitor?.lastPromptAt || '')) ? Date.parse(job.geoMonitor.lastPromptAt) : 0;
    const canPrompt = manual || (now - lastPromptAt >= WORK_LOCATION_PROMPT_COOLDOWN_MS);
    if (!canPrompt) return { distance, inside: true, cooldown: true };

    job.geoMonitor.lastPromptAt = new Date(now).toISOString();
    saveGame(true);

    if (manual) {
      const shouldStart = confirm(`Você está a ${formatDistanceMeters(distance)} do trabalho.\nDeseja iniciar o ponto agora?`);
      if (shouldStart && window.WorkTimer && typeof window.WorkTimer.start === 'function') {
        window.WorkTimer.start();
        showToast('⏱️ Ponto iniciado.');
      }
      return { distance, inside: true, prompted: true, manualPrompt: true };
    }

    const notified = await notifyWorkTimerStartPrompt(distance);
    if (notified) {
      showToast('📲 Responda na notificação: Iniciar ou Agora não.');
    } else {
      showToast('⚠️ Não consegui enviar a notificação de início do ponto.');
    }
    return { distance, inside: true, prompted: true, notificationPrompt: true, notified };
  } catch (error) {
    const msg = String(error?.message || '').toLowerCase();
    if (manual) {
      if (msg.includes('permission') || msg.includes('denied')) {
        showToast('❌ Permita localização no app para usar este recurso.');
      } else {
        showToast('❌ Não consegui verificar sua localização agora.');
      }
      if (!window.WorkTimer?.isRunning?.()) {
        const startManual = confirm('Não consegui validar o GPS agora.\nDeseja iniciar o ponto manualmente?');
        if (startManual && window.WorkTimer && typeof window.WorkTimer.start === 'function') {
          window.WorkTimer.start();
          showToast('⏱️ Ponto iniciado manualmente.');
        }
      }
    } else if ((msg.includes('permission') || msg.includes('denied')) && allowPermissionPrompt) {
      showToast('📍 Permita localização para iniciar o ponto automaticamente.');
    }
    return null;
  } finally {
    _workLocationMonitorBusy = false;
  }
}

function stopWorkLocationMonitor() {
  stopWorkLocationMonitorIntervalOnly();
  syncNativeWorkLocationMonitorState({ forceDisable: true }).catch(() => {});
}

function startWorkLocationMonitor() {
  stopWorkLocationMonitorIntervalOnly();
  const job = ensureWorkJobDefaults();
  const hasAddress = !!String(job?.address || '').trim();
  if (!job || !job.name || !job.geoMonitor?.enabled || (!hasWorkLocationPoint() && !hasAddress)) {
    syncNativeWorkLocationMonitorState({ forceDisable: true }).catch(() => {});
    return;
  }

  if (isNativeCapacitorPlatform()) {
    syncNativeWorkLocationMonitorState({
      requestPermission: shouldRequestWorkLocationPermissionAutomatically()
    }).catch(() => {});
    return;
  }

  _workLocationMonitorInterval = setInterval(() => {
    checkWorkLocationProximity({ manual: false, allowPermissionPrompt: false }).catch(() => {});
  }, WORK_LOCATION_CHECK_INTERVAL_MS);

  setTimeout(() => {
    checkWorkLocationProximity({ manual: false, allowPermissionPrompt: true }).catch(() => {});
  }, 1200);
}

// Exposição explícita para handlers inline no HTML (fallback robusto em WebView)
window.getWorkAddress = getWorkAddress;
window.openWorkLocationMap = openWorkLocationMap;
window.openWorkLocationMapFrom = openWorkLocationMapFrom;
window.setWorkLocationFromCurrentPosition = setWorkLocationFromCurrentPosition;
window.checkWorkLocationProximity = checkWorkLocationProximity;

async function saveJobSettings() {
  const name = String(elements.jobNameInput?.value || '').trim();
  const address = String(elements.jobAddressInput?.value || '').trim();
  const type = String(elements.jobTypeSelect?.value || 'pizzaria').trim() || 'pizzaria';

  if (!name) {
    showToast('⚠️ Digite o nome da empresa!');
    return;
  }

  const job = ensureWorkJobDefaults();
  if (!job) return;
  const previousAddress = String(job.address || '').trim();

  job.name = name;
  job.type = type;
  job.address = address;

  const changedAddress = previousAddress !== address;
  if (changedAddress && job.location && String(job.location.source || '') === 'address-geocode') {
    job.location = null;
  }
  if (!job.config) job.config = { rate: 0 };

  if (address && (changedAddress || !job.location)) {
    await ensureWorkAddressCoordinates({ address, force: changedAddress, silent: true });
  }

  saveGame();
  renderWorkTab();
  startWorkLocationMonitor();
  showToast('💼 Trabalho configurado!');
}

function resetJobSettings() {
  if (confirm('Deseja reconfigurar seu trabalho? O histórico será mantido.')) {
    ensureWorkJobDefaults();
    gameState.job.name = null;
    saveGame();
    renderWorkTab();
    startWorkLocationMonitor();
  }
}

function renderWorkTab() {
  const job = ensureWorkJobDefaults();
  if (!job) return;

  if (elements.jobNameInput) elements.jobNameInput.value = String(gameState.job.name || '');
  if (elements.jobTypeSelect && gameState.job.type) elements.jobTypeSelect.value = String(gameState.job.type);
  if (elements.jobAddressInput) elements.jobAddressInput.value = String(gameState.job.address || '');
  if (elements.workLocationDisplay) {
    const point = getWorkLocationPoint();
    const gpsSuffix = point ? ' • GPS ativo' : '';
    elements.workLocationDisplay.textContent = gameState.job.address
      ? `📍 ${gameState.job.address}${gpsSuffix}`
      : 'Local de trabalho não definido.';
  }
  syncWorkLocationStatusUI();
  keepWorkLocationButtonsInteractive();

  if (!gameState.job || !gameState.job.name) {
    // Modo Configuração
    if (elements.workSetupSection) elements.workSetupSection.classList.remove('hidden');
    if (elements.workDashboardSection) elements.workDashboardSection.classList.add('hidden');
    stopWorkLocationMonitor();
  } else {
    // Modo Dashboard
    if (elements.workSetupSection) elements.workSetupSection.classList.add('hidden');
    if (elements.workDashboardSection) elements.workDashboardSection.classList.remove('hidden');
    
    if (elements.workTitleDisplay) elements.workTitleDisplay.textContent = `💼 ${gameState.job.name}`;
    
    applyWorkWeeklyOverduePenalties({ showToastOnChange: true, persist: true });
    renderWorkSingularity();
    renderWorkWeeklyPlanner();
    renderWorkHistory();
    renderWorkChart();
    startWorkLocationMonitor();
  }
}

// Estado do modo de entrada (Produção ou Horas)
window.workEntryMode = 'production';
window.setWorkEntryMode = function(mode) {
  window.workEntryMode = mode;
  renderWorkSingularity();
};

function getWorkWeeklyTaskVisualState(task = {}, todayIso = getTodayIsoLocalDate()) {
  const progress = getWorkWeeklyProgressValue(task);
  const dueDateIso = getWorkWeeklyTaskDueDate(task);
  const statusRaw = String(task?.status || '').trim().toLowerCase();
  const isOverdue = progress < 100 && !!dueDateIso && dueDateIso < todayIso;

  let key = 'pending';
  if (progress >= 100 || statusRaw === 'completed') key = 'completed';
  else if (isOverdue || statusRaw === 'missed') key = 'missed';
  else if (progress > 0) key = 'in_progress';

  let label = 'Não iniciada';
  if (key === 'completed') label = 'Concluída';
  else if (key === 'missed') label = 'Atrasada';
  else if (key === 'in_progress') label = 'Em andamento';

  return { progress, dueDateIso, isOverdue, key, label };
}

function queueWorkWeekPlanLocalNotificationSync() {
  Promise.resolve(syncWorkWeekPlanLocalNotifications()).catch((e) => {
    console.warn('Falha ao sincronizar notificação do planejamento semanal:', e);
  });
}

function renderWorkWeeklyPlanner() {
  const container = elements.workWeeklyPlannerContainer || document.getElementById('workWeeklyPlannerContainer');
  if (!container) return;

  const todayIso = getTodayIsoLocalDate();
  const plan = ensureWorkWeekPlanDefaults();
  const weekTasks = plan
    .slice()
    .sort((a, b) => {
      const dueA = getWorkWeeklyTaskDueDate(a) || '9999-12-31';
      const dueB = getWorkWeeklyTaskDueDate(b) || '9999-12-31';
      const dueDiff = dueA.localeCompare(dueB);
      if (dueDiff !== 0) return dueDiff;
      return String(a?.createdAt || '').localeCompare(String(b?.createdAt || ''));
    });

  const totalTasks = weekTasks.length;
  const completedTasks = weekTasks.filter((task) => getWorkWeeklyProgressValue(task) >= 100).length;
  const averageProgress = totalTasks
    ? Math.round(weekTasks.reduce((sum, task) => sum + getWorkWeeklyProgressValue(task), 0) / totalTasks)
    : 0;

  const formatDueDateLabel = (isoDate = '') => {
    const parsed = parseIsoLocalDate(isoDate);
    if (!parsed) return '--/--/----';
    return parsed.toLocaleDateString('pt-BR');
  };

  const tasksHtml = weekTasks.length
    ? weekTasks.map((task) => {
      const safeId = String(task.id || '').trim();
      const planned = String(task.plannedText || '').trim() || 'Sem tarefa definida';
      const done = String(task.doneText || '').trim();
      const start = task.startTime || '--:--';
      const end = task.endTime || '--:--';
      const durationLabel = formatWorkDurationLabel(task.durationHours || 0);
      const visual = getWorkWeeklyTaskVisualState(task, todayIso);
      const dueLabel = formatDueDateLabel(visual.dueDateIso);
      const statusClass = visual.key === 'completed'
        ? 'is-completed'
        : (visual.key === 'missed' ? 'is-missed' : 'is-pending');

      const xpReward = Math.max(1, Number(task.xpReward) || WORK_WEEKLY_BASE_XP_REWARD);
      const xpPenalty = Math.max(1, Number(task.xpPenalty) || WORK_WEEKLY_BASE_XP_PENALTY);
      let xpHint = `Recompensa: +${xpReward} XP`;
      if (visual.key === 'completed') {
        xpHint = task.xpAwardedAt
          ? `XP recebido: +${xpReward}`
          : (task.penalizedAt ? 'Concluída sem XP (atraso)' : `Concluída: +${xpReward} XP`);
      } else if (visual.key === 'missed') {
        xpHint = task.penalizedAt
          ? `Atrasada: -${xpPenalty} XP aplicado`
          : `Atrasada: -${xpPenalty} XP`;
      }

      const doneText = done || 'Sem registro do que foi feito.';
      const controlsLabel = visual.key === 'completed' ? 'Reabrir' : '100%';

      return `
        <article class="work-week-item ${statusClass}">
          <div class="work-week-item-main">
            <div class="work-week-item-header">
              <div class="work-week-item-title">🍕 ${escapeHtmlSafe(planned)}</div>
              <span class="work-week-status">${escapeHtmlSafe(visual.label)}</span>
            </div>
            <div class="work-week-item-meta">
              <span class="badge">📅 ${escapeHtmlSafe(dueLabel)}</span>
              <span class="badge">📈 ${visual.progress}%</span>
              <span class="badge">⭐ ${escapeHtmlSafe(xpHint)}</span>
            </div>
            <div class="work-week-item-progress-wrap">
              <div class="work-week-item-progress-top">
                <span>Progresso da missão</span>
                <strong>${visual.progress}%</strong>
              </div>
              <div class="work-week-item-progress-bar">
                <div class="work-week-item-progress-fill" style="width:${visual.progress}%;"></div>
              </div>
            </div>
            <div class="work-week-item-summary">📝 ${escapeHtmlSafe(doneText)}</div>
            <div class="work-week-item-summary small">⏱️ Início: ${escapeHtmlSafe(start)} • Fim: ${escapeHtmlSafe(end)} • Carga: ${escapeHtmlSafe(durationLabel)}</div>
          </div>
          <div class="work-week-item-actions">
            <input
              class="work-week-item-range"
              type="range"
              min="0"
              max="100"
              step="1"
              value="${visual.progress}"
              onchange="updateWorkWeeklyTaskProgress('${safeId}', this.value)"
            />
            <div class="work-week-item-action-buttons">
              <button class="btn-small" type="button" onclick="toggleWorkWeeklyTaskComplete('${safeId}')">${escapeHtmlSafe(controlsLabel)}</button>
              <button class="btn-small btn-danger" type="button" onclick="removeWorkWeeklyTask('${safeId}')">Excluir</button>
            </div>
            <div class="work-week-item-action-buttons compact">
              <button class="ghost" type="button" onclick="startWorkWeeklyTask('${safeId}')">▶️ Iniciar</button>
              <button class="ghost" type="button" onclick="stopWorkWeeklyTask('${safeId}')">⏹️ Finalizar</button>
              <button class="ghost" type="button" onclick="editWorkWeeklyTaskDone('${safeId}')">📝 Relato</button>
            </div>
          </div>
        </article>
      `;
    }).join('')
    : `
      <div class="work-weekly-empty">
        Nenhuma missão cadastrada nesta semana.<br>
        Adicione a primeira tarefa da pizzaria.
      </div>
    `;

  container.innerHTML = `
    <div class="work-weekly-card">
      <div class="work-weekly-hero">
        <div class="work-weekly-title">📜 Planejamento da Pizzaria do Reino</div>
        <div class="work-weekly-subtitle">Missões salvas: ${totalTasks} • ordenadas por data</div>
      </div>

      <div class="work-weekly-grid">
        <section class="work-weekly-panel">
          <h4>➕ Nova missão</h4>
          <div class="work-weekly-form-group">
            <label for="workWeeklyTaskNameInput">Afazer</label>
            <input id="workWeeklyTaskNameInput" type="text" placeholder="Ex: Comprar queijo, revisar estoque...">
          </div>
          <div class="work-weekly-form-group">
            <label for="workWeeklyTaskDateInput">Dia para fazer</label>
            <input id="workWeeklyTaskDateInput" type="date" value="${escapeHtmlSafe(todayIso)}">
          </div>
          <div class="work-weekly-form-group">
            <label for="workWeeklyTaskProgressInput">Progresso inicial</label>
            <input id="workWeeklyTaskProgressInput" type="number" min="0" max="100" step="1" value="0">
          </div>
          <div class="work-weekly-form-group">
            <label for="workWeeklyTaskDoneInput">Descrição inicial (opcional)</label>
            <input id="workWeeklyTaskDoneInput" type="text" placeholder="Ex: Separar ingredientes do turno">
          </div>
          <button class="btn work-weekly-submit-btn" type="button" onclick="addWorkWeeklyTask()">Salvar missão</button>
          <div class="work-weekly-note">Dica: ao chegar em 100%, a tarefa fica concluída.</div>
        </section>

        <section class="work-weekly-panel">
          <h4>🛡️ Quadro de missões</h4>
          <div class="work-weekly-stats">
            <div class="work-weekly-stat-box">
              <span class="value">${totalTasks}</span>
              <span class="label">Missões</span>
            </div>
            <div class="work-weekly-stat-box">
              <span class="value">${completedTasks}</span>
              <span class="label">Concluídas</span>
            </div>
            <div class="work-weekly-stat-box">
              <span class="value">${averageProgress}%</span>
              <span class="label">Progresso médio</span>
            </div>
          </div>
          <div class="work-weekly-task-list">${tasksHtml}</div>
        </section>
      </div>
    </div>
  `;
}

window.addWorkWeeklyTask = function(event) {
  if (event && typeof event.preventDefault === 'function') event.preventDefault();
  if (!gameState) return;

  const taskNameInput = document.getElementById('workWeeklyTaskNameInput');
  const taskDateInput = document.getElementById('workWeeklyTaskDateInput');
  const progressInput = document.getElementById('workWeeklyTaskProgressInput');
  const taskDoneInput = document.getElementById('workWeeklyTaskDoneInput');

  const plannedText = String(taskNameInput?.value || '').trim().slice(0, 200);
  if (!plannedText) {
    showToast('⚠️ Digite a tarefa da semana.');
    return;
  }

  const dueDateRaw = String(taskDateInput?.value || '').trim();
  const dueDate = parseIsoLocalDate(dueDateRaw) || new Date();

  const dayIndex = dueDate.getDay() === 0 ? 7 : dueDate.getDay();
  const weekStart = getWorkWeekStartIso(dueDate);
  const progress = clampWorkWeeklyProgress(progressInput?.value || 0);
  const nowIso = new Date().toISOString();

  const plan = ensureWorkWeekPlanDefaults();
  plan.push({
    id: `ww_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`,
    weekStart,
    dayIndex,
    plannedText,
    doneText: String(taskDoneInput?.value || '').trim().slice(0, 220),
    startTime: '',
    endTime: '',
    durationHours: 0,
    progress,
    status: progress >= 100 ? 'completed' : 'pending',
    xpReward: WORK_WEEKLY_BASE_XP_REWARD,
    xpPenalty: WORK_WEEKLY_BASE_XP_PENALTY,
    createdAt: nowIso,
    updatedAt: nowIso,
    completedAt: progress >= 100 ? nowIso : '',
    penalizedAt: '',
    xpAwardedAt: ''
  });

  gameState.workWeekPlan = normalizeWorkWeekPlanEntries(plan, WORK_WEEK_PLAN_MAX_ITEMS);
  saveGame(true);
  queueWorkWeekPlanLocalNotificationSync();

  if (taskNameInput) taskNameInput.value = '';
  if (taskDoneInput) taskDoneInput.value = '';
  if (progressInput) progressInput.value = '0';
  if (taskDateInput) taskDateInput.value = getTodayIsoLocalDate();

  renderWorkWeeklyPlanner();
  showToast('✅ Missão adicionada no planejamento.');
};

window.updateWorkWeeklyTaskProgress = function(taskId, value) {
  const task = getWorkWeeklyTaskById(taskId);
  if (!task) return;

  const nextProgress = clampWorkWeeklyProgress(value);
  if (nextProgress >= 100) {
    window.completeWorkWeeklyTask(taskId, { silentToast: true });
    return;
  }

  const dueDateIso = getWorkWeeklyTaskDueDate(task);
  const todayIso = getTodayIsoLocalDate();
  task.progress = nextProgress;

  if (String(task.status || '').trim().toLowerCase() === 'completed') {
    task.status = (task.penalizedAt || (dueDateIso && dueDateIso < todayIso)) ? 'missed' : 'pending';
    task.completedAt = '';
  } else if (String(task.status || '').trim().toLowerCase() !== 'missed') {
    task.status = 'pending';
  }

  task.updatedAt = new Date().toISOString();
  saveGame(true);
  queueWorkWeekPlanLocalNotificationSync();
  renderWorkWeeklyPlanner();
};

window.toggleWorkWeeklyTaskComplete = function(taskId) {
  const task = getWorkWeeklyTaskById(taskId);
  if (!task) return;

  const visual = getWorkWeeklyTaskVisualState(task, getTodayIsoLocalDate());
  if (visual.progress >= 100 || visual.key === 'completed') {
    const dueDateIso = getWorkWeeklyTaskDueDate(task);
    const todayIso = getTodayIsoLocalDate();
    task.progress = 0;
    task.status = (task.penalizedAt || (dueDateIso && dueDateIso < todayIso)) ? 'missed' : 'pending';
    task.completedAt = '';
    task.updatedAt = new Date().toISOString();
    saveGame(true);
    queueWorkWeekPlanLocalNotificationSync();
    renderWorkWeeklyPlanner();
    showToast('↩️ Missão reaberta.');
    return;
  }

  window.completeWorkWeeklyTask(taskId);
};

window.startWorkWeeklyTask = function(taskId) {
  const task = getWorkWeeklyTaskById(taskId);
  if (!task) return;
  if (String(task.status || '').trim().toLowerCase() === 'completed') {
    showToast('ℹ️ Essa tarefa já foi concluída.');
    return;
  }

  task.startTime = getCurrentTimeHHMM();
  if (getWorkWeeklyProgressValue(task) <= 0) task.progress = 10;
  if (String(task.status || '').trim().toLowerCase() !== 'missed') task.status = 'pending';
  task.durationHours = computeWorkDurationHours(task.startTime, task.endTime);
  task.updatedAt = new Date().toISOString();
  saveGame(true);
  renderWorkWeeklyPlanner();
  showToast(`▶️ Início registrado: ${task.startTime}`);
};

window.stopWorkWeeklyTask = function(taskId) {
  const task = getWorkWeeklyTaskById(taskId);
  if (!task) return;
  if (String(task.status || '').trim().toLowerCase() === 'completed') {
    showToast('ℹ️ Essa tarefa já foi concluída.');
    return;
  }

  const nowLabel = getCurrentTimeHHMM();
  if (!task.startTime) task.startTime = nowLabel;
  task.endTime = nowLabel;
  task.durationHours = computeWorkDurationHours(task.startTime, task.endTime);
  if (getWorkWeeklyProgressValue(task) < 25) task.progress = 25;
  if (String(task.status || '').trim().toLowerCase() !== 'missed') task.status = 'pending';
  task.updatedAt = new Date().toISOString();
  saveGame(true);
  queueWorkWeekPlanLocalNotificationSync();
  renderWorkWeeklyPlanner();
  showToast(`⏹️ Finalização registrada: ${task.endTime}`);
};

window.editWorkWeeklyTaskDone = function(taskId) {
  const task = getWorkWeeklyTaskById(taskId);
  if (!task) return;
  const current = String(task.doneText || '').trim();
  const next = prompt('Descreva o que foi feito no dia:', current);
  if (next === null) return;

  task.doneText = String(next || '').trim().slice(0, 220);
  if (task.doneText && getWorkWeeklyProgressValue(task) < 15) task.progress = 15;
  task.updatedAt = new Date().toISOString();
  saveGame(true);
  queueWorkWeekPlanLocalNotificationSync();
  renderWorkWeeklyPlanner();
  showToast('📝 Atualizado com sucesso.');
};

window.completeWorkWeeklyTask = function(taskId, options = {}) {
  const task = getWorkWeeklyTaskById(taskId);
  if (!task) return;

  const opts = (options && typeof options === 'object') ? options : {};
  const silentToast = opts.silentToast === true;
  if (String(task.status || '').trim().toLowerCase() === 'completed' && getWorkWeeklyProgressValue(task) >= 100) {
    if (!silentToast) showToast('✅ Essa tarefa já está concluída.');
    return;
  }

  const nowIso = new Date().toISOString();
  const todayIso = getTodayIsoLocalDate();
  const dueDateIso = getWorkWeeklyTaskDueDate(task);
  let latePenalty = 0;

  if (dueDateIso && dueDateIso < todayIso && !task.penalizedAt) {
    latePenalty = Math.max(1, Math.round(Number(task.xpPenalty) || WORK_WEEKLY_BASE_XP_PENALTY));
    task.penalizedAt = nowIso;
    awardXp(-latePenalty, { silent: true, showLevelUpToast: false });
  }

  if (!task.endTime && task.startTime) {
    task.endTime = getCurrentTimeHHMM();
  }
  task.durationHours = computeWorkDurationHours(task.startTime, task.endTime);
  task.progress = 100;
  task.status = 'completed';
  task.completedAt = nowIso;
  task.updatedAt = nowIso;

  let reward = 0;
  let rewardGranted = false;
  const alreadyAwarded = !!task.xpAwardedAt;
  if (!task.penalizedAt && !alreadyAwarded) {
    reward = Math.max(1, getTaskXpReward(task.xpReward || WORK_WEEKLY_BASE_XP_REWARD, gameState));
    awardXp(reward, { silent: true });
    task.xpAwardedAt = nowIso;
    rewardGranted = true;
  }

  saveGame();
  updateUI();
  queueWorkWeekPlanLocalNotificationSync();
  renderWorkWeeklyPlanner();

  if (silentToast) return;
  if (task.penalizedAt) {
    if (latePenalty > 0) {
      showToast(`✅ Tarefa concluída. Como estava atrasada: -${latePenalty} XP.`);
    } else {
      showToast('✅ Tarefa concluída sem XP por atraso.');
    }
    return;
  }
  if (rewardGranted) {
    showToast(`🏅 Tarefa concluída! +${reward} XP`);
    return;
  }
  showToast('✅ Tarefa concluída. XP dessa missão já foi recebido antes.');
};

window.removeWorkWeeklyTask = function(taskId) {
  if (!confirm('Remover esta tarefa da semana?')) return;
  const safeId = String(taskId || '').trim();
  if (!safeId) return;
  const plan = ensureWorkWeekPlanDefaults();
  const before = plan.length;
  gameState.workWeekPlan = plan.filter((task) => String(task?.id || '').trim() !== safeId);
  if (gameState.workWeekPlan.length === before) return;
  saveGame(true);
  queueWorkWeekPlanLocalNotificationSync();
  renderWorkWeeklyPlanner();
  showToast('🗑️ Missão removida.');
};

function renderWorkSingularity() {
  if (!elements.workSingularityContainer) return;
  
  const type = gameState.job.type || 'pizzaria';
  const def = JOB_TYPES[type];
  const configValue = gameState.job.config ? (gameState.job.config.rate || 0) : 0;
  const today = new Date().toISOString().split('T')[0];
  const now = new Date();
  const defaultStartTime = `${String(now.getHours()).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`;
  
  // Determina o modo atual
  const entryMode = window.workEntryMode || 'production';
  const isTimeMode = entryMode === 'time';
  
  let currentWeek = Math.ceil(new Date().getDate() / 7);
  if (currentWeek > 4) currentWeek = 4; // Limita a 4 semanas conforme solicitado

  elements.workSingularityContainer.innerHTML = `
    <div class="control-panel">
      <div class="panel-header">
        <div style="font-weight: 700; font-size: 1.1rem; display: flex; align-items: center; gap: 10px;">
          <span style="font-size: 1.4rem;">${def.icon}</span> 
          <span>Registro de ${def.label}</span>
        </div>
        
        <!-- Configuração Rápida (Compacta) -->
        <div style="display: flex; gap: 5px; align-items: center; background: rgba(0,0,0,0.3); padding: 4px 8px; border-radius: 8px;">
          <label style="font-size: 10px; opacity: 0.7; margin: 0;">${def.configLabel}:</label>
          <input type="number" id="workConfigInput" value="${configValue}" placeholder="0" style="padding: 2px 5px; width: 60px; text-align: right; border: none; background: transparent; color: var(--accent); font-weight: bold;">
          <button class="ghost" onclick="saveWorkConfig()" style="font-size: 10px; padding: 2px 6px; height: auto; min-height: 0;">💾</button>
        </div>
      </div>

      <!-- Seletor de Tipo de Registro -->
      <div style="display:flex; background:rgba(255,255,255,0.05); padding:4px; border-radius:8px; margin-bottom:15px; gap: 5px;">
        <button class="btn ghost" onclick="setWorkEntryMode('production')" style="flex:1; font-size:12px; ${!isTimeMode ? 'background:var(--accent); color:#000; font-weight:bold;' : 'opacity:0.7;'}">${def.label}</button>
        <button class="btn ghost" onclick="setWorkEntryMode('time')" style="flex:1; font-size:12px; ${isTimeMode ? 'background:var(--accent); color:#000; font-weight:bold;' : 'opacity:0.7;'}">⏱️ Horas</button>
      </div>

      <!-- Formulário de Registro -->
      <div class="form-row" style="margin-bottom: 15px;">
        <div style="flex: 1;">
          <label style="font-size: 11px; opacity: 0.7; margin-bottom: 4px; display: block;">Data</label>
          <input type="date" id="workDateInput" value="${today}" onchange="autoSelectWeek()">
        </div>
        <div style="flex: 1;">
          <label style="font-size: 11px; opacity: 0.7; margin-bottom: 4px; display: block;">Semana</label>
          <select id="workWeekInput">
            <option value="1" ${currentWeek === 1 ? 'selected' : ''}>Semana 1</option>
            <option value="2" ${currentWeek === 2 ? 'selected' : ''}>Semana 2</option>
            <option value="3" ${currentWeek === 3 ? 'selected' : ''}>Semana 3</option>
            <option value="4" ${currentWeek === 4 ? 'selected' : ''}>Semana 4</option>
          </select>
        </div>
        <div style="flex: 1;">
          <label style="font-size: 11px; opacity: 0.7; margin-bottom: 4px; display: block;">Mês</label>
          <div style="display:flex; justify-content:center; align-items:center;">
            <div id="workMonthDisplay" role="button" tabindex="0" style="padding:8px 14px; border-radius:8px; background: rgba(255,255,255,0.02); font-weight:600; cursor:pointer;">${(new Date(today)).toLocaleString('pt-BR',{month:'short', year:'numeric'})}</div>
            <input type="month" id="workMonthInput" value="${today.slice(0,7)}" style="display:none;">
          </div>
        </div>
      </div>
      <div class="form-row" style="margin-bottom: 15px;">
        <div style="flex: 1;">
          <label style="font-size: 11px; opacity: 0.7; margin-bottom: 4px; display: block;">${isTimeMode ? 'Horas Trabalhadas' : def.inputLabel}</label>
          <input type="number" id="workInput" placeholder="${isTimeMode ? 'Ex: 8.5' : '0'}" style="font-size: 1.2rem; font-weight: bold;">
        </div>
        <div style="flex: 1;">
          <label style="font-size: 11px; opacity: 0.7; margin-bottom: 4px; display: block;">Horário de início</label>
          <input type="time" id="workStartTimeInput" value="${defaultStartTime}" style="font-size: 1rem; font-weight: 600;">
        </div>
      </div>
      <div style="margin-bottom: 15px; display: flex; align-items: center; gap: 8px; background: rgba(255,255,255,0.03); padding: 8px; border-radius: 8px;">
        <input type="checkbox" id="workUnpaidInput" style="width: auto; cursor: pointer;">
        <label for="workUnpaidInput" style="margin: 0; font-size: 12px; cursor: pointer; opacity: 0.8;">Não remunerado (apenas registro)</label>
      </div>
      <div class="form-row" style="margin-bottom: 15px;">
        <div style="flex: 1;">
          <label style="font-size: 11px; opacity: 0.7; margin-bottom: 4px; display: block;">Observação (opcional)</label>
          <input type="text" id="workNoteInput" placeholder="Ex: massa extra / erro corrigido">
        </div>
      </div>
      <button class="btn" onclick="addWorkRecord()" style="width: 100%; font-weight: 700; text-transform: uppercase; letter-spacing: 1px;">✅ Registrar Produção</button>
    </div>
  `;

  // Configurações do controle de mês (prev/next + display)
  (function attachMonthControls() {
    const monthInputEl = document.getElementById('workMonthInput');
    const monthDisplayEl = document.getElementById('workMonthDisplay');

    const formatMonthLabel = (ym) => {
      if (!ym) return 'Todos os meses';
      try {
        const [yy, mm] = ym.split('-').map(Number);
        const d = new Date(yy, (mm || 1) - 1, 1);
        const label = d.toLocaleString('pt-BR', { month: 'short', year: 'numeric' });
        return label.charAt(0).toUpperCase() + label.slice(1);
      } catch (e) { return ym || '';
      }
    };

    const updateDisplay = () => {
      const val = monthInputEl && monthInputEl.value ? monthInputEl.value : '';
      if (monthDisplayEl) monthDisplayEl.textContent = formatMonthLabel(val);
    };

    // Clique no rótulo abre o seletor nativo do month input
    if (monthDisplayEl) {
      monthDisplayEl.addEventListener('click', () => {
        if (!monthInputEl) return;
        // showPicker existe em alguns navegadores modernos
        if (typeof monthInputEl.showPicker === 'function') {
          monthInputEl.showPicker();
        } else {
          monthInputEl.click();
        }
      });
      monthDisplayEl.addEventListener('keydown', (e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); monthDisplayEl.click(); } });
    }

    if (monthInputEl) monthInputEl.addEventListener('change', updateDisplay);
    setTimeout(updateDisplay, 50);
  })();
}

// Função para selecionar a semana automaticamente baseada na data
window.autoSelectWeek = function() {
  const dateInput = document.getElementById('workDateInput');
  const weekSelect = document.getElementById('workWeekInput');
  
  if (!dateInput || !weekSelect || !dateInput.value) return;

  // Pega o dia da data selecionada (YYYY-MM-DD)
  const day = parseInt(dateInput.value.split('-')[2]);
  
  let week = Math.ceil(day / 7);
  // Garante que dias 22 a 31 fiquem na semana 4
  if (week > 4) week = 4;

  weekSelect.value = week;
  // Atualiza também o seletor de mês para manter coerência
  const monthInput = document.getElementById('workMonthInput');
  if (monthInput) {
    monthInput.value = dateInput.value.slice(0,7);
  }
};

window.saveWorkConfig = function() {
  const input = document.getElementById('workConfigInput');
  if (input) {
    const val = parseFloat(input.value);
    if (!gameState.job.config) gameState.job.config = {};
    gameState.job.config.rate = isNaN(val) ? 0 : val;
    saveGame(true);
    showToast('✅ Configuração salva!');
  }
};

window.addWorkRecord = function() {
  const input = document.getElementById('workInput');
  const dateInput = document.getElementById('workDateInput');
  const weekInput = document.getElementById('workWeekInput');
  const startTimeInput = document.getElementById('workStartTimeInput');
  const noteInput = document.getElementById('workNoteInput');
  const unpaidInput = document.getElementById('workUnpaidInput');
  if (!input) return;
  
  const val = parseFloat(input.value);
  if (isNaN(val) || val <= 0) {
    showToast('⚠️ Valor inválido!');
    return;
  }

  const entryMode = window.workEntryMode || 'production';
  const type = entryMode === 'time' ? 'time_tracking' : gameState.job.type;
  const rate = gameState.job.config.rate || 0;
  let financialValue = 0;
  let desc = '';
  const isUnpaid = unpaidInput ? unpaidInput.checked : false;
  // Usa a data do input ou hoje como fallback
  const recordDate = dateInput && dateInput.value ? dateInput.value : new Date().toISOString().split('T')[0];
  const nowForDefault = new Date();
  const defaultStartTime = `${String(nowForDefault.getHours()).padStart(2, '0')}:${String(nowForDefault.getMinutes()).padStart(2, '0')}`;
  const startTime = (startTimeInput && /^\d{2}:\d{2}$/.test(startTimeInput.value || ''))
    ? startTimeInput.value
    : defaultStartTime;
  const parsedTimestamp = new Date(`${recordDate}T${startTime}:00`).getTime();
  const recordTimestamp = Number.isFinite(parsedTimestamp) ? parsedTimestamp : Date.now();
  const week = weekInput ? weekInput.value : null;
  const monthInput = document.getElementById('workMonthInput');
  const month = monthInput && monthInput.value ? monthInput.value : (recordDate ? recordDate.slice(0,7) : null);

  // Lógica de Singularidade
  if (type === 'time_tracking') {
    // Se for freelancer, calcula valor por hora. Se não, é apenas registro de tempo (0 financeiro)
    if (gameState.job.type === 'freelancer') {
        financialValue = val * rate;
        desc = `Freelance: ${val}h`;
    } else {
        desc = `Jornada: ${val}h`;
    }
  } else if (type === 'pizzaria') {
    financialValue = val * rate;
    desc = `Produção: ${val} massas`;
  } else if (type === 'vendedor') {
    financialValue = val * (rate / 100);
    desc = `Comissão s/ venda de R$ ${val}`;
  } else if (type === 'motorista') {
    financialValue = val;
    desc = `Corrida`;
  } else if (type === 'freelancer') {
    financialValue = val;
    desc = `Projeto/Hora`;
  }

  // Salvar no Log de Trabalho
  if (!gameState.workLog) gameState.workLog = [];

  // Se for não remunerado, o valor financeiro registrado é 0 para não afetar gráficos de ganhos
  const loggedFinancialValue = isUnpaid ? 0 : financialValue;

  gameState.workLog.push({
    id: `w_${Date.now()}_${Math.random().toString(36).slice(2,6)}`,
    date: recordDate,
    timestamp: recordTimestamp,
    startTime: startTime,
    updatedAt: new Date().toISOString(),
    inputVal: val,
    financialVal: loggedFinancialValue,
    rateSnapshot: Number(rate) || 0,
    type: type,
    duration: type === 'time_tracking' ? val * 3600000 : 0, // Converte horas para ms se for tempo
    isUnpaid: isUnpaid,
    week: week
    , month: month,
    note: noteInput ? noteInput.value.trim() : ''
  });

  // Adicionar ao Financeiro (se gerou valor)
  if (loggedFinancialValue > 0) {
    // Categoria mais específica para produção de massas
    const category = (type === 'pizzaria') ? 'Produção' : 'Extra';
    const baseEntry = {
      id: Date.now(),
      desc: `${gameState.job.name} - ${desc}`,
      value: loggedFinancialValue,
      type: 'income',
      category: category
    };

    if (type === 'pizzaria') {
      // Massa: agendar para o próximo mês (não entra no saldo atual)
      if (!gameState.financePending) gameState.financePending = [];
      const now = new Date();
      const nextMonth = new Date(now.getFullYear(), now.getMonth() + 1, 1);
      gameState.financePending.push({
        ...baseEntry,
        scheduledDate: nextMonth.toISOString()
      });
    } else {
      if (!gameState.finances) gameState.finances = [];
      const financeEntry = {
        ...baseEntry,
        date: new Date(recordTimestamp).toISOString()
      };
      gameState.finances.push(financeEntry);

      // Anexa referência do lançamento financeiro ao registro de produção
      try {
        const idx = gameState.workLog.length - 1;
        if (idx >= 0) {
          gameState.workLog[idx].financeId = financeEntry.id;
        }
      } catch (e) {
        console.warn('Falha ao anexar financeId ao workLog:', e);
      }
    }
  }

  input.value = '';
  if (noteInput) noteInput.value = '';
  if (unpaidInput) unpaidInput.checked = false;
  saveGame();
  renderWorkHistory();
  renderWorkChart();
  const loggedMsg = (loggedFinancialValue > 0)
    ? (type === 'pizzaria' ? `Agendado para o próximo mês: + R$ ${loggedFinancialValue.toFixed(2)}` : `+ R$ ${loggedFinancialValue.toFixed(2)}`)
    : '(Não remunerado)';
  showToast(`✅ Registrado! ${loggedMsg}`);
}

// Função para finalizar sessão de tempo (Cronômetro)
window.finishWorkSession = function(startTime, endTimeOverride) {
  if (!gameState) return;
  
  const parsedEnd = Number(endTimeOverride);
  const now = Number.isFinite(parsedEnd) && parsedEnd > 0 ? parsedEnd : Date.now();
  const parsedStart = Number(startTime);
  const normalizedStart = Number.isFinite(parsedStart) && parsedStart > 0 ? parsedStart : now;
  let duration = now - normalizedStart;
  
  // Ignorar registros muito curtos (< 1 minuto) para evitar cliques acidentais
  if (duration < 60000) {
    showToast('⚠️ Trabalho muito curto para registrar (mínimo 1 min).');
    return;
  }

  // Limite máximo de 48 horas
  const maxDuration = 48 * 60 * 60 * 1000;
  if (duration > maxDuration) {
    duration = maxDuration;
    showToast('⚠️ Sessão ajustada para o limite de 48 horas.');
  }

  const hours = duration / 3600000;
  const type = gameState.job.type || 'pizzaria';
  let financialValue = 0;
  
  // Se for Freelancer, calcula valor por hora baseado na configuração
  if (type === 'freelancer') {
    const rate = gameState.job.config.rate || 0;
    financialValue = hours * rate;
  }

  // Adicionar ao Log
  if (!gameState.workLog) gameState.workLog = [];

  const startDate = new Date(normalizedStart);
  const startDateIso = Number.isFinite(startDate.getTime())
    ? startDate.toISOString().split('T')[0]
    : new Date().toISOString().split('T')[0];
  
  gameState.workLog.push({
    id: `w_${Date.now()}_${Math.random().toString(36).slice(2,6)}`,
    date: startDateIso,
    timestamp: normalizedStart,
    endTimestamp: now,
    startTime: new Date(normalizedStart).toTimeString().slice(0, 5),
    updatedAt: new Date().toISOString(),
    inputVal: hours, // Armazena horas como valor de entrada
    financialVal: financialValue,
    rateSnapshot: Number(gameState?.job?.config?.rate || 0),
    type: 'time_tracking', // Tipo especial para logs de tempo
    duration: duration,
    note: ''
  });

  // Adicionar ao Financeiro (apenas se gerou valor financeiro)
  if (financialValue > 0) {
    if (!gameState.finances) gameState.finances = [];
    gameState.finances.push({
      id: Date.now(),
      desc: `${gameState.job.name} (Freelancer)`,
      value: financialValue,
      type: 'income',
      category: 'Salário',
      date: new Date(now).toISOString()
    });
  }

  saveGame();
  renderWorkHistory();
  renderWorkChart();
  
  const h = Math.floor(duration / 3600000);
  const m = Math.floor((duration % 3600000) / 60000);
  showToast(`✅ Sessão registrada: ${h}h ${m}m`);
};

function renderWorkHistory() {
  if (typeof gameState === 'undefined' || gameState === null) {
    window.gameState = window.gameState || {};
    gameState = window.gameState;
  }
  if (!gameState.workLog) gameState.workLog = [];
  if (!elements.workTimeHistoryList || !elements.workProductionHistoryList) return;

  // Corrige duplicações acidentais vindas de sync/conflitos locais.
  try {
    dedupeWorkLogEntries({ persist: true });
  } catch (e) {}

  // Corrige registros antigos remunerados que ficaram sem valor.
  try {
    repairMissingWorkFinancialValues({ persist: true });
  } catch (e) {}

  // Garante IDs para permitir edição/remoção
  let needsSave = false;
  (gameState.workLog || []).forEach(item => {
    if (!item.id) {
      item.id = `w_${Date.now()}_${Math.random().toString(36).slice(2,6)}`;
      needsSave = true;
    }
  });
  if (needsSave) {
    try { saveGame(true); } catch (e) {}
  }
  
  // Pega os últimos 50 registros para não pesar
  const log = (gameState.workLog || []).slice(-50);

  const resolveStartTimeLabel = (item) => {
    if (!item || typeof item !== 'object') return '--:--';
    const ts = Number(item.timestamp || 0);
    if (Number.isFinite(ts) && ts > 0) {
      return new Date(ts).toTimeString().slice(0, 5);
    }
    const rawStartTime = String(item.startTime || '').trim();
    if (/^\d{2}:\d{2}$/.test(rawStartTime)) return rawStartTime;
    return '--:--';
  };

  // Separar logs
  const timeLogs = log.filter(i => i.type === 'time_tracking');
  const prodLogs = log.filter(i => i.type !== 'time_tracking');

  // Renderizar Lista de Ponto (Agrupada por Data)
  const renderList = (items, container, emptyMsg) => {
    container.innerHTML = '';
    if (items.length === 0) {
      container.innerHTML = `<div class="small" style="opacity:0.5; text-align: center; padding: 10px;">${emptyMsg}</div>`;
      return;
    }

    const groups = {};
    items.forEach(item => {
      if (!groups[item.date]) groups[item.date] = [];
      groups[item.date].push(item);
    });

    const sortedDates = Object.keys(groups).sort().reverse();

    sortedDates.forEach(dateKey => {
      const [y, m, d] = dateKey.split('-');
      const dateObj = new Date(y, m - 1, d);
      const dateStr = dateObj.toLocaleDateString('pt-BR', { weekday: 'long', day: 'numeric', month: 'long' });
      const capitalizedDate = dateStr.charAt(0).toUpperCase() + dateStr.slice(1);

      // Calcular total do dia
      let dailyTotalMs = 0;
      groups[dateKey].forEach(item => {
         dailyTotalMs += item.duration || (item.inputVal * 3600000);
      });
      const totalH = Math.floor(dailyTotalMs / 3600000);
      const totalM = Math.floor((dailyTotalMs % 3600000) / 60000);

      const groupDiv = document.createElement('div');
      groupDiv.style.marginBottom = '15px';
      
      let groupHtml = `
        <div style="display: flex; justify-content: space-between; align-items: center; font-size: 12px; font-weight: 700; color: var(--accent); margin-bottom: 8px; padding-bottom: 4px; border-bottom: 1px solid rgba(255,255,255,0.1); text-transform: capitalize;">
          <span>${capitalizedDate}</span>
          <span style="font-size: 11px; opacity: 0.9; background: rgba(255,255,255,0.1); padding: 2px 8px; border-radius: 10px;">Total: ${totalH}h ${totalM}m</span>
        </div>`;
      
      groups[dateKey].slice().reverse().forEach(item => {
        let text = '';
        let icon = '📄';
        const itemType = item.type || gameState.job.type || 'pizzaria';

        if (itemType === 'time_tracking') {
           const duration = item.duration || (item.inputVal * 3600000);
           const h = Math.floor(duration / 3600000);
           const m = Math.floor((duration % 3600000) / 60000);
           text = `Jornada: ${h}h ${m}m`;
           icon = '⏱️';
        } else if (itemType === 'pizzaria') {
           text = `${item.inputVal} massas`;
           icon = '🍕';
        } else if (itemType === 'vendedor') {
           text = `Venda: R$ ${item.inputVal}`;
           icon = '🤝';
        } else if (itemType === 'motorista') {
           text = `Corrida: R$ ${item.inputVal}`;
           icon = '🚖';
        } else {
           text = `Registro: ${item.inputVal}`;
        }

        let moneyDisplay = '';
        if (item.isUnpaid) {
          moneyDisplay = '<span style="opacity:0.6; font-size:11px; font-style:italic;">Não remunerado</span>';
        } else {
          const resolvedValue = getResolvedWorkFinancialValue(item);
          moneyDisplay = resolvedValue > 0 ? '+ R$ ' + resolvedValue.toFixed(2) : '';
        }

        const noteHtml = item.note ? `<div style="font-size:11px; opacity:0.7; margin-top:2px;">📝 ${item.note}</div>` : '';
        const startTimeLabel = resolveStartTimeLabel(item);
        groupHtml += `
          <div style="display: flex; align-items: center; justify-content: space-between; background: rgba(255,255,255,0.03); padding: 10px; border-radius: 8px; margin-bottom: 6px; font-size: 13px; gap:10px;">
            <div style="display: flex; align-items: center; gap: 10px; flex:1;">
              <span style="font-size: 16px;">${icon}</span>
              <div>
                <div>${text}</div>
                <div style="font-size:11px; opacity:0.65; margin-top:1px;">Início: ${startTimeLabel}</div>
                ${noteHtml}
              </div>
            </div>
            <div style="display:flex; align-items:center; gap:8px;">
              <div style="font-weight: 600; color: var(--success);">${moneyDisplay}</div>
              <button class="ghost" onclick="openWorkLogEditor('${item.id}')" title="Editar" style="padding:4px 8px;">✏️</button>
              <button class="ghost" onclick="deleteWorkLogEntry('${item.id}')" title="Excluir" style="padding:4px 8px; color: var(--danger);">🗑️</button>
            </div>
          </div>
        `;
      });

      groupDiv.innerHTML = groupHtml;
      container.appendChild(groupDiv);
    });
  };

  // Renderizar Lista de Produção (Agrupada por Semana)
  const renderProductionList = (items, container, emptyMsg) => {
    container.innerHTML = '';
    items = Array.isArray(items) ? items.filter(Boolean) : [];

    // Top: filtro com visual mais agradável
    // Preserva o valor selecionado anteriormente (pode ser string vazia para 'limpar')
    const prevSelected = (window._workHistorySelectedMonth !== undefined && window._workHistorySelectedMonth !== null)
      ? window._workHistorySelectedMonth
      : (document.getElementById('workHistoryMonthFilter') ? document.getElementById('workHistoryMonthFilter').value : null);
    const filterBar = document.createElement('div');
    filterBar.style.cssText = 'display:flex; gap:10px; align-items:center; margin-bottom:12px; padding:8px; background: rgba(255,255,255,0.02); border-radius:10px; border:1px solid rgba(255,255,255,0.04);';
    const lbl = document.createElement('label'); lbl.style.cssText = 'font-size:13px; opacity:0.85;'; lbl.textContent = 'Filtrar mês:';
    const monthInput = document.createElement('input'); monthInput.type = 'month'; monthInput.id = 'workHistoryMonthFilter';
    // Default para o mês: se não houver seleção anterior, tenta inferir a partir do último registro disponível
    let defaultMonth = new Date().toISOString().slice(0,7);
    if ((prevSelected === null || prevSelected === '') && Array.isArray(items) && items.length) {
      // procura o último item que tenha month ou date
      const last = items.slice().reverse().find(it => it.month || it.date);
      if (last) {
        if (last.month) defaultMonth = (last.month || '').slice(0,7) || defaultMonth;
        else if (last.date) defaultMonth = (last.date || '').slice(0,7) || defaultMonth;
      }
    }
    monthInput.value = (prevSelected !== null && prevSelected !== '') ? prevSelected : defaultMonth;
    monthInput.style.display = 'none';

    // Helper para formatar rótulo do mês (ex: "Fev 2026")
    const formatMonthLabel = (ym) => {
      if (!ym) return 'Todos os meses';
      try {
        const [yy, mm] = ym.split('-').map(Number);
        const d = new Date(yy, (mm || 1) - 1, 1);
        const label = d.toLocaleString('pt-BR', { month: 'short', year: 'numeric' });
        return label.charAt(0).toUpperCase() + label.slice(1);
      } catch (e) { return ym; }
    };

    // Controle visual: rótulo central clicável que abre o seletor nativo de mês
    const monthDisplay = document.createElement('div');
    monthDisplay.style.cssText = 'min-width:170px; text-align:center; cursor:pointer; user-select:none; padding:6px 10px; border-radius:8px; background: rgba(255,255,255,0.02); font-weight:600;';
    monthDisplay.textContent = formatMonthLabel(monthInput.value);

    const applyBtn = document.createElement('button'); applyBtn.className = 'ghost'; applyBtn.textContent = 'Aplicar'; applyBtn.style.fontSize = '12px';
    const clearBtn = document.createElement('button'); clearBtn.className = 'ghost'; clearBtn.textContent = 'Limpar'; clearBtn.style.fontSize = '12px';

    // Ao clicar no rótulo, abre o seletor nativo (se disponível)
    monthDisplay.onclick = () => { if (typeof monthInput.showPicker === 'function') monthInput.showPicker(); else monthInput.click(); };

    // Sincroniza rótulo quando o input realmente mudar e persiste seleção globalmente
    monthInput.onchange = () => {
      monthDisplay.textContent = formatMonthLabel(monthInput.value);
      window._workHistorySelectedMonth = monthInput.value || '';
    };

    applyBtn.onclick = () => {
      // garante que a seleção atual esteja persistida antes de re-renderizar
      window._workHistorySelectedMonth = monthInput.value || '';
      renderWorkHistory();
    };
    clearBtn.onclick = () => {
      monthInput.value = '';
      monthDisplay.textContent = formatMonthLabel('');
      window._workHistorySelectedMonth = '';
      renderWorkHistory();
    };

    filterBar.appendChild(lbl); filterBar.appendChild(monthDisplay); filterBar.appendChild(monthInput); filterBar.appendChild(applyBtn); filterBar.appendChild(clearBtn);
    container.appendChild(filterBar);

    const historyFilterEl = document.getElementById('workHistoryMonthFilter');
    const selectedMonth = historyFilterEl && historyFilterEl.value ? historyFilterEl.value : null; // format YYYY-MM

    if (items.length === 0) {
      const no = document.createElement('div'); no.className = 'small'; no.style.cssText = 'opacity:0.5; text-align:center; padding:10px;'; no.textContent = emptyMsg; container.appendChild(no); return;
    }

    // Filtra e agrupa como antes
    const filteredItems = selectedMonth ? items.filter(it => it && ((it.month && it.month.startsWith(selectedMonth)) || (it.date && it.date.startsWith(selectedMonth)))) : items;
    const groups = {};
    filteredItems.forEach(item => {
      let key = 'Outros';
      if (item.date) {
        const parts = item.date.split('-');
        if (parts.length === 3) {
          const day = parseInt(parts[2], 10);
          let weekNum = Math.ceil(day / 7);
          if (weekNum > 4) weekNum = 4;
          key = `Semana ${weekNum}`;
        }
      }
      if (!groups[key]) groups[key] = [];
      groups[key].push(item);
    });

    const sortedKeys = Object.keys(groups).sort((a, b) => {
      if (a === 'Outros') return 1; if (b === 'Outros') return -1; return a.localeCompare(b);
    });

    const resolveWorkQty = (entry) => {
      const rawQty = (entry && (entry.inputVal ?? entry.production)) ?? 0;
      const qty = Number(rawQty);
      return Number.isFinite(qty) ? qty : 0;
    };
    const isExplicitUnpaid = (entry) => entry && (entry.isUnpaid === true || entry.isUnpaid === 'true');

    // Render cada grupo como cartão
    sortedKeys.forEach((key, index) => {
      const groupItems = groups[key];
      groupItems.sort((a, b) => new Date(b.date) - new Date(a.date));

      let totalQty = 0, paidQty = 0, unpaidQty = 0;
      groupItems.forEach(i => {
        const val = resolveWorkQty(i);
        totalQty += val;
        if (isExplicitUnpaid(i)) unpaidQty += val;
        else paidQty += val;
      });

      const jobType = (gameState && gameState.job && gameState.job.type) ? gameState.job.type : 'pizzaria';
      const def = JOB_TYPES[jobType];
      const unit = def ? def.unit : 'unidades';

      const card = document.createElement('div');
      card.style.cssText = 'margin-bottom:12px; background: linear-gradient(180deg, rgba(255,255,255,0.01), rgba(255,255,255,0.02)); border-radius:10px; border:1px solid rgba(255,255,255,0.04); overflow:hidden;';

      const header = document.createElement('div');
      header.style.cssText = 'display:flex; justify-content:space-between; align-items:center; padding:12px 14px; cursor:pointer;';
      const left = document.createElement('div');
      const title = document.createElement('div'); title.style.cssText = 'font-weight:700; color:var(--accent);'; title.textContent = key;
      const subtitle = document.createElement('div'); subtitle.style.cssText = 'font-size:12px; opacity:0.75; margin-top:2px;'; subtitle.textContent = `Total: ${totalQty} ${unit} • ${paidQty} remunerado • ${unpaidQty} não remunerado`;
      left.appendChild(title); left.appendChild(subtitle);

      const right = document.createElement('div');
      const badge = document.createElement('div'); badge.style.cssText = 'background: rgba(74, 222, 128, 0.12); color: var(--success); padding:6px 10px; border-radius:999px; font-weight:700;'; badge.textContent = `${totalQty} ${unit}`;
      right.appendChild(badge);

      header.appendChild(left); header.appendChild(right);
      card.appendChild(header);

      const details = document.createElement('div'); details.id = `week-details-${index}`; details.style.cssText = 'display:none; padding:10px; border-top:1px solid rgba(255,255,255,0.04); background: linear-gradient(180deg, rgba(0,0,0,0.02), transparent);';

      const summaryBox = document.createElement('div'); summaryBox.style.cssText = 'display:flex; gap:10px; margin-bottom:10px; flex-wrap:wrap;';
      const totalBox = document.createElement('div'); totalBox.style.cssText = 'flex:1; min-width:120px; padding:8px; background: rgba(99, 102, 241, 0.12); border-radius:8px;'; totalBox.innerHTML = `<div style="font-size:12px; opacity:0.8;">Total</div><div style="font-weight:700; font-size:14px;">${totalQty} ${unit}</div>`;
      const paidBox = document.createElement('div'); paidBox.style.cssText = 'flex:1; min-width:120px; padding:8px; background: rgba(0,0,0,0.15); border-radius:8px;'; paidBox.innerHTML = `<div style="font-size:12px; opacity:0.8;">Remunerado</div><div style="font-weight:700; font-size:14px;">${paidQty} ${unit}</div>`;
      const unpaidBox = document.createElement('div'); unpaidBox.style.cssText = 'flex:1; min-width:120px; padding:8px; background: rgba(255,255,255,0.02); border-radius:8px;'; unpaidBox.innerHTML = `<div style="font-size:12px; opacity:0.8;">Não remunerado</div><div style="font-weight:700; font-size:14px;">${unpaidQty} ${unit}</div>`;
      summaryBox.appendChild(totalBox); summaryBox.appendChild(paidBox); summaryBox.appendChild(unpaidBox);
      details.appendChild(summaryBox);

      groupItems.forEach(item => {
        const row = document.createElement('div');
        row.style.cssText = 'display:flex; align-items:center; justify-content:space-between; gap:10px; padding:8px 0; border-bottom:1px solid rgba(255,255,255,0.03);';
        const left = document.createElement('div'); left.style.cssText = 'display:flex; align-items:center; gap:10px;';
        const dateBadge = document.createElement('div'); dateBadge.style.cssText = 'min-width:44px; text-align:center; padding:6px 6px; border-radius:8px; background: rgba(0,0,0,0.18); font-family: monospace; font-size:12px;'; dateBadge.textContent = new Date(item.date).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' });
        const icon = document.createElement('div'); icon.style.cssText = 'width:34px; height:34px; display:flex; align-items:center; justify-content:center; border-radius:8px; background: rgba(255,255,255,0.02); font-size:18px;';
        icon.textContent = item.type === 'pizzaria' ? '🍕' : (item.type === 'vendedor' ? '🤝' : (item.type === 'motorista' ? '🚖' : '📄'));
        const txtWrap = document.createElement('div');
        txtWrap.style.cssText = 'font-size:13px;';
        const qty = resolveWorkQty(item);
        const mainTxt = document.createElement('div'); mainTxt.textContent = item.type === 'pizzaria' ? `${qty} massas` : `${qty}`;
        txtWrap.appendChild(mainTxt);
        const startTimeTxt = document.createElement('div');
        startTimeTxt.style.cssText = 'font-size:11px; opacity:0.65; margin-top:1px;';
        startTimeTxt.textContent = `Início: ${resolveStartTimeLabel(item)}`;
        txtWrap.appendChild(startTimeTxt);
        if (item.note) {
          const note = document.createElement('div');
          note.style.cssText = 'font-size:11px; opacity:0.7; margin-top:2px;';
          note.textContent = `📝 ${item.note}`;
          txtWrap.appendChild(note);
        }
        left.appendChild(dateBadge); left.appendChild(icon); left.appendChild(txtWrap);

        const right = document.createElement('div'); right.style.cssText = 'text-align:right; min-width:90px;';
        if (item.isUnpaid) {
          right.innerHTML = '<div style="opacity:0.7; font-size:12px;">Não remunerado</div>';
        } else {
          const resolvedValue = getResolvedWorkFinancialValue(item);
          right.innerHTML = resolvedValue > 0
            ? `<div style="font-weight:700; color:var(--success);">+ R$ ${resolvedValue.toFixed(2)}</div>`
            : '';
        }

        const actions = document.createElement('div');
        actions.style.cssText = 'display:flex; align-items:center; gap:6px;';
        const editBtn = document.createElement('button');
        editBtn.className = 'ghost';
        editBtn.textContent = '✏️';
        editBtn.title = 'Editar';
        editBtn.style.padding = '4px 8px';
        editBtn.onclick = () => openWorkLogEditor(item.id);
        const delBtn = document.createElement('button');
        delBtn.className = 'ghost';
        delBtn.textContent = '🗑️';
        delBtn.title = 'Excluir';
        delBtn.style.padding = '4px 8px';
        delBtn.style.color = 'var(--danger)';
        delBtn.onclick = () => deleteWorkLogEntry(item.id);
        actions.appendChild(editBtn); actions.appendChild(delBtn);

        row.appendChild(left); row.appendChild(right); row.appendChild(actions);
        details.appendChild(row);
      });

      card.appendChild(details);
      // Toggle ao clicar no header
      header.addEventListener('click', () => { details.style.display = details.style.display === 'none' ? 'block' : 'none'; });

      container.appendChild(card);
    });
  };

  // Renderizar as duas listas
  renderList(timeLogs, elements.workTimeHistoryList, 'Sem registros de ponto.');
  renderProductionList(prodLogs, elements.workProductionHistoryList, 'Sem registros de produção.');
}

async function exportWorkMassListPdf() {
  repairMissingWorkFinancialValues({ persist: true });
  const logs = Array.isArray(gameState?.workLog) ? gameState.workLog : [];

  const resolveEntryMonth = (entry) => {
    if (!entry) return '';
    const monthRaw = String(entry.month || '').trim();
    if (/^\d{4}-\d{2}$/.test(monthRaw)) return monthRaw;
    const dateRaw = String(entry.date || '').trim();
    if (/^\d{4}-\d{2}-\d{2}$/.test(dateRaw)) return dateRaw.slice(0, 7);
    return '';
  };

  const resolveMonthLabel = (monthKey) => {
    if (!/^\d{4}-\d{2}$/.test(monthKey || '')) return 'Nao definido';
    const [year, month] = monthKey.split('-').map(Number);
    const dt = new Date(year, (month || 1) - 1, 1);
    const label = dt.toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' });
    return label.charAt(0).toUpperCase() + label.slice(1);
  };

  const getValidMonthValue = (id) => {
    const el = document.getElementById(id);
    if (!el) return '';
    const value = String(el.value || '').trim();
    return /^\d{4}-\d{2}$/.test(value) ? value : '';
  };

  const selectedFromHistory = getValidMonthValue('workHistoryMonthFilter');
  const selectedFromForm = getValidMonthValue('workMonthInput');
  const latestMassWithMonth = logs
    .slice()
    .reverse()
    .find((entry) => entry && entry.type === 'pizzaria' && resolveEntryMonth(entry));
  const fallbackMonth = (latestMassWithMonth && resolveEntryMonth(latestMassWithMonth))
    || new Date().toISOString().slice(0, 7);
  const selectedMonth = selectedFromHistory || selectedFromForm || fallbackMonth;
  const monthLabel = resolveMonthLabel(selectedMonth);

  const massLogs = logs
    .filter((entry) => {
      if (!entry || entry.type === 'time_tracking') return false;
      if (entry.type !== 'pizzaria') return false;
      return resolveEntryMonth(entry) === selectedMonth;
    })
    .slice()
    .sort((a, b) => new Date(a.date || 0) - new Date(b.date || 0));

  let totalMass = 0;
  let paidMass = 0;
  let unpaidMass = 0;
  let financialTotal = 0;

  const lines = [
    `Empresa: ${gameState?.job?.name || 'Nao definida'}`,
    `Tipo: Producao de massa`,
    `Mes de referencia: ${monthLabel}`,
    `Registros encontrados: ${massLogs.length}`,
    ''
  ];

  if (!massLogs.length) {
    lines.push('Nenhum registro de producao de massa foi encontrado para o mes selecionado.');
  } else {
    massLogs.forEach((item, idx) => {
      const qty = Number(item?.inputVal ?? item?.production ?? 0) || 0;
      const isUnpaid = item?.isUnpaid === true || item?.isUnpaid === 'true';
      const amount = Math.max(0, getResolvedWorkFinancialValue(item));
      const dateLabel = item?.date ? new Date(item.date).toLocaleDateString('pt-BR') : '-';
      const week = item?.week ? `Semana ${item.week}` : 'Sem semana';
      const note = item?.note ? ` | Obs: ${item.note}` : '';

      totalMass += qty;
      if (isUnpaid) {
        unpaidMass += qty;
      } else {
        paidMass += qty;
      }
      financialTotal += amount;

      lines.push(
        `${String(idx + 1).padStart(2, '0')}. ${dateLabel} | ${week} | ${qty} massas | ${isUnpaid ? 'Nao remunerado' : 'Remunerado'} | R$ ${formatCurrencyForPdf(amount)}${note}`
      );
    });
  }

  lines.push('');
  lines.push('Resumo:');
  lines.push(`Total de massas: ${totalMass}`);
  lines.push(`Massas remuneradas: ${paidMass}`);
  lines.push(`Massas nao remuneradas: ${unpaidMass}`);
  lines.push(`Total financeiro: R$ ${formatCurrencyForPdf(financialTotal)}`);

  await exportTextLinesAsPdf({
    title: `Relatorio de Producao de Massa - ${monthLabel}`,
    lines,
    filePrefix: `producao-massa-${selectedMonth}`,
    openAfterSave: true
  });
}

let _editingWorkLogId = null;

function roundWorkMoney(value) {
  const num = Number(value);
  if (!Number.isFinite(num)) return 0;
  return Math.round(num * 100) / 100;
}

function getWorkRateForEntry(entry) {
  const snapshot = Number(entry?.rateSnapshot);
  if (Number.isFinite(snapshot) && snapshot > 0) return snapshot;
  const currentRate = Number(gameState?.job?.config?.rate || 0);
  if (Number.isFinite(currentRate) && currentRate > 0) return currentRate;
  return 0;
}

function getResolvedWorkFinancialValue(entry) {
  if (!entry) return 0;
  const isUnpaid = entry.isUnpaid === true || entry.isUnpaid === 'true';
  if (isUnpaid) return 0;

  const stored = Number(entry.financialVal);
  if (Number.isFinite(stored) && stored > 0) return roundWorkMoney(stored);

  const rawVal = entry.inputVal ?? entry.production ?? 0;
  const val = Number(rawVal);
  if (!Number.isFinite(val) || val <= 0) return 0;

  const entryType = String(entry.type || gameState?.job?.type || 'pizzaria');
  const jobType = String(gameState?.job?.type || 'pizzaria');
  const rate = getWorkRateForEntry(entry);
  let computed = 0;

  if (entryType === 'time_tracking') {
    computed = jobType === 'freelancer' ? (val * rate) : 0;
  } else if (entryType === 'pizzaria') {
    computed = val * rate;
  } else if (entryType === 'vendedor') {
    computed = val * (rate / 100);
  } else if (entryType === 'motorista') {
    computed = val;
  } else if (entryType === 'freelancer') {
    computed = val;
  }

  return computed > 0 ? roundWorkMoney(computed) : 0;
}

function repairMissingWorkFinancialValues({ persist = true } = {}) {
  if (!gameState || !Array.isArray(gameState.workLog) || !gameState.workLog.length) return 0;
  let changed = 0;

  gameState.workLog.forEach((entry) => {
    if (!entry) return;
    const isUnpaid = entry.isUnpaid === true || entry.isUnpaid === 'true';
    if (isUnpaid) return;
    const current = Number(entry.financialVal);
    if (Number.isFinite(current) && current > 0) return;

    const resolved = getResolvedWorkFinancialValue(entry);
    if (!(resolved > 0)) return;
    entry.financialVal = resolved;
    if (!Number(entry.rateSnapshot)) entry.rateSnapshot = getWorkRateForEntry(entry);
    changed += 1;

    if (entry.financeId && Array.isArray(gameState.finances)) {
      const linked = gameState.finances.find((f) => String(f?.id) === String(entry.financeId));
      if (linked && !(Number(linked.value) > 0)) {
        linked.value = resolved;
      }
    }
  });

  if (changed > 0 && persist && typeof saveGame === 'function') {
    saveGame(true);
  }
  return changed;
}

function calculateWorkFinancialValue(type, val, isUnpaid) {
  if (isUnpaid) return 0;
  const jobType = (gameState && gameState.job && gameState.job.type) ? gameState.job.type : 'pizzaria';
  const rate = (gameState && gameState.job && gameState.job.config && gameState.job.config.rate) ? gameState.job.config.rate : 0;
  if (type === 'time_tracking') {
    // Para freelancer, calcula por hora
    return jobType === 'freelancer' ? (val * rate) : 0;
  }
  if (type === 'pizzaria') return val * rate;
  if (type === 'vendedor') return val * (rate / 100);
  if (type === 'motorista') return val;
  if (type === 'freelancer') return val;
  return 0;
}

function recomputeWeekMonth(dateStr) {
  if (!dateStr) return { week: null, month: null };
  const parts = dateStr.split('-');
  if (parts.length !== 3) return { week: null, month: null };
  const day = parseInt(parts[2], 10);
  let weekNum = Math.ceil(day / 7);
  if (weekNum > 4) weekNum = 4;
  return { week: String(weekNum), month: dateStr.slice(0, 7) };
}

function openWorkLogEditor(id) {
  const safeId = String(id || '').trim();
  const item = (gameState.workLog || []).find(i => String(i?.id || '').trim() === safeId);
  if (!item) return;
  _editingWorkLogId = safeId;
  if (!elements.workLogEditModal) return;

  const date = item.date || new Date(item.timestamp || Date.now()).toISOString().split('T')[0];
  const fallbackStartTime = String(item.startTime || '').trim();
  const time = item.timestamp
    ? new Date(item.timestamp).toTimeString().slice(0,5)
    : (/^\d{2}:\d{2}$/.test(fallbackStartTime) ? fallbackStartTime : '08:00');

  if (elements.workEditDate) elements.workEditDate.value = date;
  if (elements.workEditTime) elements.workEditTime.value = time;
  if (elements.workEditValue) elements.workEditValue.value = item.inputVal;
  if (elements.workEditUnpaid) elements.workEditUnpaid.checked = !!item.isUnpaid;
  if (elements.workEditNote) elements.workEditNote.value = item.note || '';
  if (elements.workEditValueLabel) {
    elements.workEditValueLabel.textContent = (item.type === 'time_tracking') ? 'Horas' : 'Quantidade';
  }

  elements.workLogEditModal.classList.add('active');
}

function closeWorkLogEditor() {
  if (elements.workLogEditModal) elements.workLogEditModal.classList.remove('active');
  _editingWorkLogId = null;
}

function saveWorkLogEdit() {
  if (!_editingWorkLogId) return;
  const item = (gameState.workLog || []).find(i => String(i?.id || '').trim() === String(_editingWorkLogId).trim());
  if (!item) return;

  const date = elements.workEditDate ? elements.workEditDate.value : item.date;
  const time = elements.workEditTime ? elements.workEditTime.value : '08:00';
  const rawVal = elements.workEditValue ? String(elements.workEditValue.value || '').replace(',', '.').trim() : String(item.inputVal || '0');
  const val = parseFloat(rawVal || '0');
  const isUnpaid = elements.workEditUnpaid ? elements.workEditUnpaid.checked : !!item.isUnpaid;
  const note = elements.workEditNote ? elements.workEditNote.value.trim() : (item.note || '');

  if (!date) {
    showToast('⚠️ Data inválida.');
    return;
  }
  if (!Number.isFinite(val) || val <= 0) {
    showToast('⚠️ Valor inválido para salvar.');
    return;
  }
  const ts = new Date(`${date}T${time}:00`).getTime();

  item.date = date;
  item.timestamp = isNaN(ts) ? item.timestamp : ts;
  item.startTime = time;
  item.updatedAt = new Date().toISOString();
  item.inputVal = val;
  item.isUnpaid = isUnpaid;
  item.note = note;

  if (item.type === 'time_tracking') {
    item.duration = val * 3600000;
  }

  const { week, month } = recomputeWeekMonth(date);
  if (week) item.week = week;
  if (month) item.month = month;

  // Atualiza valor financeiro e lançamento associado
  item.financialVal = calculateWorkFinancialValue(item.type, val, isUnpaid);
  if (!isUnpaid) {
    const currentRate = Number(gameState?.job?.config?.rate || 0);
    if (currentRate > 0) item.rateSnapshot = currentRate;
  }
  if (item.financeId && Array.isArray(gameState.finances)) {
    const fin = gameState.finances.find(f => f.id === item.financeId);
    if (fin) {
      fin.value = item.financialVal;
      fin.date = new Date(item.timestamp || Date.now()).toISOString();
      if (item.type === 'pizzaria') fin.category = 'Produção';
      if (item.type === 'time_tracking') fin.category = 'Salário';
      fin.desc = `${gameState.job?.name || 'Trabalho'} - ${item.type === 'pizzaria' ? 'Produção' : 'Registro'}`;
    }
  }

  saveGame();
  renderWorkHistory();
  renderWorkChart();
  closeWorkLogEditor();
  showToast('✅ Registro atualizado!');
}

async function deleteWorkLogEntry(id) {
  const safeId = String(id || '').trim();
  const item = (gameState.workLog || []).find(i => String(i?.id || '').trim() === safeId);
  if (!item) return;
  if (!confirm('Remover este registro?')) return;

  const normalizeNote = (value) => String(value || '').trim().toLowerCase().replace(/\s+/g, ' ');
  const targetType = String(item.type || '').trim();
  const targetDate = String(item.date || '').trim();
  const targetInput = Number(item.inputVal ?? item.production ?? 0);
  const targetUnpaid = normalizeWorkUnpaidFlag(item.isUnpaid);
  const targetNote = normalizeNote(item.note);
  const targetTsRaw = Number(item.timestamp || 0);
  const targetTsFallback = targetDate ? Date.parse(`${targetDate}T00:00:00`) : 0;
  const targetTs = Number.isFinite(targetTsRaw) && targetTsRaw > 0
    ? targetTsRaw
    : (Number.isFinite(targetTsFallback) ? targetTsFallback : 0);
  const targetSemantic = workLogSemanticKey(item);

  const entries = Array.isArray(gameState.workLog) ? gameState.workLog : [];
  const entriesToRemove = entries.filter((entry) => {
    if (!entry || typeof entry !== 'object') return false;
    const entryId = String(entry.id || '').trim();
    if (entryId && entryId === safeId) return true;

    // Remove duplicatas "gêmeas" (mesma data/tipo/valor + timestamp muito próximo).
    const sameType = String(entry.type || '').trim() === targetType;
    const sameDate = String(entry.date || '').trim() === targetDate;
    const sameInput = Number(entry.inputVal ?? entry.production ?? 0) === targetInput;
    const sameUnpaid = normalizeWorkUnpaidFlag(entry.isUnpaid) === targetUnpaid;
    const sameNote = normalizeNote(entry.note) === targetNote;
    const entryTsRaw = Number(entry.timestamp || 0);
    const entryTsFallback = sameDate ? Date.parse(`${targetDate}T00:00:00`) : 0;
    const entryTs = Number.isFinite(entryTsRaw) && entryTsRaw > 0
      ? entryTsRaw
      : (Number.isFinite(entryTsFallback) ? entryTsFallback : 0);
    const closeInTime = targetTs > 0 && entryTs > 0 && Math.abs(entryTs - targetTs) <= 120000;
    if (sameType && sameDate && sameInput && sameUnpaid && sameNote && closeInTime) return true;

    if (targetSemantic && workLogSemanticKey(entry) === targetSemantic) return true;
    return false;
  });

  const idsToRemove = entriesToRemove
    .map((entry) => String(entry?.id || '').trim())
    .filter(Boolean);
  const financeIdsToRemove = entriesToRemove
    .map((entry) => entry?.financeId)
    .filter(Boolean);
  const cloudIdsToRemove = Array.from(new Set(idsToRemove.filter((entryId) => isCloudUuidLike(entryId))));

  gameState.workLog = entries.filter((entry) => {
    const entryId = String(entry?.id || '').trim();
    return !idsToRemove.includes(entryId);
  });
  rememberDeletedWorkLogIds(idsToRemove.length ? idsToRemove : [safeId]);

  if (Array.isArray(gameState.finances) && financeIdsToRemove.length > 0) {
    const financeDropSet = new Set(financeIdsToRemove.map((fid) => String(fid)));
    gameState.finances = gameState.finances.filter((f) => !financeDropSet.has(String(f?.id)));
  }

  saveGame();
  renderWorkHistory();
  renderWorkChart();

  try {
    if (
      typeof SupabaseService !== 'undefined' &&
      SupabaseService.deleteWorkSession &&
      cloudIdsToRemove.length > 0
    ) {
      const removedCloudIds = [];
      for (const cloudId of cloudIdsToRemove) {
        try {
          await SupabaseService.deleteWorkSession(cloudId);
          removedCloudIds.push(cloudId);
        } catch (e) {
          console.warn('Falha ao remover registro na nuvem:', cloudId, e);
        }
      }
      if (removedCloudIds.length > 0) {
        forgetDeletedWorkLogIds(removedCloudIds);
        saveGame(true);
      }
    }
  } catch (error) {
    console.warn('Falha ao remover registro de ponto na nuvem (será reenviado depois):', error);
  }

  showToast('🗑️ Registro removido!');
}

function renderWorkChart() {
  if (!elements.workChart) return;
  
  const log = gameState.workLog || [];
  
  // Verifica se há registros de tempo (prioridade para o gráfico de tempo se houver)
  const hasTimeLogs = log.some(i => i.type === 'time_tracking');

  if (workChartInstance) {
    workChartInstance.destroy();
  }

  if (hasTimeLogs) {
    // Gráfico de Pizza: Distribuição por Dia da Semana
    const weekDays = ['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'];
    const distribution = new Array(7).fill(0);

    log.forEach(item => {
      if (item.type === 'time_tracking') {
        let date;
        if (item.timestamp) {
          date = new Date(item.timestamp);
        } else {
          // Fallback seguro para data local
          const [y, m, d] = item.date.split('-').map(Number);
          date = new Date(y, m - 1, d);
        }
        
        const dayIndex = date.getDay();
        const durationMs = item.duration || (item.inputVal * 3600000);
        distribution[dayIndex] += durationMs;
      }
    });

    // Converter ms para horas
    const dataHours = distribution.map(ms => parseFloat((ms / 3600000).toFixed(1)));

    workChartInstance = new Chart(elements.workChart, {
      type: 'pie',
      data: {
        labels: weekDays,
        datasets: [{
          data: dataHours,
          backgroundColor: [
            '#ff6384', '#36a2eb', '#ffcd56', '#4bc0c0', '#9966ff', '#ff9f40', '#c9cbcf'
          ],
          borderWidth: 1,
          borderColor: 'rgba(0,0,0,0.1)'
        }]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: { 
            position: 'right', 
            labels: { color: '#ccc', boxWidth: 12, font: { size: 11 } } 
          },
          title: {
            display: true,
            text: 'Horas por Dia da Semana',
            color: 'rgba(255,255,255,0.8)',
            font: { size: 13 },
            padding: { bottom: 10 }
          },
          tooltip: {
            callbacks: {
              label: function(context) {
                return ` ${context.label}: ${context.parsed}h`;
              }
            }
          }
        }
      }
    });

  } else {
    // Fallback: Gráfico de Barras (Financeiro) para quem só usa produção
    const days = {};
    
    log.forEach(item => {
      if (!days[item.date]) days[item.date] = 0;
      days[item.date] += getResolvedWorkFinancialValue(item);
    });

    const labels = Object.keys(days).sort().slice(-7);
    const data = labels.map(d => days[d]);
    
    const formattedLabels = labels.map(d => {
      const parts = d.split('-');
      return `${parts[2]}/${parts[1]}`;
    });

    workChartInstance = new Chart(elements.workChart, {
      type: 'bar',
      data: {
        labels: formattedLabels,
        datasets: [{
          label: 'Ganhos (R$)',
          data: data,
          backgroundColor: '#4ade80',
          borderRadius: 4
        }]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        scales: {
          y: { beginAtZero: true, grid: { color: 'rgba(255,255,255,0.1)' }, ticks: { color: '#ccc' } },
          x: { grid: { display: false }, ticks: { color: '#ccc' } }
        },
        plugins: { legend: { display: false } }
      }
    });
  }
}

function renderInventory() {
  if (elements.inventoryList) elements.inventoryList.innerHTML = '';
  const items = gameState.inventory || [];
  if (elements.inventoryCount) elements.inventoryCount.textContent = `${items.length} itens`;

  if (items.length === 0) {
    elements.inventoryList.innerHTML = '<div class="small" style="text-align:center; opacity:0.5; padding: 10px;">Mochila vazia</div>';
    return;
  }

  items.forEach((item, index) => {
    const div = document.createElement('div');
    div.className = 'inventory-item';
    div.innerHTML = `
      <span>${item.name}</span>
      <button onclick="removeItem(${index})" title="Remover">🗑️</button>
    `;
    if (elements.inventoryList) elements.inventoryList.appendChild(div);
  });
}

function renderDailyTasks() {
  const tasks = Array.isArray(gameState?.dailyTasks) ? gameState.dailyTasks : [];

  // Resumo simples de progresso
  if (elements.taskList && !document.getElementById('taskProgressContainer')) {
    const container = document.createElement('div');
    container.id = 'taskProgressContainer';
    container.className = 'task-progress-card';
    elements.taskList.parentNode.insertBefore(container, elements.taskList);
  }

  const pContainer = document.getElementById('taskProgressContainer');
  if (pContainer) {
    if (tasks.length === 0) {
      pContainer.style.display = 'none';
      pContainer.innerHTML = '';
    } else {
      pContainer.style.display = 'flex';
      const total = tasks.length;
      const completed = tasks.filter((t) => t?.completed).length;
      const percent = Math.max(0, Math.min(100, (completed / total) * 100));
      const finishedAll = percent === 100;
      pContainer.innerHTML = `
        <div class="task-progress-head">
          <span>Metas de hoje</span>
          <span>${completed}/${total} (${Math.round(percent)}%)</span>
        </div>
        <div class="task-progress-track">
          <div class="task-progress-fill"></div>
        </div>
        <div class="task-progress-note">${finishedAll ? 'Tudo concluído. Excelente!' : 'Pendentes primeiro, concluídas no fim da lista.'}</div>
      `;
      const fill = pContainer.querySelector('.task-progress-fill');
      if (fill) {
        fill.style.width = `${percent}%`;
        if (finishedAll) {
          fill.style.background = 'linear-gradient(90deg, #1fbe64, #45e58d)';
        }
      }
    }
  }

  if (!elements.taskList) return;
  elements.taskList.innerHTML = '';

  if (tasks.length === 0) {
    elements.taskList.innerHTML = '<div class="task-empty">Nenhuma tarefa definida</div>';
    return;
  }

  const sortedTasks = tasks.slice().sort((a, b) => {
    const aCompleted = !!a?.completed;
    const bCompleted = !!b?.completed;
    if (aCompleted !== bCompleted) return aCompleted ? 1 : -1;

    const aOverdue = isTaskOverdue(a);
    const bOverdue = isTaskOverdue(b);
    if (aOverdue !== bOverdue) return aOverdue ? -1 : 1;

    const aDue = getTaskDueTimestamp(a);
    const bDue = getTaskDueTimestamp(b);
    const aHasDue = Number.isFinite(aDue);
    const bHasDue = Number.isFinite(bDue);
    if (aHasDue && bHasDue && aDue !== bDue) return aDue - bDue;
    if (aHasDue !== bHasDue) return aHasDue ? -1 : 1;

    return Number(a?.id || 0) - Number(b?.id || 0);
  });

  sortedTasks.forEach((task) => {
    const overdue = isTaskOverdue(task);
    const div = document.createElement('div');
    div.className = `task-item ${task.completed ? 'completed' : ''} ${overdue ? 'overdue' : ''}`.trim();
    div.dataset.id = task.id;

    const toggleBtn = document.createElement('button');
    toggleBtn.type = 'button';
    toggleBtn.className = 'task-toggle-btn';
    toggleBtn.title = task.completed ? 'Desmarcar tarefa' : 'Concluir tarefa';
    toggleBtn.textContent = task.completed ? '✓' : '○';
    toggleBtn.onclick = (event) => {
      if (event) event.stopPropagation();
      toggleTask(task.id);
    };

    const content = document.createElement('div');
    content.className = 'task-content';
    content.tabIndex = 0;
    content.onclick = () => toggleTask(task.id);
    content.onkeydown = (event) => {
      if (event.key === 'Enter' || event.key === ' ') {
        event.preventDefault();
        toggleTask(task.id);
      }
    };

    const title = document.createElement('div');
    title.className = 'task-title';
    title.textContent = String(task?.text || '').trim() || 'Tarefa sem nome';
    content.appendChild(title);

    const dueLabel = formatTaskDueLabel(task);
    if (dueLabel) {
      const due = document.createElement('small');
      due.className = 'task-item-meta';
      due.textContent = `🗓️ ${dueLabel}`;
      if (overdue) {
        due.classList.add('task-item-meta-overdue');
      }
      content.appendChild(due);
    }

    const actions = document.createElement('div');
    actions.className = 'task-actions';

    const editBtn = document.createElement('button');
    editBtn.type = 'button';
    editBtn.className = 'ghost task-action-btn';
    editBtn.title = 'Editar tarefa';
    editBtn.textContent = '✏️';
    editBtn.onclick = (event) => editTask(task.id, event);

    const deleteBtn = document.createElement('button');
    deleteBtn.type = 'button';
    deleteBtn.className = 'ghost task-action-btn';
    deleteBtn.title = 'Excluir tarefa';
    deleteBtn.textContent = '🗑️';
    deleteBtn.onclick = (event) => removeTask(task.id, event);

    actions.appendChild(editBtn);
    actions.appendChild(deleteBtn);

    div.appendChild(toggleBtn);
    div.appendChild(content);
    div.appendChild(actions);

    elements.taskList.appendChild(div);
  });
}

function renderXpChart() {
  if (!elements.xpChart || !gameState) return;
  gameState.xpHistory = normalizeXpHistoryMap(gameState.xpHistory, 365);
  if (!isChartJsReady()) {
    paintCanvasFallbackMessage(elements.xpChart, 'Carregando histórico de XP...');
    scheduleXpChartRetry(1200);
    return;
  }
  if (xpChartRetryTimer) {
    clearTimeout(xpChartRetryTimer);
    xpChartRetryTimer = null;
  }
  
  // Preparar dados dos últimos 7 dias
  const labels = [];
  const data = [];
  const days = ['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'];
  
  for (let i = 6; i >= 0; i--) {
    const d = new Date();
    d.setDate(d.getDate() - i);
    const dateKey = d.toISOString().split('T')[0];
    const dayName = days[d.getDay()];
    
    labels.push(dayName);
    let val = (gameState.xpHistory && gameState.xpHistory[dateKey]) || 0;
    if (val < 0) val = 0; // Visualmente corrige dias passados negativos
    data.push(val);
  }

  if (xpChartInstance) {
    xpChartInstance.destroy();
  }

  xpChartInstance = new Chart(elements.xpChart, {
    type: 'bar',
    data: {
      labels: labels,
      datasets: [{
        label: 'XP (Saldo Diário)',
        data: data,
        backgroundColor: '#ffdd57',
        borderRadius: 4
      }]
    },
    options: {
      responsive: true,
      scales: {
        y: { beginAtZero: true, grid: { color: 'rgba(255,255,255,0.1)' }, ticks: { color: '#ccc' } },
        x: { grid: { display: false }, ticks: { color: '#ccc' } }
      },
      plugins: { legend: { display: false } }
    }
  });
}

function setTabBadge(tabId, show) {
  const tabBtn = document.querySelector(`.tab-btn[data-tab="${tabId}"]`);
  if (!tabBtn) return;
  
  let badge = tabBtn.querySelector('.tab-badge');
  
  if (show) {
    if (!badge) {
      badge = document.createElement('span');
      badge.className = 'tab-badge';
      badge.style.cssText = 'position: absolute; top: 5px; right: 5px; width: 8px; height: 8px; background-color: #ff4757; border-radius: 50%; box-shadow: 0 0 0 2px #2c2c2c; pointer-events: none;';
      tabBtn.style.position = 'relative';
      tabBtn.appendChild(badge);
    }
  } else {
    if (badge) badge.remove();
  }
}

function updateUI() {

  // Se não houver gameState, tenta preencher com memórias locais (OracleMemory) antes de sair
  if (!gameState) {
    try {
      if (typeof OracleMemory !== 'undefined') {
        const name = OracleMemory.getProfile && OracleMemory.getProfile('name');
        if (name) {
          gameState = normalizeGameState({
            name: name,
            username: OracleMemory.getProfile('email') || OracleMemory.getProfile('username') || 'user',
            race: OracleMemory.getProfile('occupation') || OracleMemory.getProfile('race') || 'Humano',
            title: OracleMemory.getProfile('title') || 'Viajante',
            level: parseInt(OracleMemory.getProfile('level')) || 1,
            xp: parseInt(OracleMemory.getProfile('xp')) || 0,
            skillPoints: parseInt(OracleMemory.getProfile('skillPoints')) || 0
          });
        }
      }
    } catch (e) { /* silencioso */ }
    // Se ainda não temos gameState (usuário não logado / sem OracleMemory),
    // tenta carregar o último usuário local salvo no dispositivo antes de usar placeholder.
    if (!gameState) {
      try {
        const lastUser = localStorage.getItem('ur_last_user');
        if (lastUser) {
          const users = (typeof getUsers === 'function') ? getUsers() : JSON.parse(localStorage.getItem('ur_users') || '{}');
          if (users && users[lastUser] && users[lastUser].character) {
            gameState = users[lastUser].character;
          } else {
            gameState = normalizeGameState({});
          }
        } else {
          gameState = normalizeGameState({});
        }
      } catch (e) {
        gameState = normalizeGameState({});
      }
    }
  }

  ensureEconomyState(gameState);
  ensureCinemaRoomState(gameState);
  renderAdminMaintenanceBanner();
  updateAdminPanelVisibility();
  syncGlobalHelpVisibility();

  const financeStateChanged = ensureFinanceMonthlyState();
  if (financeStateChanged && isLoggedIn) {
    saveGame(true);
  }
  
  // Atualizar preview do personagem (com placeholders seguros)
  const safeName = gameState.name || 'Viajante';
  const safeTitle = gameState.title || 'Viajante';
  const safeRace = gameState.race || 'Humano';
  const safeUsername = gameState.username || 'usuario';
  const safeLevel = (typeof gameState.level === 'number' ? gameState.level : parseInt(gameState.level) || 1);
  const safeXp = (typeof gameState.xp === 'number' ? gameState.xp : parseInt(gameState.xp) || 0);

  if (elements.previewName) elements.previewName.textContent = safeName;
  if (elements.previewTitle) elements.previewTitle.textContent = safeTitle;
  if (elements.previewRace) elements.previewRace.textContent = safeRace;
  if (elements.previewUsername) elements.previewUsername.textContent = `@${safeUsername}`;
  if (elements.level) elements.level.textContent = safeLevel;
  if (elements.orbLevel) elements.orbLevel.textContent = safeLevel;
  const rankInfo = getHeroRankInfo(safeLevel);
  const powerInfo = getHeroPowerInfo(gameState);
  if (elements.heroPowerBadge) {
    elements.heroPowerBadge.textContent = `${powerInfo.icon} Poder ${powerInfo.score.toLocaleString('pt-BR')}`;
    elements.heroPowerBadge.dataset.powerTier = powerInfo.tier;
    elements.heroPowerBadge.title = `Classe de Poder: ${powerInfo.label} • Clique para ver o cálculo`;
  }
  if (elements.heroPowerChip) {
    elements.heroPowerChip.textContent = `${powerInfo.icon} Poder: ${powerInfo.score.toLocaleString('pt-BR')} (${powerInfo.label})`;
    elements.heroPowerChip.dataset.powerTier = powerInfo.tier;
    elements.heroPowerChip.title = `Classe de Poder: ${powerInfo.label} • Clique para ver o cálculo`;
  }
  if (elements.heroRankBadge) {
    elements.heroRankBadge.textContent = `${rankInfo.icon} ${rankInfo.label}`;
    elements.heroRankBadge.dataset.rank = rankInfo.key;
    elements.heroRankBadge.title = `Patente baseada no seu nível atual (${safeLevel})`;
  }
  if (elements.heroRankChip) {
    elements.heroRankChip.textContent = `${rankInfo.icon} Patente: ${rankInfo.label}`;
    elements.heroRankChip.dataset.rank = rankInfo.key;
  }
  syncPlayerRoomPresenceProfile();
  renderHeroGlobalRankPanel({ rankInfo, powerInfo });
  const xpToNextLevel = XP_PER_LEVEL;
  if (elements.xp) elements.xp.textContent = `${gameState.xp} / ${xpToNextLevel}`;
  if (elements.skillPoints) elements.skillPoints.textContent = gameState.skillPoints;

  // Atualizar barra de progresso
  const xpPercent = (gameState.xp / xpToNextLevel) * 100;
  if (elements.xpProgress) elements.xpProgress.style.width = `${xpPercent}%`;
  
  // Atualizar segunda barra de XP (na seção de missões)
  const xpProgressMissions = document.getElementById('xpProgressMissions');
  if (xpProgressMissions) xpProgressMissions.style.width = `${xpPercent}%`;

  // Atualizar última reivindicação e streak
  if (gameState.lastClaim) {
    const date = new Date(gameState.lastClaim);
    if (elements.lastClaim) elements.lastClaim.textContent = date.toLocaleDateString('pt-BR');
  } else {
    if (elements.lastClaim) elements.lastClaim.textContent = 'Nunca';
  }
  if (elements.streakDisplay) elements.streakDisplay.textContent = gameState.streak || 0;
  
  // Atualizar cores
  const auraColor = gameState.auraColor || DEFAULT_AURA_COLOR;
  if (elements.orb) elements.orb.style.background = `radial-gradient(circle at 30% 20%, ${auraColor}40, transparent 45%)`;
  if (elements.ring) elements.ring.style.background = `conic-gradient(from 0deg, ${auraColor}, transparent, ${auraColor})`;
  if (elements.avatar) elements.avatar.style.borderColor = auraColor;
  
  // Atualizar cor das estrelas do universo
  if (typeof updateStarColor === 'function') {
    updateStarColor(auraColor);
  }

  // Atualizar Tema da Classe (Emoji e Imagem de Fundo)
  const theme = CLASS_THEMES[gameState.race] || CLASS_THEMES['default'];
  if (elements.avatar) elements.avatar.textContent = theme.emoji;
  
  if (elements.heroCardHeader) {
    elements.heroCardHeader.style.backgroundImage = `url('${theme.image}')`;
    elements.heroCardHeader.style.backgroundSize = 'cover';
    elements.heroCardHeader.style.backgroundPosition = 'center';
  }
  const heroTabEl = document.getElementById('tab-hero');
  if (heroTabEl) heroTabEl.dataset.rank = rankInfo.key;
  if (heroTabEl) heroTabEl.dataset.powerTier = powerInfo.tier;
  const heroCardEl = heroTabEl ? heroTabEl.querySelector('.hero-card-container') : null;
  if (heroCardEl) heroCardEl.dataset.rank = rankInfo.key;
  if (heroCardEl) heroCardEl.dataset.powerTier = powerInfo.tier;
 
  const isTabActive = (tabId) => {
    const el = document.getElementById(`tab-${tabId}`);
    return !!(el && el.classList.contains('active'));
  };
  const renderFinanceNow = isTabActive('finance');
  const renderWorkNow = isTabActive('dom');

  // Renderizações pesadas em lotes para evitar travar a tela inicial
  deferTask(() => {
    renderAttributes();
    renderAchievements();
    renderVisualBadges();
    renderInventory();
    renderShop();
    renderCinemaRoom();
    renderYoutubePremiumRoom();
    renderGratitudeJournal();
    renderArena();
  }, 120);

  deferTask(() => {
    const heroOrQuestActive = isTabActive('hero') || isTabActive('quests');
    if (!heroOrQuestActive) return;
    if (typeof renderAttributesChart === 'function') renderAttributesChart();
    if (typeof renderXpChart === 'function') renderXpChart();
  }, 180);

  deferTask(() => {
    renderDailyTasks();
    if (renderFinanceNow) {
      renderFinances();
      renderFinanceChart();
      renderFinancialGoal();
      renderSalaryMission();
      renderFinanceMonthlyChart();
      renderFinanceGroups();
      renderBills();
    }
  }, 320);

  deferTask(() => {
    if (renderWorkNow) renderWorkTab();
  }, 700);
  
  // Atualizar Badges nas Abas
  // 1. Hero: Pontos de habilidade disponíveis
  setTabBadge('hero', gameState.skillPoints > 0);

  // 2. Finance: Contas vencendo hoje
  const now = new Date();
  const localDate = new Date(now.getTime() - (now.getTimezoneOffset() * 60000));
  const today = localDate.toISOString().split('T')[0];
  const hasBillsDue = (gameState.bills || []).some(b => !b.paid && b.dueDate === today);
  setTabBadge('finance', hasBillsDue);

  // Atualizar UI de Relacionamento
  if (gameState.relationshipStart) {
    if (elements.relationshipSetup) elements.relationshipSetup.classList.add('hidden');
    if (elements.relationshipDisplay) elements.relationshipDisplay.classList.remove('hidden');

    if (elements.relationshipPhotoDisplay) {
      const hasRelationshipPhoto = typeof gameState.relationshipPhoto === 'string' && gameState.relationshipPhoto.length > 10;
      const fallbackZenPhoto = getZenBackgroundImages()[0] || '';
      const previewPhoto = hasRelationshipPhoto
        ? gameState.relationshipPhoto
        : (fallbackZenPhoto || 'logo.png');

      elements.relationshipPhotoDisplay.src = previewPhoto;
      elements.relationshipPhotoDisplay.style.display = 'block';
      elements.relationshipPhotoDisplay.classList.toggle('is-placeholder', !hasRelationshipPhoto && !fallbackZenPhoto);
      elements.relationshipPhotoDisplay.title = hasRelationshipPhoto
        ? 'Clique para alterar a foto'
        : 'Clique para adicionar a foto do casal';
    }
    
    updateRelationshipTimer();
  } else {
    if (elements.relationshipSetup) elements.relationshipSetup.classList.remove('hidden');
    if (elements.relationshipDisplay) elements.relationshipDisplay.classList.add('hidden');
  }

  updatePlayerRoomNofapUI({ sync: true, silent: true });
  purgeExpiredAdminNewsInbox({ persist: false, silent: true });
  updatePlayerRoomNewsInboxHint();
  updateZenPhotoVaultUI();
  deferTask(() => syncArenaPresence(), 850);
  const hasSavedWorkAddress = !!String(gameState?.job?.address || '').trim();
  if (gameState?.job?.name && (hasWorkLocationPoint() || hasSavedWorkAddress)) {
    startWorkLocationMonitor();
  } else {
    stopWorkLocationMonitor();
  }
}

