function getConfiguredAppShareUrl() {
  const isShareablePublicHttpUrl = (value) => {
    const safe = String(value || '').trim();
    if (!/^https?:\/\//i.test(safe)) return false;
    try {
      const parsed = new URL(safe);
      const host = String(parsed.hostname || '').trim().toLowerCase();
      if (!host) return false;
      if (host === 'localhost' || host === '127.0.0.1' || host === '::1') return false;
      if (host.endsWith('.local')) return false;
      return true;
    } catch (e) {
      return false;
    }
  };

  const fromConfig = String(window?.OracleConfig?.appShareUrl || '').trim();
  if (isShareablePublicHttpUrl(fromConfig)) return fromConfig;
  try {
    const fromStorage = String(localStorage.getItem(APP_SHARE_URL_STORAGE_KEY) || '').trim();
    if (isShareablePublicHttpUrl(fromStorage)) return fromStorage;
  } catch (e) {}

  const href = String(window.location.href || '').trim();
  if (isShareablePublicHttpUrl(href)) {
    return href.split('#')[0];
  }
  return '';
}

function getConfiguredAppUpdateUrl() {
  const isPublicHttpUrl = (value) => {
    const safe = String(value || '').trim();
    if (!/^https?:\/\//i.test(safe)) return false;
    try {
      const parsed = new URL(safe);
      const host = String(parsed.hostname || '').trim().toLowerCase();
      if (!host) return false;
      if (host === 'localhost' || host === '127.0.0.1' || host === '::1') return false;
      if (host.endsWith('.local')) return false;
      return true;
    } catch (e) {
      return false;
    }
  };

  const fromConfig = String(window?.OracleConfig?.appUpdateUrl || '').trim();
  if (isPublicHttpUrl(fromConfig)) return fromConfig;
  try {
    const fromStorage = String(localStorage.getItem(APP_UPDATE_URL_STORAGE_KEY) || '').trim();
    if (isPublicHttpUrl(fromStorage)) return fromStorage;
  } catch (e) {}
  const fallbackShareUrl = getConfiguredAppShareUrl();
  if (isPublicHttpUrl(fallbackShareUrl)) return fallbackShareUrl;
  return '';
}

function promptAndSaveAppUpdateUrl() {
  const current = getConfiguredAppUpdateUrl() || getConfiguredAppShareUrl();
  const input = prompt(
    'Cole o link público para atualização do app (página de download ou APK):',
    current || 'https://'
  );
  const safe = String(input || '').trim();
  if (!safe) return '';
  let parsed = null;
  try { parsed = new URL(safe); } catch (e) {}
  const host = String(parsed?.hostname || '').trim().toLowerCase();
  if (!/^https?:\/\//i.test(safe) || !host || host === 'localhost' || host === '127.0.0.1' || host === '::1' || host.endsWith('.local')) {
    showToast('⚠️ Use um link público real (https://...) para atualização.');
    return '';
  }
  try {
    localStorage.setItem(APP_UPDATE_URL_STORAGE_KEY, safe);
  } catch (e) {}
  return safe;
}

async function openAppUpdateUrl(url = '') {
  const safeUrl = String(url || '').trim();
  if (!safeUrl) return false;
  try {
    if (isNativeCapacitorPlatform()) {
      const Browser = window?.Capacitor?.Plugins?.Browser;
      if (Browser && typeof Browser.open === 'function') {
        await Browser.open({ url: safeUrl });
        return true;
      }
    }
  } catch (e) {
    console.warn('Falha ao abrir atualização com Browser nativo:', e);
  }
  try {
    window.open(safeUrl, '_blank', 'noopener,noreferrer');
    return true;
  } catch (e) {
    console.warn('Falha ao abrir link de atualização no navegador:', e);
    return false;
  }
}

function promptAndSaveAppShareUrl() {
  const current = getConfiguredAppShareUrl();
  const input = prompt(
    'Cole o link do seu site para download do app (https://...):',
    current || 'https://'
  );
  const safe = String(input || '').trim();
  if (!safe) return '';
  let parsed = null;
  try { parsed = new URL(safe); } catch (e) {}
  const host = String(parsed?.hostname || '').trim().toLowerCase();
  if (!/^https?:\/\//i.test(safe) || !host || host === 'localhost' || host === '127.0.0.1' || host === '::1' || host.endsWith('.local')) {
    showToast('⚠️ Use um link público real (https://...) e não localhost.');
    return '';
  }
  try {
    localStorage.setItem(APP_SHARE_URL_STORAGE_KEY, safe);
  } catch (e) {}
  return safe;
}

async function shareAppLink() {
  let url = getConfiguredAppShareUrl();
  if (!url) {
    url = promptAndSaveAppShareUrl();
  }
  if (!url) return false;

  const appName = String((window?.OracleConfig?.appName || 'Universo Real')).trim() || 'Universo Real';
  const text = `Baixe o app ${appName} aqui: ${url}`;

  if (navigator.share && window.isSecureContext) {
    try {
      await navigator.share({
        title: appName,
        text,
        url
      });
      showToast('✅ Link compartilhado!');
      return true;
    } catch (error) {
      if (String(error?.name || '').toLowerCase() === 'aborterror') return false;
    }
  }

  try {
    if (navigator.clipboard && window.isSecureContext) {
      await navigator.clipboard.writeText(url);
      showToast('📋 Link copiado!');
      return true;
    }
  } catch (error) {}

  prompt('Copie e compartilhe este link:', url);
  showToast('📤 Compartilhe esse link com os usuários.');
  return true;
}

// Função para verificar e aplicar atualizações
async function checkForUpdates() {
  const btn = document.getElementById('updateAppBtn');
  const mobileBtn = document.getElementById('mobileUpdateBtn');
  
  try {
    if (btn) { btn.disabled = true; btn.textContent = '⏳'; }
    if (mobileBtn) { mobileBtn.disabled = true; }
    
    if (isNativeCapacitorPlatform()) {
      let updateUrl = getConfiguredAppUpdateUrl();
      if (!updateUrl) updateUrl = promptAndSaveAppUpdateUrl();
      if (!updateUrl) {
        showToast('⚠️ Configure um link público de atualização do app.');
        return;
      }
      const opened = await openAppUpdateUrl(updateUrl);
      if (opened) {
        showToast('📲 Página de atualização aberta. Baixe e instale a nova versão.');
      } else {
        showToast('❌ Não consegui abrir o link de atualização.');
      }
      return;
    }

    showToast('🔍 Forçando atualização completa...');
    
    // 1. Limpa TODOS os caches
    if ('caches' in window) {
      const cacheNames = await caches.keys();
      console.log('🗑️ Removendo caches:', cacheNames);
      await Promise.all(cacheNames.map(name => caches.delete(name)));
    }
    
    // 2. Desregistra o Service Worker atual
    if ('serviceWorker' in navigator) {
      const registrations = await navigator.serviceWorker.getRegistrations();
      for (const registration of registrations) {
        console.log('🔄 Atualizando SW:', registration.scope);
        
        // Tenta atualizar
        await registration.update();
        
        // Se há um worker esperando, força ativação
        if (registration.waiting) {
          registration.waiting.postMessage({ type: 'SKIP_WAITING' });
        }
        
        // Se ainda não funcionou, desregistra completamente
        if (registration.active) {
          await registration.unregister();
          console.log('🗑️ SW desregistrado');
        }
      }
    }
    
    // 3. Limpa localStorage de versão (se houver)
    localStorage.removeItem('app_version');
    
    showToast('✅ Cache limpo! Recarregando em 2s...');
    
    // 4. Recarrega com cache-bust
    setTimeout(() => {
      const url = window.location.origin + window.location.pathname;
      window.location.replace(url + '?nocache=' + Date.now());
    }, 2000);
    
  } catch (error) {
    console.error('Erro ao atualizar:', error);
    showToast('⚠️ Erro! Tentando reload forçado...');
    setTimeout(() => {
      window.location.reload(true);
    }, 1500);
  }
}

