function handleWorkLocationActionFromDataset(action = '') {
  const safe = String(action || '').trim();
  if (!safe) return false;
  const now = Date.now();
  if (now - _workLocationLastActionAt < 550) return true;
  _workLocationLastActionAt = now;
  switch (safe) {
    case 'open-map-setup':
      openWorkLocationMap();
      return true;
    case 'use-current-setup':
    case 'use-current-dashboard':
      setWorkLocationFromCurrentPosition();
      return true;
    case 'open-map-dashboard':
      openWorkLocationMapFrom(getWorkAddress());
      return true;
    case 'check-nearby':
      checkWorkLocationProximity({ manual: true });
      return true;
    default:
      return false;
  }
}

