  recognition: null,
  isListening: false,
  isStarting: false,
  pendingNative: false,
  nativeStartTimeoutMs: 16000,
  sessionId: 0,
  lastToggleAt: 0,
  hasPermission: false,
  nativeMode: false,
  nativePluginAvailable: false,
  nativeUnavailableUntilReload: false,
  allowConversationMode: false,
  conversationMode: false, // Modo conversa contínua (telefone)
  voiceActivityTimer: null,
  typingTimer: null,
  typingToken: 0,
  lastNoResultAt: 0,
  keyboardLockActive: false,
  liveTranscript: '',
