// UI Methods
function ensureOracleInlineHandlers() {
  if (window.__oracleInlineHandlersBound) return;
  const messages = document.getElementById('chatMessages');
  if (!messages) return;
  window.__oracleInlineHandlersBound = true;
  messages.addEventListener('click', (e) => {
    const saveBtn = e.target.closest('.oracle-task-save');
    const cancelBtn = e.target.closest('.oracle-task-cancel');
    if (cancelBtn) {
      const wrap = cancelBtn.closest('.oracle-inline-card');
      if (wrap) wrap.remove();
      if (window.OracleChat) OracleChat.pendingAction = null;
      addSystemMessage('Ok, cancelado! 👍');
      return;
    }
    if (saveBtn) {
      const wrap = saveBtn.closest('.oracle-inline-card');
      if (!wrap) return;
      const titleEl = wrap.querySelector('input[name="taskTitle"]');
      const dateEl = wrap.querySelector('input[name="taskDate"]');
      const timeEl = wrap.querySelector('input[name="taskTime"]');
      const title = (titleEl && titleEl.value || '').trim();
      const today = new Date().toISOString().split('T')[0];
      const dueDate = (dateEl && dateEl.value || '').trim() || today;
      const dueTime = (timeEl && timeEl.value || '').trim() || null;
      if (!title) {
        addSystemMessage('⚠️ Digite o nome da tarefa.');
        return;
      }
      if (window.OracleChat) OracleChat.pendingAction = null;
      const data = { title, dueDate, dueTime, xpReward: OracleNLU.estimateTaskXP(title) };
      if (window.OracleChat && typeof OracleChat.createTaskWithDetails === 'function') {
        addBotMessage(OracleChat.createTaskWithDetails(data));
      } else if (typeof createTask === 'function') {
        addBotMessage(createTask(title));
      } else {
        addSystemMessage('❌ Não consegui criar a tarefa.');
      }
      wrap.remove();
    }
  });
}

function escapeHtmlSafe(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function sanitizeChatHtml(input, { allowInteractive = true } = {}) {
  const template = document.createElement('template');
  template.innerHTML = String(input ?? '');

  const allowedTags = new Set([
    'a', 'b', 'br', 'code', 'div', 'em', 'i', 'input', 'label', 'li', 'ol', 'option',
    'p', 'select', 'small', 'span', 'strong', 'textarea', 'ul', 'button'
  ]);
  const interactiveTags = new Set(['button', 'input', 'select', 'option', 'textarea', 'label']);
  const allowedGlobalAttrs = new Set([
    'aria-hidden', 'aria-label', 'class', 'cols', 'disabled', 'for', 'id', 'max',
    'maxlength', 'min', 'name', 'placeholder', 'readonly', 'role', 'rows', 'selected',
    'step', 'style', 'tabindex', 'title', 'type', 'value'
  ]);
  const allowedByTag = {
    a: new Set(['href', 'target', 'rel']),
    input: new Set(['checked', 'autocomplete', 'inputmode']),
    textarea: new Set(['autocomplete']),
    option: new Set(['value'])
  };

  const isSafeUrl = (rawUrl) => {
    const url = String(rawUrl || '').trim().toLowerCase();
    return (
      url === '' ||
      url.startsWith('#') ||
      url.startsWith('/') ||
      url.startsWith('http://') ||
      url.startsWith('https://') ||
      url.startsWith('mailto:') ||
      url.startsWith('tel:')
    );
  };

  const elements = [];
  const walker = document.createTreeWalker(template.content, NodeFilter.SHOW_ELEMENT);
  while (walker.nextNode()) elements.push(walker.currentNode);

  elements.forEach((el) => {
    const tag = el.tagName.toLowerCase();
    if (!allowedTags.has(tag) || (!allowInteractive && interactiveTags.has(tag))) {
      const textNode = document.createTextNode(el.textContent || '');
      el.replaceWith(textNode);
      return;
    }

    Array.from(el.attributes).forEach((attr) => {
      const name = attr.name.toLowerCase();
      if (name.startsWith('on')) {
        el.removeAttribute(attr.name);
        return;
      }
      if (name.startsWith('data-')) return;

      const isAllowed = allowedGlobalAttrs.has(name) || (allowedByTag[tag] && allowedByTag[tag].has(name));
      if (!isAllowed) {
        el.removeAttribute(attr.name);
        return;
      }

      if ((name === 'href' || name === 'src') && !isSafeUrl(attr.value)) {
        el.removeAttribute(attr.name);
        return;
      }

      if (tag === 'a' && name === 'target' && String(attr.value).toLowerCase() === '_blank') {
        const rel = new Set(String(el.getAttribute('rel') || '').split(/\s+/).filter(Boolean));
        rel.add('noopener');
        rel.add('noreferrer');
        el.setAttribute('rel', Array.from(rel).join(' '));
      }
    });
  });

  return template.innerHTML;
}

function addUserMessage(text) {
  const messages = document.getElementById('chatMessages');
  if (!messages) return;
  
  const div = document.createElement('div');
  div.className = 'chat-message user';
  div.textContent = text;
  messages.appendChild(div);
  messages.scrollTop = messages.scrollHeight;
  updateOracleModePill();
  ensureOracleInlineHandlers();
}

function buildImportantSpeechText(rawText) {
  const base = String(rawText || '')
    .replace(/<[^>]*>/g, ' ')
    .replace(/[\u{1F600}-\u{1F6FF}\u{2600}-\u{26FF}\u{2700}-\u{27BF}\u{1F900}-\u{1F9FF}\u{1F300}-\u{1F5FF}]/gu, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  if (!base) return '';
  if (base.length <= 200) return base;

  const normalized = base
    .replace(/[•▪●◆▶►]/g, '. ')
    .replace(/\s*\n+\s*/g, '. ')
    .replace(/\s+/g, ' ')
    .trim();
  const parts = normalized
    .split(/(?<=[.!?;:])\s+/)
    .map(part => part.trim())
    .filter(part => part.length > 2);
  if (!parts.length) return base.slice(0, 220);

  const importantPattern = /(importante|aten[cç][aã]o|agora|hoje|urgente|prioridade|passo|resumo|meta|saldo|total|prazo|venc|r\$|\d+)/i;
  const selected = [];
  selected.push(parts[0]);

  for (let i = 1; i < parts.length; i += 1) {
    const part = parts[i];
    const isImportant = importantPattern.test(part);
    const isShort = part.length <= 90;
    if (!isImportant && !isShort) continue;
    if (selected.includes(part)) continue;
    selected.push(part);
    if (selected.length >= 3) break;
  }

  if (selected.length < 2 && parts[1] && !selected.includes(parts[1])) {
    selected.push(parts[1]);
  }

  let output = selected.join(' ').replace(/\s+/g, ' ').trim();
  if (output.length > 240) {
    output = `${output.slice(0, 237).replace(/[,:;.!?]?\s+\S*$/, '')}...`;
  }
  return output || base.slice(0, 220);
}

function buildSpeechTitleText(rawText) {
  const base = String(rawText || '')
    .replace(/<[^>]*>/g, ' ')
    .replace(/[\u{1F600}-\u{1F6FF}\u{2600}-\u{26FF}\u{2700}-\u{27BF}\u{1F900}-\u{1F9FF}\u{1F300}-\u{1F5FF}]/gu, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  if (!base) return '';

  const intentPatterns = [
    /\b(tarefa\s+(?:criada|conclu[ií]da|atualizada|removida|deletada))\b/i,
    /\b(meta\s+(?:criada|conclu[ií]da|atualizada|removida|deletada))\b/i,
    /\b(gasto\s+(?:registrado|adicionado|corrigido|removido|deletado|renomeado))\b/i,
    /\b(entrada\s+(?:registrada|adicionada|removida|deletada|renomeada))\b/i,
    /\b(saldo\s+(?:atualizado|calculado))\b/i,
    /\b(erro)\b/i
  ];

  for (const pattern of intentPatterns) {
    const match = base.match(pattern);
    if (match && match[1]) {
      const phrase = String(match[1]).trim();
      if (phrase) {
        return phrase.charAt(0).toUpperCase() + phrase.slice(1);
      }
    }
  }

  let candidate = base
    .split(/[•|]/)[0]
    .split(/\s[—-]\s/)[0]
    .trim();

  if (candidate.includes(':')) {
    candidate = candidate.split(':')[0].trim();
  } else {
    candidate = candidate.split(/[.!?]/)[0].trim();
  }

  candidate = candidate
    .replace(/\s*\([^)]*\)\s*/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  if (!candidate) return buildImportantSpeechText(base);
  if (candidate.length > 70) {
    candidate = candidate.slice(0, 70).replace(/\s+\S*$/, '').trim();
  }
  return candidate || buildImportantSpeechText(base);
}

function addBotMessage(text, actions = null, options = {}) {
  // Aceita também um objeto { message, actions }
  if (text && typeof text === 'object') {
    const obj = text;
    actions = obj.actions || actions || null;
    text = obj.message || obj.text || '';
  }

  const messages = document.getElementById('chatMessages');
  if (!messages) return;

  const div = document.createElement('div');
  div.className = 'chat-message bot';
  div.innerHTML = sanitizeChatHtml(text, { allowInteractive: true });
  const spokenText = div.textContent || '';
  
  if (actions && actions.length > 0) {
    const actionsDiv = document.createElement('div');
    actionsDiv.className = 'oracle-action-btns';
    const hasCards = actions.some(action => {
      const variant = String(action?.variant || action?.style || '').toLowerCase();
      return variant === 'card' || !!action?.card || !!String(action?.description || '').trim();
    });
    if (hasCards) actionsDiv.classList.add('oracle-action-cards');
    
    actions.forEach(action => {
      const btn = document.createElement('button');
      btn.className = 'oracle-action-btn';
      const label = String(action?.text || action?.title || '').trim() || 'Selecionar';
      const description = String(action?.description || '').trim();
      const variant = String(action?.variant || action?.style || '').toLowerCase();
      const isCard = hasCards || variant === 'card' || !!action?.card;
      if (isCard) {
        btn.classList.add('oracle-action-card');
        const titleEl = document.createElement('span');
        titleEl.className = 'oracle-action-title';
        titleEl.textContent = label;
        btn.appendChild(titleEl);
        if (description) {
          const descEl = document.createElement('span');
          descEl.className = 'oracle-action-desc';
          descEl.textContent = description;
          btn.appendChild(descEl);
        }
      } else {
        btn.textContent = label;
        if (description) btn.title = description;
      }
      btn.addEventListener('click', () => {
        try {
          if (action && typeof action.action === 'function') {
            action.action();
          } else if (action && typeof action.command === 'string' && window.OracleChat && typeof OracleChat.processMessage === 'function') {
            Promise.resolve(OracleChat.processMessage(action.command)).catch(() => {});
          } else if (action && typeof action.response === 'string' && typeof addBotMessage === 'function') {
            addBotMessage(action.response);
          }
        } catch (_) {}
        actionsDiv.remove();
      });
      actionsDiv.appendChild(btn);
    });
    
    div.appendChild(actionsDiv);
  }
  
  messages.appendChild(div);
  messages.scrollTop = messages.scrollHeight;
  playSound('click');
  updateOracleModePill();
  ensureOracleInlineHandlers();
  
  // Se estiver em modo conversa (ou mensagem veio por voz), fala a resposta
  const forceSpeak = !!(options && options.forceSpeak);
  const alwaysSpeak = !!(
    window.OracleChat &&
    typeof OracleChat.isAlwaysSpeakEnabled === 'function' &&
    OracleChat.isAlwaysSpeakEnabled()
  );
  const shouldSpeak = !!(VoiceRecognition.conversationMode || forceSpeak || alwaysSpeak);
  if (shouldSpeak && OracleSpeech.enabled) {
    const cleanText = String(spokenText || '').replace(/\s+/g, ' ').trim();
    const speechText = buildSpeechTitleText(cleanText);
    if (speechText) {
      OracleSpeech.speak(speechText);
    }
  }
}

function addSystemMessage(text) {
  const messages = document.getElementById('chatMessages');
  if (!messages) return;
  
  const div = document.createElement('div');
  div.className = 'chat-message system';
  div.innerHTML = sanitizeChatHtml(text, { allowInteractive: false });
  messages.appendChild(div);
  messages.scrollTop = messages.scrollHeight;
  updateOracleModePill();
  ensureOracleInlineHandlers();
}

function updateOracleModePill() {
  const messages = document.getElementById('chatMessages');
  if (!messages) return;

  const profile = (typeof OracleMemory !== 'undefined' && OracleMemory.get) ? (OracleMemory.get().profile || {}) : {};
  const conversationActive = !!(profile.conversationMode || (window.VoiceRecognition && VoiceRecognition.conversationMode));
  const alwaysSpeakActive = !!(
    window.OracleChat &&
    typeof OracleChat.isAlwaysSpeakEnabled === 'function' &&
    OracleChat.isAlwaysSpeakEnabled()
  );
  const pending = !!(window.OracleChat && OracleChat.pendingAction);

  let pill = document.getElementById('oracleModePill');
  if (!conversationActive && !alwaysSpeakActive && !pending) {
    if (pill) pill.remove();
    return;
  }
  if (!pill) {
    pill = document.createElement('div');
    pill.id = 'oracleModePill';
    pill.className = 'oracle-mode-pill';
    messages.prepend(pill);
  }

  const parts = [];
  if (pending) parts.push('🧭 Ação em andamento');
  if (conversationActive) parts.push('📞 Modo conversa ativo');
  if (alwaysSpeakActive) parts.push('🔊 Resposta por voz ativa');

  pill.innerHTML = `
    <span class="oracle-mode-text">${parts.join(' • ')}</span>
    <button type="button" class="oracle-mode-stop">Parar</button>
  `;

  const stopBtn = pill.querySelector('.oracle-mode-stop');
  if (stopBtn) {
    stopBtn.onclick = () => {
      if (window.OracleChat) OracleChat.pendingAction = null;
      try {
        if (window.OracleChat && typeof OracleChat.stopConversationMode === 'function') {
          OracleChat.stopConversationMode();
        }
      } catch (e) {}
      try {
        if (window.VoiceRecognition && VoiceRecognition.conversationMode) {
          VoiceRecognition.conversationMode = false;
          if (typeof VoiceRecognition.stopListening === 'function') VoiceRecognition.stopListening({ reason: 'conversation_off' });
        }
      } catch (e) {}
      try {
        if (typeof OracleMemory !== 'undefined') {
          OracleMemory.setProfile('conversationMode', false);
          OracleMemory.setProfile('lastQuestion', null);
        }
      } catch (e) {}
      try {
        if (window.OracleChat && typeof OracleChat.setAlwaysSpeakEnabled === 'function') {
          OracleChat.setAlwaysSpeakEnabled(false);
        }
      } catch (e) {}
      addSystemMessage('⛔ Ação interrompida.');
      updateOracleModePill();
    };
  }
}

function showThinking() {
  const messages = document.getElementById('chatMessages');
  if (!messages) return;
  
  const div = document.createElement('div');
  div.className = 'chat-message thinking';
  div.id = 'oracleThinking';
  div.innerHTML = '<div class="thinking-dots"><span></span><span></span><span></span></div>';
  messages.appendChild(div);
  messages.scrollTop = messages.scrollHeight;
}

// Utilitários de debug para verificar bindings e elementos do Oráculo
function dumpOracleBindings() {
  const ids = ['addTaskBtn','addFinanceBtn','editProfileBtn','oracleScriptBtn','oracleSettingsBtn','chatBtn','oracleQuickActions','chatModal','chatInput','sendMessageBtn'];
  const results = {};
  console.group('Dump Oracle Bindings');
  ids.forEach(id => {
    const el = document.getElementById(id);
    console.log(id, !!el, el);
    results[id] = !!el;
  });
  console.groupEnd();
  return results;
}

function removeThinking() {
  const thinking = document.getElementById('oracleThinking');
  if (thinking) thinking.remove();
}

function ensureOracleReady() {
  try {
    if (!OracleChat || typeof OracleChat.init !== 'function') return false;
    if (!OracleChat._initialized) {
      OracleChat.init();
      OracleChat._initialized = true;
      console.log('✅ OracleChat.init executado com sucesso');
    }
    return true;
  } catch (err) {
    console.error('❌ Erro na inicialização do OracleChat:', err);
    const chatStatus = document.getElementById('oracleStatusText');
    if (chatStatus) chatStatus.textContent = 'Erro ao inicializar Assistente (ver console)';
    return false;
  }
}

function safeToggleOracleChat() {
  if (ensureOracleReady()) OracleChat.toggle();
}

function openOracleChatModal() {
  if (!ensureOracleReady()) return false;
  const modal = document.getElementById('chatModal');
  if (!modal) return false;

  if (!modal.classList.contains('active')) {
    OracleChat.toggle();
  } else {
    syncOracleModalVisibilityState();
    const input = document.getElementById('chatInput');
    if (input && shouldAutoFocus()) {
      setTimeout(() => {
        try { input.focus(); } catch (e) {}
      }, 50);
    }
  }
  return true;
}

