// SISTEMA DE ATUALIZAÇÃO DO PWA
// ===========================================

let swRegistration = null;
let updateAvailable = false;

// Força atualização do app (chamado pela notificação automática)
function forceAppUpdate() {
  if (isNativeCapacitorPlatform()) {
    checkForUpdates().catch((e) => {
      console.warn('Falha ao abrir atualização no app nativo:', e);
      showToast('❌ Não consegui abrir a atualização agora.');
    });
    return;
  }
  if (swRegistration && swRegistration.waiting) {
    // Envia mensagem para o SW waiting para ativar
    swRegistration.waiting.postMessage({ type: 'SKIP_WAITING' });
  } else {
    // Se não tem SW waiting, apenas recarrega
    window.location.reload(true);
  }
}

// Mostra notificação de atualização
function showUpdateNotification() {
  // Remove notificação antiga se existir
  const oldNotif = document.getElementById('updateNotification');
  if (oldNotif) oldNotif.remove();
  
  const notification = document.createElement('div');
  notification.id = 'updateNotification';
  notification.innerHTML = `
    <div style="
      position: fixed;
      bottom: 80px;
      left: 50%;
      transform: translateX(-50%);
      background: linear-gradient(135deg, #4ade80, #22c55e);
      color: #000;
      padding: 12px 20px;
      border-radius: 12px;
      box-shadow: 0 4px 20px rgba(0,0,0,0.3);
      z-index: 10001;
      display: flex;
      align-items: center;
      gap: 12px;
      font-weight: 600;
      animation: slide-up 0.3s ease;
    ">
      <span>🔄 Nova versão disponível!</span>
      <button onclick="forceAppUpdate()" style="
        background: #000;
        color: #fff;
        border: none;
        padding: 8px 16px;
        border-radius: 8px;
        cursor: pointer;
        font-weight: bold;
      ">Atualizar</button>
      <button onclick="this.parentElement.parentElement.remove()" style="
        background: transparent;
        border: none;
        color: #000;
        cursor: pointer;
        font-size: 18px;
      ">✕</button>
    </div>
  `;
  document.body.appendChild(notification);
}

