const NOTIFICATION_PREFS_KEY = 'ur_notification_prefs_v1';
const NOTIFICATION_BILLS_LAST_KEY = 'ur_notification_bills_last_v1';
const TASK_DUE_LOCAL_NOTIF_MAP_KEY = 'ur_task_due_local_notif_map_v1';
const BILLS_DUE_LOCAL_NOTIF_MAP_KEY = 'ur_bills_due_local_notif_map_v1';
const WORK_WEEK_PLAN_LOCAL_NOTIF_MAP_KEY = 'ur_work_week_plan_local_notif_map_v1';
const TASK_DUE_NOTIFICATION_INTERVAL_MS = 20000;
const LOCAL_NOTIFICATION_ACTION_TYPE_PREFIX = 'ur_action_';
const TASK_DUE_LOCAL_ID_BASE = 410000000;
const BILLS_DUE_LOCAL_ID_BASE = 420000000;
const WORK_WEEK_PLAN_LOCAL_ID_BASE = 430000000;
const WORK_TIMER_LOCAL_NOTIFICATION_ID = 440000001;
const WORK_TIMER_START_PROMPT_NOTIFICATION_ID = 440000002;
const WORK_TIMER_ACTION_START = 'work_start_yes';
const WORK_TIMER_ACTION_SKIP = 'work_start_no';
const LOCAL_NOTIFICATION_ID_SPAN = 9000000;
const DEFAULT_NOTIFICATION_PREFS = Object.freeze({
  workTimer: true,
  billsDue: true,
  tasksDue: true,
  roomMessages: true
});
let notificationPrefs = {
  workTimer: true,
  billsDue: true,
  tasksDue: true,
  roomMessages: true
};

function normalizeNotificationPrefs(raw) {
  const source = raw && typeof raw === 'object' ? raw : {};
  return {
    workTimer: source.workTimer !== false,
    billsDue: source.billsDue !== false,
    tasksDue: source.tasksDue !== false,
    roomMessages: source.roomMessages !== false
  };
}

function loadNotificationPrefs() {
  try {
    const parsed = JSON.parse(localStorage.getItem(NOTIFICATION_PREFS_KEY) || '{}');
    notificationPrefs = normalizeNotificationPrefs(parsed);
  } catch (e) {
    notificationPrefs = { ...DEFAULT_NOTIFICATION_PREFS };
  }
  return notificationPrefs;
}

function saveNotificationPrefs() {
  try {
    localStorage.setItem(NOTIFICATION_PREFS_KEY, JSON.stringify(notificationPrefs));
  } catch (e) {}
}

function isWorkTimerNotificationEnabled() {
  return !!notificationPrefs.workTimer;
}

function isBillsNotificationEnabled() {
  return !!notificationPrefs.billsDue;
}

function isTasksDueNotificationEnabled() {
  return !!notificationPrefs.tasksDue;
}

function isRoomMessageNotificationEnabled() {
  return !!notificationPrefs.roomMessages;
}

function getNotificationPermissionText() {
  const isNative = isNativeCapacitorPlatform();
  if (isNative) return 'permissão no Android';
  if (!('Notification' in window)) return 'indisponível';
  if (Notification.permission === 'granted') return 'permitida';
  if (Notification.permission === 'denied') return 'bloqueada';
  return 'não definida';
}

function updateNotificationSettingsUI(extraText = '') {
  const timerOn = isWorkTimerNotificationEnabled();
  const billsOn = isBillsNotificationEnabled();
  const tasksOn = isTasksDueNotificationEnabled();
  const roomOn = isRoomMessageNotificationEnabled();
  const timerText = `⏱️ Cronômetro: ${timerOn ? 'Ligado' : 'Desligado'}`;
  const billsText = `📅 Contas: ${billsOn ? 'Ligado' : 'Desligado'}`;

  if (elements.notifWorkToggleBtn) elements.notifWorkToggleBtn.textContent = timerText;
  if (elements.drawerNotifWorkToggleBtn) elements.drawerNotifWorkToggleBtn.textContent = timerText;
  if (elements.notifBillsToggleBtn) elements.notifBillsToggleBtn.textContent = billsText;
  if (elements.drawerNotifBillsToggleBtn) elements.drawerNotifBillsToggleBtn.textContent = billsText;

  if (elements.notifStatusLabel) {
    const base = `Permissão: ${getNotificationPermissionText()} • Cronômetro: ${timerOn ? 'ativo' : 'desativado'} • Contas: ${billsOn ? 'ativo' : 'desativado'} • Tarefas: ${tasksOn ? 'ativo' : 'desativado'} • Sala: ${roomOn ? 'ativo' : 'desativado'}`;
    elements.notifStatusLabel.textContent = extraText ? `${base} • ${extraText}` : base;
  }
  // Evita chamar UI do alarme antes do bloco de alarme finalizar bootstrap.
  if (globalThis.__urAlarmMusicReady === true) {
    try {
      updateAlarmMusicSettingsUI();
    } catch (e) {
      console.warn('Falha ao atualizar UI de música do alarme:', e);
    }
  }
}

async function requestNotificationPermissionFromSettings() {
  try {
    const granted = await ensureNotificationPermission();
    if (granted) {
      showToast('🔔 Permissão de notificação concedida.');
      updateNotificationSettingsUI('permissão concedida');
      try {
        await showNotificationViaSW('Notificações ativadas', {
          body: 'Você já pode receber avisos do app.',
          tag: 'notification-permission-granted',
          highPriority: true,
          renotify: true,
          forceNew: true,
          data: { type: 'permission-granted' }
        });
      } catch (e) {
        // Sem impacto: permissão já foi concedida.
      }
      return true;
    }
    showToast('⚠️ Permissão de notificação não concedida.');
    updateNotificationSettingsUI('permissão não concedida');
    return false;
  } catch (e) {
    showToast('❌ Não foi possível pedir permissão agora.');
    updateNotificationSettingsUI('erro ao pedir permissão');
    return false;
  }
}

function setNotificationPreference(prefKey, enabled, options = {}) {
  const key = String(prefKey || '').trim();
  const next = !!enabled;
  if (!Object.prototype.hasOwnProperty.call(notificationPrefs, key)) return;

  notificationPrefs[key] = next;
  saveNotificationPrefs();
  updateNotificationSettingsUI();

  if (key === 'workTimer') {
    const running = !!Number(localStorage.getItem('work_start_time') || 0);
    if (!next) {
      stopWorkNotification();
    } else if (running) {
      startWorkNotification(Number(localStorage.getItem('work_start_time') || Date.now()));
    }
  }

  if (key === 'tasksDue') {
    Promise.resolve(syncTaskDueLocalNotifications()).catch(() => {});
    Promise.resolve(syncWorkWeekPlanLocalNotifications()).catch(() => {});
  }

  if (options.announce !== false) {
    const pretty = (
      key === 'workTimer'
        ? 'cronômetro'
        : key === 'billsDue'
          ? 'contas'
          : key === 'tasksDue'
            ? 'tarefas'
            : key === 'roomMessages'
              ? 'sala'
              : key
    );
    showToast(`🔔 Notificações de ${pretty}: ${next ? 'ligado' : 'desligado'}`);
  }
}

function buildBillsNotificationSignature(bills = []) {
  const now = new Date();
  const localDate = new Date(now.getTime() - (now.getTimezoneOffset() * 60000));
  const dayKey = localDate.toISOString().split('T')[0];
  const ids = bills
    .map((b) => String(b?.id ?? `${b?.desc || ''}-${b?.dueDate || ''}-${b?.value || 0}`))
    .sort()
    .join(',');
  return `${dayKey}:${ids}`;
}

function shouldNotifyBillsOncePerSet(signature) {
  if (!signature) return false;
  try {
    const last = String(localStorage.getItem(NOTIFICATION_BILLS_LAST_KEY) || '');
    if (last === signature) return false;
    localStorage.setItem(NOTIFICATION_BILLS_LAST_KEY, signature);
    return true;
  } catch (e) {
    return true;
  }
}

function buildDeterministicLocalNotificationId(seed = '', base = TASK_DUE_LOCAL_ID_BASE) {
  const safe = String(seed || '').trim() || `${base}-${Date.now()}`;
  let hash = 17;
  for (let i = 0; i < safe.length; i += 1) {
    hash = ((hash * 31) + safe.charCodeAt(i)) % LOCAL_NOTIFICATION_ID_SPAN;
  }
  return Number(base) + Number(hash) + 1;
}

function loadLocalNotificationMap(storageKey = '') {
  const key = String(storageKey || '').trim();
  if (!key) return {};
  try {
    const parsed = JSON.parse(localStorage.getItem(key) || '{}');
    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) return {};
    const safe = {};
    Object.entries(parsed).forEach(([entryKey, entryValue]) => {
      const id = Number(entryValue);
      if (!Number.isFinite(id) || id <= 0) return;
      safe[String(entryKey)] = id;
    });
    return safe;
  } catch (e) {
    return {};
  }
}

function saveLocalNotificationMap(storageKey = '', map = {}) {
  const key = String(storageKey || '').trim();
  if (!key) return;
  try {
    localStorage.setItem(key, JSON.stringify(map && typeof map === 'object' ? map : {}));
  } catch (e) {}
}

async function hasNotificationPermissionWithoutPrompt() {
  if (isNativeCapacitorPlatform()) {
    try {
      const local = getCapacitorLocalNotificationsPlugin();
      if (local && typeof local.checkPermissions === 'function') {
        const checked = await local.checkPermissions();
        const granted = parseLocalNotificationPermissionGranted(checked);
        if (granted !== null) return granted;
      }
    } catch (e) {}
    return false;
  }
  if (!('Notification' in window)) return false;
  return Notification.permission === 'granted';
}

async function cancelLocalNotificationsByIds(notificationIds = []) {
  if (!isNativeCapacitorPlatform()) return false;
  const local = getCapacitorLocalNotificationsPlugin();
  if (!local) return false;
  const ids = (Array.isArray(notificationIds) ? notificationIds : [])
    .map((id) => Number(id))
    .filter((id) => Number.isFinite(id) && id > 0);
  if (!ids.length) return false;

  const payload = { notifications: ids.map((id) => ({ id })) };
  let changed = false;
  try {
    if (typeof local.cancel === 'function') {
      await local.cancel(payload);
      changed = true;
    }
  } catch (e) {}
  try {
    if (typeof local.removeDeliveredNotifications === 'function') {
      await local.removeDeliveredNotifications(payload);
      changed = true;
    }
  } catch (e) {}
  return changed;
}

function getPendingTasksForNativeSchedule() {
  const list = Array.isArray(gameState?.dailyTasks) ? gameState.dailyTasks : [];
  const now = Date.now();
  return list
    .filter((task) => task && !task.completed)
    .map((task) => {
      const dueTs = getTaskDueTimestamp(task);
      if (!Number.isFinite(dueTs) || dueTs <= now + 1500) return null;
      const taskId = String(task?.id || '').trim();
      if (!taskId) return null;
      const taskTitle = String(task?.text || 'Tarefa sem nome').trim() || 'Tarefa sem nome';
      const dueLabel = formatTaskDueLabel(task) || new Date(dueTs).toLocaleString('pt-BR');
      return {
        taskId,
        taskTitle,
        dueLabel,
        dueTs
      };
    })
    .filter(Boolean)
    .sort((a, b) => a.dueTs - b.dueTs)
    .slice(0, 120);
}

async function syncTaskDueLocalNotifications() {
  if (!isNativeCapacitorPlatform()) return false;
  const local = getCapacitorLocalNotificationsPlugin();
  if (!local || typeof local.schedule !== 'function') return false;

  const previousMap = loadLocalNotificationMap(TASK_DUE_LOCAL_NOTIF_MAP_KEY);
  if (!isTasksDueNotificationEnabled()) {
    const previousIds = Object.values(previousMap);
    if (previousIds.length) {
      await cancelLocalNotificationsByIds(previousIds);
    }
    saveLocalNotificationMap(TASK_DUE_LOCAL_NOTIF_MAP_KEY, {});
    return false;
  }

  const permissionGranted = await hasNotificationPermissionWithoutPrompt();
  if (!permissionGranted) return false;
  await ensureLocalNotificationsChannel();

  const pendingTasks = getPendingTasksForNativeSchedule();
  const nextMap = {};
  const scheduleItems = [];
  pendingTasks.forEach((entry) => {
    const notificationId = buildDeterministicLocalNotificationId(`task-${entry.taskId}`, TASK_DUE_LOCAL_ID_BASE);
    nextMap[entry.taskId] = notificationId;
    scheduleItems.push({
      id: notificationId,
      title: 'Tarefa no horário',
      body: `📝 ${entry.taskTitle}\n⏰ ${entry.dueLabel}`,
      channelId: 'ur_default',
      schedule: {
        at: new Date(entry.dueTs),
        allowWhileIdle: true
      },
      extra: {
        type: 'task-due',
        taskId: entry.taskId
      },
      summaryArgument: `task-due-${entry.taskId}`
    });
  });

  const removedIds = Object.entries(previousMap)
    .filter(([taskId]) => !Object.prototype.hasOwnProperty.call(nextMap, taskId))
    .map(([, id]) => Number(id))
    .filter((id) => Number.isFinite(id) && id > 0);
  if (removedIds.length) {
    await cancelLocalNotificationsByIds(removedIds);
  }

  if (scheduleItems.length) {
    try {
      await local.schedule({ notifications: scheduleItems });
    } catch (e) {
      console.warn('Falha ao sincronizar notificações de tarefas no Android:', e);
      return false;
    }
  }

  saveLocalNotificationMap(TASK_DUE_LOCAL_NOTIF_MAP_KEY, nextMap);
  return true;
}

function getPendingBillsForNativeSchedule() {
  const bills = Array.isArray(gameState?.bills) ? gameState.bills : [];
  const now = Date.now();
  return bills
    .filter((bill) => bill && !bill.paid)
    .map((bill) => {
      const billId = String(bill?.id || '').trim();
      if (!billId) return null;
      const explicitDueAt = Date.parse(String(bill?.dueAt || '').trim());
      let dueTs = Number.isFinite(explicitDueAt) ? explicitDueAt : NaN;
      if (!Number.isFinite(dueTs) || dueTs <= now + 1500) {
        const dueDate = String(bill?.dueDate || '').trim();
        if (!dueDate) return null;
        const parsed = Date.parse(`${dueDate}T09:00:00`);
        if (!Number.isFinite(parsed) || parsed <= now + 1500) return null;
        dueTs = parsed;
      }
      const desc = String(bill?.desc || 'Conta').trim() || 'Conta';
      const value = Number(bill?.value || 0);
      return {
        billId,
        desc,
        value,
        dueTs
      };
    })
    .filter(Boolean)
    .sort((a, b) => a.dueTs - b.dueTs)
    .slice(0, 120);
}

