function getPendingWorkWeekPlanForNativeSchedule() {
  const list = Array.isArray(gameState?.workWeekPlan) ? gameState.workWeekPlan : [];
  const plan = normalizeWorkWeekPlanEntries(list, WORK_WEEK_PLAN_MAX_ITEMS);
  const now = Date.now();

  return plan
    .filter((task) => {
      if (!task) return false;
      const progress = getWorkWeeklyProgressValue(task);
      return progress < 100 && String(task.status || '').trim().toLowerCase() !== 'completed';
    })
    .map((task) => {
      const taskId = String(task?.id || '').trim();
      if (!taskId) return null;

      const dueDateIso = getWorkWeeklyTaskDueDate(task);
      if (!dueDateIso) return null;

      // Regra do usuário: notificar sempre às 09:00 do dia planejado
      const dueTs = Date.parse(`${dueDateIso}T09:00:00`);
      if (!Number.isFinite(dueTs) || dueTs <= now + 1500) return null;

      const planned = String(task?.plannedText || 'Missão da pizzaria').trim() || 'Missão da pizzaria';
      const dayRef = parseIsoLocalDate(dueDateIso);
      const dueDateLabel = dayRef
        ? dayRef.toLocaleDateString('pt-BR', { weekday: 'short', day: '2-digit', month: '2-digit' })
        : dueDateIso;

      return {
        taskId,
        planned,
        dueTs,
        dueDateLabel
      };
    })
    .filter(Boolean)
    .sort((a, b) => a.dueTs - b.dueTs)
    .slice(0, 180);
}

