updateNotificationSettingsUI();
bindLocalNotificationActionListener();
startTaskDueNotificationWatcher();

function getNativeWorkTimerNotifier() {
  try {
    const ur = window.URNative;
    if (ur && (typeof ur.notifyNotification === 'function' || typeof ur.requestNotificationPermission === 'function')) {
      return {
        async requestPermission() {
          if (typeof ur.requestNotificationPermission === 'function') {
            const raw = ur.requestNotificationPermission();
            const parsed = parseNativeBooleanResult(raw);
            if (parsed === false) return { granted: false };
            if (parsed === true) return { granted: true };
            // Compatibilidade: alguns bridges só disparam prompt e não retornam estado.
            return { granted: true };
          }
          return { granted: true };
        },
        async notify(payload = {}) {
          if (typeof ur.notifyNotification !== 'function') return false;
          try {
            const raw = ur.notifyNotification(JSON.stringify(payload || {}));
            const parsed = parseNativeBooleanResult(raw);
            if (parsed === false) return false;
            if (parsed === true) return true;
            // Fire-and-forget em bridges legados.
            if (raw == null) return true;
            return !!raw;
          } catch (e) {
            console.warn('URNative.notifyNotification falhou:', e);
            return false;
          }
        }
      };
    }

    const cap = window.Capacitor;
    if (!cap || !isNativeCapacitorPlatform()) return null;
    if (cap.Plugins?.WorkTimerNotifier) return cap.Plugins.WorkTimerNotifier;
    if (!_nativeWorkTimerNotifier && typeof cap.registerPlugin === 'function') {
      _nativeWorkTimerNotifier = cap.registerPlugin('WorkTimerNotifier');
    }
    return _nativeWorkTimerNotifier || null;
  } catch (e) {
    return null;
  }
}

function parseNativeBooleanResult(value) {
  if (value === true) return true;
  if (value === false) return false;

  if (typeof value === 'number') {
    if (value === 0) return false;
    if (value === 1) return true;
    return null;
  }

  if (value && typeof value === 'object') {
    if (Object.prototype.hasOwnProperty.call(value, 'granted')) {
      return parseNativeBooleanResult(value.granted);
    }
    const status = String(
      value.status ||
      value.permission ||
      value.state ||
      value.result ||
      value.value ||
      value.display ||
      value.receive ||
      ''
    ).trim().toLowerCase();
    if (status) return parseNativeBooleanResult(status);
    return null;
  }

  const raw = String(value || '').trim();
  if (!raw) return null;

  if ((raw.startsWith('{') && raw.endsWith('}')) || (raw.startsWith('[') && raw.endsWith(']'))) {
    try {
      return parseNativeBooleanResult(JSON.parse(raw));
    } catch (e) {}
  }

  const lower = raw.toLowerCase();
  if (
    lower === '1' ||
    lower === 'true' ||
    lower === 'ok' ||
    lower === 'yes' ||
    lower === 'sim' ||
    lower === 'granted' ||
    lower === 'allowed' ||
    lower === 'authorized'
  ) {
    return true;
  }
  if (
    lower === '0' ||
    lower === 'false' ||
    lower === 'no' ||
    lower === 'nao' ||
    lower === 'não' ||
    lower === 'denied' ||
    lower === 'blocked' ||
    lower === 'rejected'
  ) {
    return false;
  }
  if (/(granted|allow|allowed|authorized|concedid|autorizad)/.test(lower)) return true;
  if (/(denied|deny|block|blocked|forbidden|rejected|negad|recusad)/.test(lower)) return false;
  if (/(prompt|default|unknown|ask|unset|pend)/.test(lower)) return null;
  return null;
}

function parseLocalNotificationPermissionGranted(result) {
  if (!result || typeof result !== 'object') return null;
  const direct = parseNativeBooleanResult(result);
  if (direct === true || direct === false) return direct;

  const display = String(result.display || result.receive || result.status || result.permission || '').trim().toLowerCase();
  if (display.includes('granted') || display.includes('allow') || display.includes('authorized')) return true;
  if (display.includes('denied') || display.includes('blocked') || display.includes('forbidden')) return false;
  if (display.includes('prompt') || display.includes('default')) return null;
  return null;
}

function getCapacitorLocalNotificationsPlugin() {
  try {
    if (!isNativeCapacitorPlatform()) return null;
    const cap = window.Capacitor;
    if (!cap) return null;
    if (cap.Plugins?.LocalNotifications) return cap.Plugins.LocalNotifications;
    if (!_nativeLocalNotificationsPlugin && typeof cap.registerPlugin === 'function') {
      _nativeLocalNotificationsPlugin = cap.registerPlugin('LocalNotifications');
    }
    return _nativeLocalNotificationsPlugin || null;
  } catch (e) {
    return null;
  }
}

function normalizeNotificationActionId(value = '') {
  return String(value || '')
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9_-]/g, '')
    .slice(0, 40);
}

function buildLocalNotificationActionTypeId(actions = []) {
  const normalized = (Array.isArray(actions) ? actions : [])
    .map((entry) => normalizeNotificationActionId(entry?.action || entry?.id || entry))
    .filter(Boolean);
  if (!normalized.length) return '';
  return `${LOCAL_NOTIFICATION_ACTION_TYPE_PREFIX}${normalized.join('_').slice(0, 50)}`;
}

async function ensureLocalNotificationActionType(actions = []) {
  const local = getCapacitorLocalNotificationsPlugin();
  if (!local || typeof local.registerActionTypes !== 'function') return '';

  const entries = (Array.isArray(actions) ? actions : [])
    .map((entry) => {
      const id = normalizeNotificationActionId(entry?.action || entry?.id || entry);
      if (!id) return null;
      const title = String(entry?.title || 'Abrir').trim().slice(0, 40) || 'Abrir';
      return {
        id,
        title,
        foreground: entry?.foreground !== false
      };
    })
    .filter(Boolean);
  if (!entries.length) return '';

  const typeId = buildLocalNotificationActionTypeId(entries);
  if (!typeId || _registeredLocalNotificationActionTypes.has(typeId)) return typeId;

  try {
    await local.registerActionTypes({
      types: [
        {
          id: typeId,
          actions: entries.map((entry) => ({
            id: entry.id,
            title: entry.title,
            foreground: entry.foreground !== false
          }))
        }
      ]
    });
    _registeredLocalNotificationActionTypes.add(typeId);
    return typeId;
  } catch (e) {
    console.warn('Falha ao registrar ações de notificação local:', e);
    return '';
  }
}

async function ensureLocalNotificationsChannel() {
  if (!isNativeCapacitorPlatform() || _nativeLocalNotificationsChannelReady) return;
  const local = getCapacitorLocalNotificationsPlugin();
  if (!local || typeof local.createChannel !== 'function') {
    _nativeLocalNotificationsChannelReady = true;
    return;
  }
  try {
    await local.createChannel({
      id: 'ur_default',
      name: 'Universo Real',
      description: 'Notificações do app Universo Real',
      importance: 5,
      visibility: 1,
      lights: true,
      vibration: true
    });
  } catch (e) {
    // canal pode já existir
  } finally {
    _nativeLocalNotificationsChannelReady = true;
  }
}

function startWorkTimerFromNotificationAction() {
  try {
    if (window.WorkTimer?.isRunning?.()) {
      return true;
    }
    if (window.WorkTimer && typeof window.WorkTimer.start === 'function') {
      window.WorkTimer.start();
      return true;
    }
    const startTime = Date.now();
    localStorage.setItem('work_start_time', String(startTime));
    window.dispatchEvent(new CustomEvent('workTimerStarted', { detail: { startTime } }));
    return true;
  } catch (e) {
    console.warn('Falha ao iniciar cronômetro via notificação:', e);
    return false;
  }
}

async function notifyWorkTimerStartPrompt(distanceMeters = NaN) {
  if (!isWorkTimerNotificationEnabled()) return false;
  const distanceLabel = Number.isFinite(distanceMeters)
    ? `Você está a ${formatDistanceMeters(distanceMeters)} do trabalho.`
    : 'Você chegou ao trabalho.';
  const body = `${distanceLabel} Deseja iniciar o ponto agora?`;
  return showNotificationViaSW('⏱️ Iniciar ponto de trabalho?', {
    body,
    tag: 'work-start-prompt',
    category: 'reminder',
    highPriority: true,
    silent: false,
    renotify: true,
    forceNew: true,
    notificationId: WORK_TIMER_START_PROMPT_NOTIFICATION_ID,
    data: {
      type: 'work-start-prompt',
      distanceMeters: Number.isFinite(distanceMeters) ? Math.round(distanceMeters) : null
    },
    actions: [
      { action: WORK_TIMER_ACTION_START, title: 'Iniciar', foreground: true },
      { action: WORK_TIMER_ACTION_SKIP, title: 'Agora não', foreground: false }
    ]
  });
}

function handleNotificationActionFromPayload(actionId = '', payload = {}) {
  const action = normalizeNotificationActionId(actionId);
  const data = payload && typeof payload === 'object' ? payload : {};

  if (!action) return false;

  if (action === WORK_TIMER_ACTION_START) {
    const started = startWorkTimerFromNotificationAction();
    Promise.resolve(cancelLocalNotificationsByIds([WORK_TIMER_START_PROMPT_NOTIFICATION_ID])).catch(() => {});
    if (started) {
      showToast('⏱️ Ponto iniciado pela notificação.');
    } else {
      showToast('❌ Não consegui iniciar o ponto pela notificação.');
    }
    return true;
  }

  if (action === WORK_TIMER_ACTION_SKIP) {
    try {
      const job = ensureWorkJobDefaults();
      if (job?.geoMonitor) {
        job.geoMonitor.lastPromptAt = new Date().toISOString();
        saveGame(true);
      }
    } catch (e) {}
    Promise.resolve(cancelLocalNotificationsByIds([WORK_TIMER_START_PROMPT_NOTIFICATION_ID])).catch(() => {});
    showToast('👌 Tudo bem. Não iniciei o ponto agora.');
    return true;
  }

  if (action === 'pause') {
    if (window.WorkTimer && typeof window.WorkTimer.stop === 'function') {
      window.WorkTimer.stop();
    }
    return true;
  }

  if (action === 'pay') {
    try {
      const financeTabBtn = document.querySelector('.tab-btn[data-tab="finance"]');
      if (financeTabBtn && typeof financeTabBtn.click === 'function') {
        financeTabBtn.click();
        return true;
      }
    } catch (e) {}
    try {
      window.location.href = './financeiro.html';
      return true;
    } catch (e) {}
    return false;
  }

  if (action === PLAYER_ROOM_BLESS_ACCEPT_ACTION) {
    const openPayload = {
      ...(data && typeof data === 'object' ? data : {}),
      target: 'player-room',
      type: 'room-message'
    };
    openPlayerRoomFromNotificationPayload(openPayload);
    triggerPlayerRoomBlessAcceptedEvent(openPayload);
    return true;
  }

  if (action === 'alarm_stop') {
    if (typeof handleOracleAlarmNotificationAction === 'function') {
      return !!handleOracleAlarmNotificationAction(action, data);
    }
    return false;
  }

  return false;
}

function bindLocalNotificationActionListener() {
  if (_localNotificationActionListenerBound || !isNativeCapacitorPlatform()) return;
  const local = getCapacitorLocalNotificationsPlugin();
  if (!local || typeof local.addListener !== 'function') return;

  _localNotificationActionListenerBound = true;
  try {
    local.addListener('localNotificationActionPerformed', (event) => {
      try {
        const actionId = normalizeNotificationActionId(
          event?.actionId ||
          event?.action?.id ||
          event?.action?.actionId ||
          event?.notificationAction?.actionId ||
          ''
        );
        const data = event?.notification?.extra && typeof event.notification.extra === 'object'
          ? event.notification.extra
          : {};
        handleNotificationActionFromPayload(actionId, data);
      } catch (e) {
        console.warn('Falha ao processar ação de notificação local:', e);
      }
    });
  } catch (e) {
    _localNotificationActionListenerBound = false;
    console.warn('Falha ao registrar listener de ação da notificação local:', e);
  }
}

async function ensureNotificationPermission() {
  bindLocalNotificationActionListener();
  if (isNativeCapacitorPlatform()) {
    let nativeDenied = false;
    try {
      const nativeNotifier = getNativeWorkTimerNotifier();
      if (nativeNotifier && typeof nativeNotifier.requestPermission === 'function') {
        const out = await nativeNotifier.requestPermission();
        const nativeGranted = out?.granted !== false;
        if (nativeGranted) return true;
        nativeDenied = true;
      }
      if (nativeNotifier && !nativeDenied) return true;
    } catch (e) {
      // tenta fallback web abaixo
    }

    try {
      const local = getCapacitorLocalNotificationsPlugin();
      if (local) {
        if (typeof local.checkPermissions === 'function') {
          const checked = await local.checkPermissions();
          const checkGranted = parseLocalNotificationPermissionGranted(checked);
          if (checkGranted === true) {
            await ensureLocalNotificationsChannel();
            return true;
          }
        }
        if (typeof local.requestPermissions === 'function') {
          const requested = await local.requestPermissions();
          const requestGranted = parseLocalNotificationPermissionGranted(requested);
          if (requestGranted === true) {
            await ensureLocalNotificationsChannel();
            return true;
          }
          if (requestGranted === false) {
            if (nativeDenied) return false;
          }
        }
      }
    } catch (e) {
      // segue fallback web abaixo
    }
  }
  if (!('Notification' in window)) return false;
  if (Notification.permission === 'granted') return true;
  if (Notification.permission === 'denied') return false;
  try {
    const p = await Notification.requestPermission();
    return p === 'granted';
  } catch (e) { return false; }
}

async function showNotificationViaNative(title, options = {}) {
  try {
    bindLocalNotificationActionListener();
    const nativeNotifier = getNativeWorkTimerNotifier();
    const permissionOk = await ensureNotificationPermission();
    if (!permissionOk) return false;

    const hasExplicitId = Number.isFinite(Number(options.notificationId)) && Number(options.notificationId) > 0;
    const wantsRenotify = options.renotify === true;
    const forceNew = options.forceNew === true || (!hasExplicitId && wantsRenotify && !options.ongoing);
    const safeTitle = String(title || 'Universo Real').trim() || 'Universo Real';
    const safeBody = String(options.body || '').trim();
    const safeTag = String(options.tag || 'ur-alert').trim() || 'ur-alert';
    const safeCategory = String(options.category || (options.ongoing ? 'service' : 'reminder'));
    const safeActions = (Array.isArray(options.actions) ? options.actions : [])
      .map((entry) => {
        const action = normalizeNotificationActionId(entry?.action || entry?.id || entry);
        if (!action) return null;
        const title = String(entry?.title || '').trim().slice(0, 40) || 'Abrir';
        return { action, title };
      })
      .filter(Boolean);

    if (nativeNotifier && typeof nativeNotifier.notify === 'function') {
      const payload = {
        title: safeTitle,
        body: safeBody,
        tag: safeTag,
        ongoing: !!options.ongoing,
        silent: options.silent === true,
        highPriority: options.highPriority !== false,
        category: safeCategory,
        forceNew
      };
      if (options.data && typeof options.data === 'object') {
        payload.data = options.data;
      }
      if (options.openTarget != null) {
        payload.openTarget = String(options.openTarget || '').trim();
      }
      if (safeActions.length) {
        payload.actions = safeActions.map((entry) => ({
          action: entry.action,
          id: entry.action,
          title: entry.title
        }));
      }
      if (hasExplicitId) {
        payload.notificationId = Number(options.notificationId);
      }
      let nativeResult = false;
      try {
        nativeResult = await nativeNotifier.notify(payload);
      } catch (e) {
        console.warn('Notificação nativa WorkTimerNotifier indisponível, usando fallback local:', e);
        nativeResult = false;
      }
      if (nativeResult !== false) {
        return true;
      }
      console.warn('Notificação nativa retornou falha, tentando fallback local.');
    }

    const local = getCapacitorLocalNotificationsPlugin();
    if (local && typeof local.schedule === 'function') {
      await ensureLocalNotificationsChannel();
      const generatedId = Number((Date.now() % 2147482000) + Math.floor(Math.random() * 1000));
      const notificationId = hasExplicitId ? Number(options.notificationId) : generatedId;
      const actionTypeId = safeActions.length ? await ensureLocalNotificationActionType(safeActions) : '';
      await local.schedule({
        notifications: [
          {
            id: notificationId,
            title: safeTitle,
            body: safeBody,
            channelId: 'ur_default',
            ongoing: !!options.ongoing,
            autoCancel: options.ongoing ? false : true,
            summaryArgument: safeTag,
            extra: options.data && typeof options.data === 'object' ? options.data : {},
            actionTypeId: actionTypeId || undefined
          }
        ]
      });
      return true;
    }
  } catch (e) {
    console.warn('Falha ao enviar notificação nativa de alerta:', e);
  }
  return false;
}

async function showNotificationViaSW(title, options = {}) {
  if (isNativeCapacitorPlatform()) {
    const nativeSent = await showNotificationViaNative(title, options);
    if (nativeSent) return true;
  }
  try {
    if (navigator.serviceWorker && navigator.serviceWorker.getRegistration) {
      const reg = await navigator.serviceWorker.getRegistration();
      if (reg && reg.showNotification) {
        await reg.showNotification(title, options);
        return true;
      }
    }
  } catch (e) {}
  // Fallback direto
  try {
    const n = new Notification(title, options);
    return !!n;
  } catch (e) { return false; }
}

function formatElapsed(ms) {
  const hrs = Math.floor(ms / 3600000);
  const mins = Math.floor((ms % 3600000) / 60000);
  const secs = Math.floor((ms % 60000) / 1000);
  return `${String(hrs).padStart(2,'0')}:${String(mins).padStart(2,'0')}:${String(secs).padStart(2,'0')}`;
}

async function startWorkNotificationFallbackLoop() {
  if (!await ensureNotificationPermission()) {
    return false;
  }
  await stopWorkNotification();
  _lastNotificationType = 'work-timer';
  const native = isNativeCapacitorPlatform();

  const sendTick = async () => {
    const elapsed = window.WorkTimer?.getElapsedTime?.() || 0;
    const text = native
      ? `Cronômetro: ${formatElapsed(elapsed)} • Notificação fixa ativa`
      : `Cronômetro: ${formatElapsed(elapsed)}`;
    await showNotificationViaSW('Tempo de Trabalho', {
      body: text,
      tag: 'work-timer',
      renotify: false,
      silent: true,
      ongoing: native,
      notificationId: native ? WORK_TIMER_LOCAL_NOTIFICATION_ID : undefined,
      data: { type: 'work-timer' },
      actions: [{ action: 'pause', title: 'Pausar' }]
    });
  };

  await sendTick();
  if (native) {
    // No Android sem plugin nativo de cronômetro, mantemos 1 notificação fixa
    // para evitar spam de uma notificação nova por segundo.
    return true;
  }

  _workNotifInterval = setInterval(() => {
    sendTick().catch(() => {});
  }, 1000);

  return true;
}

async function startWorkNotification(startTimeMs) {
  if (!isWorkTimerNotificationEnabled()) return;
  const isNative = isNativeCapacitorPlatform();
  const nativeNotifier = getNativeWorkTimerNotifier();
  const parsedStart = Number(startTimeMs || localStorage.getItem('work_start_time') || Date.now());
  const startTime = Number.isFinite(parsedStart) && parsedStart > 0 ? parsedStart : Date.now();
  if (nativeNotifier && typeof nativeNotifier.start === 'function') {
    if (_nativeWorkNotifActive && Math.abs(_nativeWorkNotifStartAt - startTime) < 1200) {
      return;
    }
    if (_nativeWorkNotifStartInFlight) {
      return;
    }
    _nativeWorkNotifStartInFlight = true;
    try {
      if (typeof nativeNotifier.requestPermission === 'function') {
        await nativeNotifier.requestPermission();
      }
      await nativeNotifier.start({ startTime });
      _nativeWorkNotifActive = true;
      _nativeWorkNotifStartAt = startTime;
      _nativeWorkNotifLookupRetries = 0;
      return;
    } catch (e) {
      console.warn('Falha ao iniciar notificação nativa do timer:', e);
      _nativeWorkNotifActive = false;
      if (isNative) {
        const msg = String(e?.message || '');
        if (/not implemented|unimplemented|plugin/i.test(msg) && _nativeWorkNotifLookupRetries < 4) {
          _nativeWorkNotifLookupRetries++;
          setTimeout(() => startWorkNotification(startTime), 400 * _nativeWorkNotifLookupRetries);
          return;
        }
        const fallbackOk = await startWorkNotificationFallbackLoop();
        if (!fallbackOk) {
          showToast('⚠️ Não consegui ativar a notificação do cronômetro. Verifique a permissão de notificações do app.');
        }
        return;
      }
    } finally {
      _nativeWorkNotifStartInFlight = false;
    }
  }
  if (isNative) {
    const fallbackOk = await startWorkNotificationFallbackLoop();
    if (!fallbackOk) {
      console.warn('Plugin nativo WorkTimerNotifier indisponível e fallback de notificação falhou.');
      showToast('⚠️ Não consegui ativar a notificação do cronômetro. Verifique a permissão de notificações do app.');
    }
    return;
  }
  await startWorkNotificationFallbackLoop();
}

async function stopWorkNotification() {
  const nativeNotifier = getNativeWorkTimerNotifier();
  if (nativeNotifier && typeof nativeNotifier.stop === 'function') {
    try {
      await nativeNotifier.stop();
    } catch (e) {
      console.warn('Falha ao parar notificação nativa do timer:', e);
    }
  }
  _nativeWorkNotifActive = false;
  _nativeWorkNotifStartAt = 0;
  _nativeWorkNotifStartInFlight = false;
  _nativeWorkNotifLookupRetries = 0;
  if (_workNotifInterval) { clearInterval(_workNotifInterval); _workNotifInterval = null; }
  try {
    if (navigator.serviceWorker && navigator.serviceWorker.getRegistration) {
      const reg = await navigator.serviceWorker.getRegistration();
      if (reg && reg.getNotifications) {
        const notifs = await reg.getNotifications({ tag: 'work-timer' });
        notifs.forEach(n => n.close());
      }
    }
  } catch (e) {}
  try {
    await cancelLocalNotificationsByIds([
      WORK_TIMER_LOCAL_NOTIFICATION_ID,
      WORK_TIMER_START_PROMPT_NOTIFICATION_ID
    ]);
  } catch (e) {}
  // also try to clear direct Notification objects if any (best-effort)
}

// Hook into WorkTimer events
window.addEventListener('workTimerStarted', (e) => {
  const startTime = e?.detail?.startTime || localStorage.getItem('work_start_time');
  startWorkNotification(startTime);
  syncNativeWorkTimerStateWithMonitor({ running: true, startTime: Number(startTime || 0) }).catch(() => {});
});

window.addEventListener('workTimerStopped', (e) => {
  stopWorkNotification();
  syncNativeWorkTimerStateWithMonitor({ running: false, startTime: 0 }).catch(() => {});
});

try {
  const persistedStart = Number(localStorage.getItem('work_start_time') || 0);
  if (persistedStart > 0) {
    startWorkNotification(persistedStart);
    syncNativeWorkTimerStateWithMonitor({ running: true, startTime: persistedStart }).catch(() => {});
  } else {
    syncNativeWorkTimerStateWithMonitor({ running: false, startTime: 0 }).catch(() => {});
  }
} catch (e) {}

// Notificar contas vencendo hoje com ação para abrir financeiro
async function notifyBillsDue(bills) {
  if (!bills || bills.length === 0) return;
  if (!isBillsNotificationEnabled()) return;
  const signature = buildBillsNotificationSignature(bills);
  if (!shouldNotifyBillsOncePerSet(signature)) return;
  if (!await ensureNotificationPermission()) return;
  const total = bills.reduce((s,b) => s + (b.value || 0), 0);
  await showNotificationViaSW('Contas vencendo hoje', {
    body: `Você tem ${bills.length} conta(s) vencendo hoje. Total: R$ ${total.toLocaleString('pt-BR')}`,
    tag: 'bills-due',
    category: 'reminder',
    highPriority: true,
    silent: false,
    renotify: true,
    data: { type: 'bills-due' },
    actions: [ { action: 'pay', title: 'Pagar agora' } ]
  });
}

// Integrate with existing checkBillsDueToday (override the function to also notify)
const _orig_checkBillsDueToday = typeof checkBillsDueToday === 'function' ? checkBillsDueToday : null;
function checkBillsDueTodayWithNotif() {
  if (typeof _orig_checkBillsDueToday === 'function') _orig_checkBillsDueToday();
  // compute bills and notify
  try {
    if (!gameState || !gameState.bills) return;
    const now = new Date();
    const localDate = new Date(now.getTime() - (now.getTimezoneOffset() * 60000));
    const today = localDate.toISOString().split('T')[0];
    const dueBills = gameState.bills.filter(b => !b.paid && b.dueDate === today);
    if (dueBills.length > 0) notifyBillsDue(dueBills);
  } catch (e) { console.warn('checkBillsDueTodayWithNotif failed', e); }
}
// Replace references
try { if (typeof window !== 'undefined') window.checkBillsDueToday = checkBillsDueTodayWithNotif; } catch(e){}

async function notifyTaskDue(task) {
  if (!task || task.completed) return false;
  if (!isTasksDueNotificationEnabled()) return false;

  const dueLabel = formatTaskDueLabel(task) || 'agora';
  const taskTitle = String(task.text || 'Tarefa sem nome').trim() || 'Tarefa sem nome';
  const taskId = String(task.id || `${taskTitle}-${dueLabel}`);
  const body = `📝 ${taskTitle}\n⏰ ${dueLabel}`;

  if (!await ensureNotificationPermission()) return false;
  return showNotificationViaSW('Tarefa no horário', {
    body,
    tag: `task-due-${taskId}`,
    category: 'reminder',
    highPriority: true,
    silent: false,
    renotify: true,
    data: { type: 'task-due', taskId: task.id || null }
  });
}

async function checkDueTasksAndNotify() {
  if (!gameState || !Array.isArray(gameState.dailyTasks) || gameState.dailyTasks.length === 0) return;

  const now = Date.now();
  let changed = false;
  const pending = gameState.dailyTasks.filter((task) => task && !task.completed);

  for (const task of pending) {
    const dueTs = getTaskDueTimestamp(task);
    if (!Number.isFinite(dueTs) || dueTs > now) continue;
    if (task.notifiedAt && Number.isFinite(Date.parse(task.notifiedAt))) continue;

    try {
      const sent = await notifyTaskDue(task);
      if (sent) {
        task.notifiedAt = new Date().toISOString();
        changed = true;
      }
    } catch (e) {
      console.warn('Falha ao notificar tarefa no horário:', e);
    }
  }

  if (changed) {
    gameState.tasksLastChangedAt = new Date().toISOString();
    saveGame(true);
    if (typeof renderDailyTasks === 'function') renderDailyTasks();
  }
}

function startTaskDueNotificationWatcher() {
  if (_taskDueNotifInterval) return;
  const run = () => {
    Promise.resolve(syncTaskDueLocalNotifications()).catch((e) => {
      console.warn('Falha na sincronização de notificações de tarefas (nativo):', e);
    });
    Promise.resolve(syncBillsDueLocalNotifications()).catch((e) => {
      console.warn('Falha na sincronização de notificações de contas (nativo):', e);
    });
    Promise.resolve(syncWorkWeekPlanLocalNotifications()).catch((e) => {
      console.warn('Falha na sincronização de notificações do planejamento (nativo):', e);
    });
    Promise.resolve(checkDueTasksAndNotify()).catch((e) => {
      console.warn('Falha na verificação de tarefas com horário:', e);
    });
  };
  _taskDueNotifInterval = setInterval(run, TASK_DUE_NOTIFICATION_INTERVAL_MS);
  setTimeout(run, 2000);
}

/* ---------------------------
   Alarmes do Oraculo (nativo/web)
   --------------------------- */
const ORACLE_ALARM_STORAGE_KEY = 'ur_oracle_alarms_v1';
const ORACLE_ALARM_MAX_TIMEOUT_MS = 2147480000;
const ORACLE_ALARM_DEFAULT_LABEL = 'Alarme do Assistente';
const ORACLE_ALARM_ACTION_STOP = 'alarm_stop';
const ORACLE_ALARM_RING_CYCLE_MS = 2200;
const ORACLE_ALARM_RING_AUTO_STOP_MS = 180000;
const ORACLE_ALARM_INLINE_BANNER_ID = 'oracleAlarmInlineBanner';
const ORACLE_ALARM_CUSTOM_AUDIO_DATA_KEY = 'ur_oracle_alarm_custom_audio_data_v1';
const ORACLE_ALARM_CUSTOM_AUDIO_META_KEY = 'ur_oracle_alarm_custom_audio_meta_v1';
const oracleAlarmTimers = new Map();
let oracleAlarmRingTimer = null;
let oracleAlarmRingAutoStopTimer = null;
let oracleAlarmRingingRecordId = '';
var oracleAlarmCustomAudioDataUrl = '';
var oracleAlarmCustomAudioName = '';
var oracleAlarmCustomAudioPersisted = false;
var oracleAlarmCustomAudioElement = null;

function buildOracleAlarmNotificationId(recordId = '') {
  const safe = String(recordId || '').trim();
  if (!safe) {
    return Number((Date.now() % 2147480000) + 101);
  }
  let hash = 7;
  for (let i = 0; i < safe.length; i += 1) {
    hash = ((hash * 31) + safe.charCodeAt(i)) % 2147480000;
  }
  const normalized = Number(hash) + 101;
  return normalized > 0 ? normalized : Number((Date.now() % 2147480000) + 303);
}

async function scheduleOracleAlarmLocalNotification(record = {}) {
  if (!isNativeCapacitorPlatform()) return false;

  const local = getCapacitorLocalNotificationsPlugin();
  if (!local || typeof local.schedule !== 'function') return false;

  const fireAt = Number(record?.fireAt || 0);
  if (!Number.isFinite(fireAt) || fireAt <= Date.now() + 500) return false;

  const notificationId = Number(record?.notificationId || buildOracleAlarmNotificationId(record?.id));
  const label = String(record?.label || ORACLE_ALARM_DEFAULT_LABEL).trim() || ORACLE_ALARM_DEFAULT_LABEL;
  const alarmId = String(record?.id || '').trim() || null;
  const permissionOk = await ensureNotificationPermission();
  if (!permissionOk) return false;

  try {
    await ensureLocalNotificationsChannel();
  } catch (e) {}

  let actionTypeId = '';
  try {
    actionTypeId = await ensureLocalNotificationActionType([
      { action: ORACLE_ALARM_ACTION_STOP, title: 'Desativar' }
    ]);
  } catch (e) {}

  await local.schedule({
    notifications: [
      {
        id: notificationId,
        title: '⏰ Alarme Universo Real',
        body: label,
        channelId: 'ur_default',
        schedule: {
          at: new Date(fireAt),
          allowWhileIdle: true
        },
        extra: {
          type: 'oracle-alarm',
          target: 'oracle-alarm',
          alarmId
        },
        actionTypeId: actionTypeId || undefined
      }
    ]
  });

  return true;
}

async function cancelOracleAlarmLocalNotificationsByIds(notificationIds = []) {
  if (!isNativeCapacitorPlatform()) return false;
  const local = getCapacitorLocalNotificationsPlugin();
  if (!local) return false;

  const ids = (Array.isArray(notificationIds) ? notificationIds : [])
    .map((id) => Number(id))
    .filter((id) => Number.isFinite(id) && id > 0);
  if (!ids.length) return false;

  const payload = { notifications: ids.map((id) => ({ id })) };
  let changed = false;
  try {
    if (typeof local.cancel === 'function') {
      await local.cancel(payload);
      changed = true;
    }
  } catch (e) {}
  try {
    if (typeof local.removeDeliveredNotifications === 'function') {
      await local.removeDeliveredNotifications(payload);
      changed = true;
    }
  } catch (e) {}
  return changed;
}

function playOracleAlarmMusicBurst() {
  const ctx = getAudioContext();
  if (!ctx) {
    playSound('achievement');
    return;
  }

  try {
    if (ctx.state === 'suspended') {
      Promise.resolve(ctx.resume()).catch(() => {});
    }
  } catch (e) {}

  const now = ctx.currentTime;
  const notes = [523.25, 659.25, 783.99, 1046.5, 783.99, 659.25];
  notes.forEach((freq, idx) => {
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.type = idx % 2 === 0 ? 'triangle' : 'sine';
    osc.frequency.setValueAtTime(freq, now + idx * 0.16);
    gain.gain.setValueAtTime(0.0001, now + idx * 0.16);
    gain.gain.exponentialRampToValueAtTime(0.12, now + idx * 0.16 + 0.03);
    gain.gain.exponentialRampToValueAtTime(0.0001, now + idx * 0.16 + 0.22);

    osc.start(now + idx * 0.16);
    osc.stop(now + idx * 0.16 + 0.24);
  });
}

async function closeOracleAlarmNotifications() {
  try {
    if (navigator.serviceWorker && navigator.serviceWorker.getRegistration) {
      const reg = await navigator.serviceWorker.getRegistration();
      if (reg && typeof reg.getNotifications === 'function') {
        const list = await reg.getNotifications();
        list
          .filter((n) => String(n?.tag || '').startsWith('ur-oracle-alarm-'))
          .forEach((n) => {
            try { n.close(); } catch (e) {}
          });
      }
    }
  } catch (e) {}

  try {
    const local = getCapacitorLocalNotificationsPlugin();
    if (local && typeof local.getDeliveredNotifications === 'function') {
      const delivered = await local.getDeliveredNotifications();
      const notifications = Array.isArray(delivered?.notifications) ? delivered.notifications : [];
      const ids = notifications
        .filter((item) => {
          const tag = String(item?.summaryArgument || item?.threadIdentifier || '');
          const type = String(item?.extra?.type || '').toLowerCase();
          return tag.startsWith('ur-oracle-alarm-') || type === 'oracle-alarm';
        })
        .map((item) => Number(item?.id))
        .filter((id) => Number.isFinite(id) && id > 0);
      if (ids.length && typeof local.removeDeliveredNotifications === 'function') {
        await local.removeDeliveredNotifications({ notifications: ids.map((id) => ({ id })) });
      }
      if (ids.length && typeof local.cancel === 'function') {
        await local.cancel({ notifications: ids.map((id) => ({ id })) });
      }
    }
  } catch (e) {}
}

function startOracleAlarmMusic(record = {}) {
  stopOracleAlarmMusic({ silent: true, closeNotification: false });
  oracleAlarmRingingRecordId = String(record?.id || '').trim();

  const customPlaying = playOracleAlarmCustomTrack();
  if (!customPlaying) {
    startOracleAlarmFallbackBurstLoop();
  }

  oracleAlarmRingAutoStopTimer = setTimeout(() => {
    stopOracleAlarmMusic({ silent: true, closeNotification: true });
    showToast('🔕 Alarme encerrado automaticamente.');
  }, ORACLE_ALARM_RING_AUTO_STOP_MS);
}

function removeOracleAlarmInlineBanner() {
  try {
    const el = document.getElementById(ORACLE_ALARM_INLINE_BANNER_ID);
    if (el && typeof el.remove === 'function') {
      el.remove();
    } else if (el && el.parentNode) {
      el.parentNode.removeChild(el);
    }
  } catch (e) {}
}

function showOracleAlarmInlineBanner(record = {}) {
  const label = String(record?.label || ORACLE_ALARM_DEFAULT_LABEL).trim() || ORACLE_ALARM_DEFAULT_LABEL;
  const alarmId = String(record?.id || '').trim();
  const notified = record?.notified !== false;
  const subtitle = notified
    ? 'Toque em Desativar para parar o alarme.'
    : 'Notificação do aparelho falhou. Use Desativar para parar o alarme.';

  try {
    removeOracleAlarmInlineBanner();

    const wrap = document.createElement('div');
    wrap.id = ORACLE_ALARM_INLINE_BANNER_ID;
    wrap.setAttribute('role', 'alert');
    wrap.setAttribute('aria-live', 'assertive');
    wrap.style.cssText = [
      'position:fixed',
      'left:12px',
      'right:12px',
      'top:calc(12px + env(safe-area-inset-top))',
      'z-index:25000',
      'border-radius:14px',
      'padding:12px',
      'border:1px solid rgba(255, 214, 130, 0.45)',
      'background:linear-gradient(160deg, rgba(28,18,9,0.96), rgba(17,11,6,0.98))',
      'box-shadow:0 16px 40px rgba(0,0,0,0.45)',
      'color:#ffe9bd',
      'display:flex',
      'flex-direction:column',
      'gap:8px'
    ].join(';');

    const title = document.createElement('div');
    title.style.cssText = 'font-weight:800;font-size:14px;line-height:1.3;';
    title.textContent = `⏰ ${label}`;

    const desc = document.createElement('div');
    desc.style.cssText = 'font-size:12px;opacity:0.92;line-height:1.35;';
    desc.textContent = subtitle;

    const actions = document.createElement('div');
    actions.style.cssText = 'display:flex;gap:8px;flex-wrap:wrap;';

    const stopBtn = document.createElement('button');
    stopBtn.type = 'button';
    stopBtn.textContent = 'Desativar';
    stopBtn.style.cssText = [
      'min-height:36px',
      'padding:0 14px',
      'border-radius:999px',
      'border:1px solid rgba(132,255,188,0.6)',
      'background:rgba(11,73,42,0.78)',
      'color:#eafff3',
      'font-weight:700',
      'cursor:pointer'
    ].join(';');
    stopBtn.addEventListener('click', () => {
      handleOracleAlarmNotificationAction(ORACLE_ALARM_ACTION_STOP, { alarmId: alarmId || null });
    });

    const hideBtn = document.createElement('button');
    hideBtn.type = 'button';
    hideBtn.textContent = 'Fechar aviso';
    hideBtn.style.cssText = [
      'min-height:36px',
      'padding:0 12px',
      'border-radius:999px',
      'border:1px solid rgba(255,255,255,0.28)',
      'background:rgba(255,255,255,0.08)',
      'color:#f6f1e2',
      'font-weight:600',
      'cursor:pointer'
    ].join(';');
    hideBtn.addEventListener('click', removeOracleAlarmInlineBanner);

    actions.appendChild(stopBtn);
    actions.appendChild(hideBtn);

    wrap.appendChild(title);
    wrap.appendChild(desc);
    wrap.appendChild(actions);
    document.body.appendChild(wrap);
  } catch (e) {
    console.warn('Falha ao mostrar aviso interno de alarme:', e);
  }
}

function stopOracleAlarmMusic(options = {}) {
  const silent = options?.silent === true;
  const closeNotification = options?.closeNotification !== false;

  if (oracleAlarmRingTimer) {
    clearInterval(oracleAlarmRingTimer);
    oracleAlarmRingTimer = null;
  }
  if (oracleAlarmRingAutoStopTimer) {
    clearTimeout(oracleAlarmRingAutoStopTimer);
    oracleAlarmRingAutoStopTimer = null;
  }
  oracleAlarmRingingRecordId = '';

  if (oracleAlarmCustomAudioElement) {
    try {
      oracleAlarmCustomAudioElement.pause();
      oracleAlarmCustomAudioElement.currentTime = 0;
    } catch (e) {}
  }

  if (closeNotification) {
    Promise.resolve(closeOracleAlarmNotifications()).catch(() => {});
  }
  removeOracleAlarmInlineBanner();

  if (!silent) {
    showToast('🔕 Alarme desativado.');
  }
}

function formatOracleAlarmWhen(fireAt) {
  try {
    const date = new Date(Number(fireAt) || Date.now());
    return date.toLocaleString('pt-BR', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit'
    });
  } catch (e) {
    return 'data inválida';
  }
}

function sanitizeOracleAlarmLabel(label) {
  const raw = String(label || ORACLE_ALARM_DEFAULT_LABEL).replace(/\s+/g, ' ').trim();
  const cut = raw.length > 80 ? raw.slice(0, 80).trim() : raw;
  return cut || ORACLE_ALARM_DEFAULT_LABEL;
}

function getOracleAlarmClockParts(fireAt) {
  const base = new Date(Number(fireAt) || Date.now());
  const target = new Date(base.getTime());
  if (target.getSeconds() > 0 || target.getMilliseconds() > 0) {
    target.setMinutes(target.getMinutes() + 1, 0, 0);
  } else {
    target.setSeconds(0, 0);
  }
  return {
    hour: target.getHours(),
    minute: target.getMinutes(),
    fireAt: target.getTime()
  };
}

function buildAndroidSetAlarmIntentUri({ hour = 0, minute = 0, label = ORACLE_ALARM_DEFAULT_LABEL } = {}) {
  const h = Math.max(0, Math.min(23, Number(hour) || 0));
  const m = Math.max(0, Math.min(59, Number(minute) || 0));
  const msg = encodeURIComponent(sanitizeOracleAlarmLabel(label));
  return (
    'intent:#Intent;' +
    'action=android.intent.action.SET_ALARM;' +
    `i.android.intent.extra.alarm.HOUR=${h};` +
    `i.android.intent.extra.alarm.MINUTES=${m};` +
    `S.android.intent.extra.alarm.MESSAGE=${msg};` +
    'B.android.intent.extra.alarm.SKIP_UI=false;' +
    'end'
  );
}

function getCapacitorAppLauncherPlugin() {
  try {
    const cap = window.Capacitor;
    if (!cap || !isNativeCapacitorPlatform()) return null;
    if (cap.Plugins && cap.Plugins.AppLauncher) return cap.Plugins.AppLauncher;
    if (typeof cap.registerPlugin === 'function') return cap.registerPlugin('AppLauncher');
  } catch (e) {}
  return null;
}

function getUrNativeBridge() {
  try {
    const bridge = window.URNative;
    if (bridge && typeof bridge === 'object') return bridge;
  } catch (e) {}
  return null;
}

function hasUrNativeAlarmBridge() {
  const bridge = getUrNativeBridge();
  if (!bridge) return false;
  return (
    typeof bridge.setAlarm === 'function' ||
    typeof bridge.openClock === 'function'
  );
}

function tryOpenClockWithUrBridge() {
  const bridge = getUrNativeBridge();
  if (!bridge || typeof bridge.openClock !== 'function') return false;
  try {
    return !!bridge.openClock();
  } catch (e) {
    console.warn('URNative.openClock falhou:', e);
    return false;
  }
}

function trySetAlarmWithUrBridge({ hour = 0, minute = 0, label = ORACLE_ALARM_DEFAULT_LABEL } = {}) {
  const bridge = getUrNativeBridge();
  if (!bridge || typeof bridge.setAlarm !== 'function') return false;
  try {
    return !!bridge.setAlarm(
      Math.max(0, Math.min(23, Number(hour) || 0)),
      Math.max(0, Math.min(59, Number(minute) || 0)),
      sanitizeOracleAlarmLabel(label)
    );
  } catch (e) {
    console.warn('URNative.setAlarm falhou:', e);
    return false;
  }
}

function trySetTimerWithUrBridge({ seconds = 0, label = ORACLE_ALARM_DEFAULT_LABEL } = {}) {
  const bridge = getUrNativeBridge();
  if (!bridge || typeof bridge.setTimer !== 'function') return false;
  const safeSeconds = Math.max(1, Math.floor(Number(seconds) || 0));
  if (!safeSeconds) return false;
  try {
    return !!bridge.setTimer(safeSeconds, sanitizeOracleAlarmLabel(label));
  } catch (e) {
    console.warn('URNative.setTimer falhou:', e);
    return false;
  }
}

function buildAndroidClockOpenCandidates(intentUri) {
  const candidates = [];
  const pushCandidate = (url) => {
    const safe = String(url || '').trim();
    if (!safe) return;
    if (!candidates.includes(safe)) candidates.push(safe);
  };

  pushCandidate(intentUri);
  pushCandidate('intent:#Intent;action=android.intent.action.SET_ALARM;package=com.sec.android.app.clockpackage;end');
  pushCandidate('intent:#Intent;action=android.intent.action.SET_ALARM;package=com.google.android.deskclock;end');
  pushCandidate('intent:#Intent;action=android.intent.action.MAIN;category=android.intent.category.LAUNCHER;package=com.sec.android.app.clockpackage;end');
  pushCandidate('intent:#Intent;action=android.intent.action.MAIN;category=android.intent.category.LAUNCHER;package=com.google.android.deskclock;end');
  pushCandidate('com.sec.android.app.clockpackage');
  pushCandidate('com.google.android.deskclock');
  return candidates;
}

function tryLaunchIntentWithoutPlugin(candidates = []) {
  const urls = (Array.isArray(candidates) ? candidates : [])
    .map((item) => String(item || '').trim())
    .filter((item) => item && item.includes(':'));

  if (!urls.length) return false;
  const target = urls[0];
  let attempted = false;

  try {
    if (document && document.body) {
      const iframe = document.createElement('iframe');
      iframe.style.display = 'none';
      iframe.setAttribute('aria-hidden', 'true');
      iframe.src = target;
      document.body.appendChild(iframe);
      setTimeout(() => {
        try { iframe.remove(); } catch (e) {}
      }, 900);
      attempted = true;
    }
  } catch (e) {}

  if (!attempted) {
    try {
      const anchor = document.createElement('a');
      anchor.href = target;
      anchor.rel = 'noopener noreferrer';
      anchor.style.display = 'none';
      document.body.appendChild(anchor);
      anchor.click();
      setTimeout(() => {
        try { anchor.remove(); } catch (e) {}
      }, 900);
      attempted = true;
    } catch (e) {}
  }

  if (!attempted) {
    try {
      window.location.href = target;
      attempted = true;
    } catch (e) {}
  }

  return attempted;
}

function tryLaunchAndroidAlarmIntent(intentUri, options = {}) {
  const uri = String(intentUri || '').trim();
  if (!uri) return false;

  if (hasUrNativeAlarmBridge()) {
    if (trySetAlarmWithUrBridge(options)) return true;
    return false;
  }

  if (!isNativeCapacitorPlatform() && !hasUrNativeAlarmBridge()) return false;

  try {
    const candidates = buildAndroidClockOpenCandidates(uri);
    return tryLaunchIntentWithoutPlugin(candidates);
  } catch (e) {
    console.warn('Falha ao tentar abrir alarme nativo:', e);
    return false;
  }
}

function openDeviceClockApp() {
  if (tryOpenClockWithUrBridge()) return true;
  return tryLaunchAndroidAlarmIntent(
    'intent:#Intent;action=android.intent.action.MAIN;category=android.intent.category.LAUNCHER;package=com.sec.android.app.clockpackage;end'
  );
}

function scheduleDeviceClockAlarm(options = {}) {
  const canUseNativeAlarm = isNativeCapacitorPlatform() || hasUrNativeAlarmBridge();
  if (!canUseNativeAlarm) {
    return { ok: false, reason: 'plataforma não nativa' };
  }

  const label = sanitizeOracleAlarmLabel(options?.label || ORACLE_ALARM_DEFAULT_LABEL);
  const rawFireAt = Number(options?.fireAt || 0);
  if (!Number.isFinite(rawFireAt) || rawFireAt <= Date.now() + 500) {
    return { ok: false, reason: 'horário inválido' };
  }

  const parts = getOracleAlarmClockParts(rawFireAt);
  const intentUri = buildAndroidSetAlarmIntentUri({
    hour: parts.hour,
    minute: parts.minute,
    label
  });
  const opened = tryLaunchAndroidAlarmIntent(intentUri, {
    hour: parts.hour,
    minute: parts.minute,
    label
  });
  if (!opened) {
    return { ok: false, reason: 'não consegui abrir o app Relógio' };
  }

  return {
    ok: true,
    mode: 'device-clock',
    hour: parts.hour,
    minute: parts.minute,
    label,
    fireAt: parts.fireAt,
    whenLabel: formatOracleAlarmWhen(parts.fireAt)
  };
}

function loadOracleAlarmRecords() {
  try {
    const parsed = JSON.parse(localStorage.getItem(ORACLE_ALARM_STORAGE_KEY) || '[]');
    const now = Date.now();
    return (Array.isArray(parsed) ? parsed : [])
      .map((item) => ({
        id: String(item?.id || '').trim(),
        label: String(item?.label || 'Alarme do Assistente').trim() || 'Alarme do Assistente',
        fireAt: Number(item?.fireAt || 0),
        createdAt: Number(item?.createdAt || now),
        source: String(item?.source || 'manual'),
        notificationId: Math.max(0, Number(item?.notificationId || 0) || 0)
      }))
      .filter((item) => item.id && Number.isFinite(item.fireAt) && item.fireAt > now - 60000);
  } catch (e) {
    return [];
  }
}

function saveOracleAlarmRecords(records) {
  try {
    localStorage.setItem(ORACLE_ALARM_STORAGE_KEY, JSON.stringify(Array.isArray(records) ? records : []));
  } catch (e) {}
}

function getOracleAlarms() {
  const now = Date.now();
  const records = loadOracleAlarmRecords()
    .filter((item) => item.fireAt > now)
    .sort((a, b) => a.fireAt - b.fireAt);
  return records.map((item) => ({
    ...item,
    whenLabel: formatOracleAlarmWhen(item.fireAt)
  }));
}

function removeOracleAlarmById(id) {
  const safeId = String(id || '').trim();
  if (!safeId) return false;
  if (oracleAlarmTimers.has(safeId)) {
    clearTimeout(oracleAlarmTimers.get(safeId));
    oracleAlarmTimers.delete(safeId);
  }
  const records = loadOracleAlarmRecords();
  const removed = records.filter((item) => item.id === safeId);
  const next = records.filter((item) => item.id !== safeId);
  const changed = next.length !== records.length;
  if (changed) {
    saveOracleAlarmRecords(next);
    const notificationIds = removed
      .map((item) => Number(item?.notificationId || 0))
      .filter((value) => Number.isFinite(value) && value > 0);
    if (notificationIds.length) {
      Promise.resolve(cancelOracleAlarmLocalNotificationsByIds(notificationIds)).catch(() => {});
    }
  }
  return changed;
}

function loadOracleAlarmCustomAudioPreference() {
  let dataUrl = '';
  let name = '';
  try {
    dataUrl = String(localStorage.getItem(ORACLE_ALARM_CUSTOM_AUDIO_DATA_KEY) || '').trim();
  } catch (e) {}
  try {
    const meta = JSON.parse(localStorage.getItem(ORACLE_ALARM_CUSTOM_AUDIO_META_KEY) || '{}');
    name = String(meta?.name || '').trim();
  } catch (e) {}

  if (!dataUrl || !dataUrl.startsWith('data:audio/')) {
    oracleAlarmCustomAudioDataUrl = '';
    oracleAlarmCustomAudioName = '';
    oracleAlarmCustomAudioPersisted = false;
    return false;
  }

  const bytes = getDataUrlBytes(dataUrl);
  if (!(bytes > 0)) {
    try { localStorage.removeItem(ORACLE_ALARM_CUSTOM_AUDIO_DATA_KEY); } catch (e) {}
    try { localStorage.removeItem(ORACLE_ALARM_CUSTOM_AUDIO_META_KEY); } catch (e) {}
    oracleAlarmCustomAudioDataUrl = '';
    oracleAlarmCustomAudioName = '';
    oracleAlarmCustomAudioPersisted = false;
    return false;
  }

  oracleAlarmCustomAudioDataUrl = dataUrl;
  oracleAlarmCustomAudioName = name;
  oracleAlarmCustomAudioPersisted = true;
  return true;
}

function persistOracleAlarmCustomAudioPreference() {
  const hasCustom = oracleAlarmCustomAudioDataUrl && oracleAlarmCustomAudioDataUrl.startsWith('data:audio/');
  if (!hasCustom) {
    try { localStorage.removeItem(ORACLE_ALARM_CUSTOM_AUDIO_DATA_KEY); } catch (e) {}
    try { localStorage.removeItem(ORACLE_ALARM_CUSTOM_AUDIO_META_KEY); } catch (e) {}
    oracleAlarmCustomAudioPersisted = false;
    return true;
  }

  try {
    localStorage.setItem(ORACLE_ALARM_CUSTOM_AUDIO_DATA_KEY, oracleAlarmCustomAudioDataUrl);
    localStorage.setItem(ORACLE_ALARM_CUSTOM_AUDIO_META_KEY, JSON.stringify({
      name: String(oracleAlarmCustomAudioName || '').trim().slice(0, 120),
      updatedAt: new Date().toISOString()
    }));
    oracleAlarmCustomAudioPersisted = true;
    return true;
  } catch (e) {
    console.warn('Falha ao salvar música personalizada do alarme:', e);
    oracleAlarmCustomAudioPersisted = false;
    return false;
  }
}

function clearOracleAlarmCustomAudioPreference({ silent = false } = {}) {
  oracleAlarmCustomAudioDataUrl = '';
  oracleAlarmCustomAudioName = '';
  persistOracleAlarmCustomAudioPreference();

  if (oracleAlarmCustomAudioElement) {
    try {
      oracleAlarmCustomAudioElement.pause();
      oracleAlarmCustomAudioElement.removeAttribute('src');
      oracleAlarmCustomAudioElement.load();
    } catch (e) {}
  }

  updateAlarmMusicSettingsUI();
  if (!silent) showToast('🔔 Música do alarme removida. Voltou para o som padrão.');
}

function readAlarmMusicFileAsDataUrl(file) {
  return new Promise((resolve, reject) => {
    try {
      const reader = new FileReader();
      reader.onload = () => resolve(String(reader.result || ''));
      reader.onerror = () => reject(reader.error || new Error('Falha ao ler arquivo de áudio.'));
      reader.readAsDataURL(file);
    } catch (e) {
      reject(e);
    }
  });
}

function ensureOracleAlarmCustomAudioElement() {
  if (oracleAlarmCustomAudioElement) return oracleAlarmCustomAudioElement;
  try {
    const audio = document.createElement('audio');
    audio.id = 'oracleAlarmCustomAudio';
    audio.preload = 'auto';
    audio.loop = true;
    audio.playsInline = true;
    audio.hidden = true;
    audio.volume = 1;
    document.body.appendChild(audio);
    oracleAlarmCustomAudioElement = audio;
  } catch (e) {
    oracleAlarmCustomAudioElement = null;
  }
  return oracleAlarmCustomAudioElement;
}

function startOracleAlarmFallbackBurstLoop() {
  if (oracleAlarmRingTimer) return;
  playOracleAlarmMusicBurst();
  oracleAlarmRingTimer = setInterval(() => {
    playOracleAlarmMusicBurst();
  }, ORACLE_ALARM_RING_CYCLE_MS);
}

function playOracleAlarmCustomTrack() {
  const dataUrl = String(oracleAlarmCustomAudioDataUrl || '').trim();
  if (!dataUrl || !dataUrl.startsWith('data:audio/')) return false;

  const audio = ensureOracleAlarmCustomAudioElement();
  if (!audio) return false;

  try {
    if (audio.src !== dataUrl) {
      audio.src = dataUrl;
    }
    audio.currentTime = 0;
    const maybe = audio.play();
    if (maybe && typeof maybe.then === 'function') {
      maybe.catch((error) => {
        console.warn('Falha ao tocar música personalizada do alarme:', error);
        if (oracleAlarmRingingRecordId) {
          startOracleAlarmFallbackBurstLoop();
        }
      });
    }
    return true;
  } catch (error) {
    console.warn('Falha ao iniciar música personalizada do alarme:', error);
    return false;
  }
}

function getAlarmMusicDisplayName() {
  const custom = String(oracleAlarmCustomAudioName || '').trim();
  if (custom) return custom;
  return 'arquivo personalizado';
}

function updateAlarmMusicSettingsUI() {
  const hasCustom = !!String(oracleAlarmCustomAudioDataUrl || '').trim();
  const customPersisted = hasCustom && !!oracleAlarmCustomAudioPersisted;
  const pickText = hasCustom ? '🎵 Trocar música do alarme' : '🎵 Música do alarme';
  const clearText = hasCustom ? '🧹 Remover música do alarme' : '🧹 Sem música personalizada';
  const statusText = hasCustom
    ? (customPersisted
      ? `Música do alarme: ${getAlarmMusicDisplayName()}`
      : `Música do alarme: ${getAlarmMusicDisplayName()} (apenas nesta sessão)`)
    : 'Música do alarme: padrão do app.';

  if (elements.alarmMusicPickBtn) elements.alarmMusicPickBtn.textContent = pickText;
  if (elements.drawerAlarmMusicPickBtn) elements.drawerAlarmMusicPickBtn.textContent = pickText;
  if (elements.alarmMusicClearBtn) {
    elements.alarmMusicClearBtn.textContent = clearText;
    elements.alarmMusicClearBtn.disabled = !hasCustom;
  }
  if (elements.drawerAlarmMusicClearBtn) {
    elements.drawerAlarmMusicClearBtn.textContent = clearText;
    elements.drawerAlarmMusicClearBtn.disabled = !hasCustom;
  }
  if (elements.alarmMusicStatusLabel) {
    elements.alarmMusicStatusLabel.textContent = statusText;
  }
}

// Marca que o bloco de alarme já terminou bootstrap antes de atualizar sua UI.
globalThis.__urAlarmMusicReady = true;

// Carrega a preferência de áudio somente depois da inicialização completa
// do bloco de alarmes (evita acessar variáveis antes da hora).
try {
  loadOracleAlarmCustomAudioPreference();
} catch (e) {
  console.warn('Falha ao carregar preferência de música do alarme:', e);
  oracleAlarmCustomAudioDataUrl = '';
  oracleAlarmCustomAudioName = '';
  oracleAlarmCustomAudioPersisted = false;
}
try {
  updateAlarmMusicSettingsUI();
} catch (e) {
  console.warn('Falha ao iniciar UI de música do alarme:', e);
}

async function handleAlarmMusicFileSelection(file) {
  if (!file) return false;
  const mime = String(file.type || '').toLowerCase();
  const isAudio = mime.startsWith('audio/') || /\.(mp3|wav|ogg|m4a|aac|flac|webm)$/i.test(String(file.name || ''));
  if (!isAudio) {
    showToast('⚠️ Escolha um arquivo de áudio válido (mp3, wav, m4a, etc).');
    return false;
  }

  try {
    const dataUrl = await readAlarmMusicFileAsDataUrl(file);
    if (!String(dataUrl || '').startsWith('data:audio/')) {
      showToast('⚠️ Não consegui usar esse áudio.');
      return false;
    }
    const dataBytes = getDataUrlBytes(dataUrl);
    if (!(dataBytes > 0)) {
      showToast('⚠️ Não consegui usar esse áudio.');
      return false;
    }

    oracleAlarmCustomAudioDataUrl = dataUrl;
    oracleAlarmCustomAudioName = String(file.name || 'audio personalizado').trim().slice(0, 120);
    const saved = persistOracleAlarmCustomAudioPreference();
    updateAlarmMusicSettingsUI();
    if (saved) {
      showToast('✅ Música do alarme atualizada!');
    } else {
      showToast('✅ Música aplicada, mas arquivo grande não foi salvo para reinício do app.');
    }
    return true;
  } catch (e) {
    console.warn('Falha ao processar música personalizada do alarme:', e);
    showToast('❌ Não consegui carregar essa música.');
    return false;
  }
}

function handleOracleAlarmNotificationAction(actionId = '', payload = {}) {
  const action = normalizeNotificationActionId(actionId);
  if (action !== ORACLE_ALARM_ACTION_STOP) return false;

  const alarmId = String(
    payload?.alarmId ||
    payload?.id ||
    payload?.extra?.alarmId ||
    ''
  ).trim();

  if (alarmId) {
    removeOracleAlarmById(alarmId);
    if (oracleAlarmRingingRecordId && oracleAlarmRingingRecordId === alarmId) {
      stopOracleAlarmMusic({ silent: true, closeNotification: true });
      showToast('🔕 Alarme desativado.');
      return true;
    }
  }

  stopOracleAlarmMusic({ silent: false, closeNotification: true });
  return true;
}

async function fireOracleAlarm(record) {
  const safeRecord = record && typeof record === 'object' ? record : {};
  const id = String(safeRecord.id || '').trim();
  const label = String(safeRecord.label || 'Alarme do Assistente').trim() || 'Alarme do Assistente';
  let notified = false;

  startOracleAlarmMusic(safeRecord);

  try {
    notified = await showNotificationViaSW('⏰ Alarme Universo Real', {
      body: label,
      tag: `ur-oracle-alarm-${id || Date.now()}`,
      category: 'alarm',
      highPriority: true,
      silent: false,
      renotify: true,
      forceNew: true,
      data: { type: 'oracle-alarm', target: 'oracle-alarm', alarmId: id || null },
      actions: [ { action: ORACLE_ALARM_ACTION_STOP, title: 'Desativar' } ]
    });
  } catch (e) {
    console.warn('Falha ao disparar notificação de alarme:', e);
  }
  showOracleAlarmInlineBanner({ id, label, notified });

  try { playSound('achievement'); } catch (e) {}
  try { triggerHaptic([120, 80, 120]); } catch (e) {}
  try {
    const hint = notified
      ? 'Toque em "Desativar" na notificação para parar.'
      : 'Notificação indisponível neste momento. Use o botão "Desativar" no aviso da tela.';
    showToast(`⏰ Alarme: ${label}. ${hint}`, 6000);
  } catch (e) {}

  if (id) removeOracleAlarmById(id);
}

function armOracleAlarmTimer(record) {
  if (!record || !record.id) return;
  if (oracleAlarmTimers.has(record.id)) {
    clearTimeout(oracleAlarmTimers.get(record.id));
    oracleAlarmTimers.delete(record.id);
  }

  const now = Date.now();
  const delay = Number(record.fireAt || 0) - now;

  if (!Number.isFinite(delay) || delay <= 0) {
    const timer = setTimeout(() => fireOracleAlarm(record), 12);
    oracleAlarmTimers.set(record.id, timer);
    return;
  }

  if (delay > ORACLE_ALARM_MAX_TIMEOUT_MS) {
    const timer = setTimeout(() => armOracleAlarmTimer(record), ORACLE_ALARM_MAX_TIMEOUT_MS);
    oracleAlarmTimers.set(record.id, timer);
    return;
  }

  const timer = setTimeout(() => fireOracleAlarm(record), delay);
  oracleAlarmTimers.set(record.id, timer);
}

function createInternalOracleAlarmRecord({ label = ORACLE_ALARM_DEFAULT_LABEL, fireAt = 0, source = 'manual' } = {}) {
  const now = Date.now();
  const safeFireAt = Number(fireAt || 0);
  if (!Number.isFinite(safeFireAt) || safeFireAt <= now + 500) return null;

  const generatedId = `alarm_${now}_${Math.random().toString(36).slice(2, 8)}`;
  const notificationId = isNativeCapacitorPlatform()
    ? buildOracleAlarmNotificationId(generatedId)
    : 0;
  const record = {
    id: generatedId,
    label: String(label || ORACLE_ALARM_DEFAULT_LABEL).trim() || ORACLE_ALARM_DEFAULT_LABEL,
    fireAt: safeFireAt,
    createdAt: now,
    source: String(source || 'manual'),
    notificationId
  };

  const records = loadOracleAlarmRecords();
  records.push(record);
  saveOracleAlarmRecords(records);
  armOracleAlarmTimer(record);
  if (isNativeCapacitorPlatform()) {
    Promise.resolve(scheduleOracleAlarmLocalNotification(record))
      .then((ok) => {
        if (!ok) {
          console.warn('Falha ao agendar notificação nativa do alarme; timer interno seguirá como fallback.');
          try {
            showToast('⚠️ Não consegui agendar notificação do Android. Verifique a permissão de notificações do app.');
          } catch (e) {}
        }
      })
      .catch((e) => {
        console.warn('Erro ao agendar notificação nativa do alarme:', e);
        try {
          showToast('⚠️ Erro ao agendar notificação do alarme no Android.');
        } catch (err) {}
      });
  }
  return record;
}

function scheduleOracleAlarm(options = {}) {
  const label = String(options?.label || ORACLE_ALARM_DEFAULT_LABEL).trim() || ORACLE_ALARM_DEFAULT_LABEL;
  const fireAt = Number(options?.fireAt || 0);
  const now = Date.now();

  if (!Number.isFinite(fireAt) || fireAt <= now + 500) {
    return { ok: false, reason: 'horário inválido' };
  }

  const nativeMode = isNativeCapacitorPlatform() || hasUrNativeAlarmBridge();
  let nativeFallbackReason = '';
  if (nativeMode) {
    const nativeCreated = scheduleDeviceClockAlarm({
      label,
      fireAt,
      source: options?.source
    });
    if (nativeCreated?.ok) {
      // Sempre cria backup interno no app para evitar perda em variações do Android/Relógio.
      const backup = createInternalOracleAlarmRecord({
        label,
        fireAt,
        source: `oracle-native-backup:${String(nativeCreated.mode || 'native')}`
      });
      if (backup) {
        nativeCreated.backupInternal = true;
        nativeCreated.backupId = backup.id;
      } else {
        nativeCreated.backupInternal = false;
      }
      return nativeCreated;
    }
    nativeFallbackReason = String(nativeCreated?.reason || 'nao consegui abrir o app Relogio do telefone');
    Promise.resolve(ensureNotificationPermission()).catch(() => {});
  }

  const record = createInternalOracleAlarmRecord({
    label,
    fireAt,
    source: String(options?.source || 'manual')
  });
  if (!record) return { ok: false, reason: 'horário inválido' };

  return {
    ok: true,
    id: record.id,
    whenLabel: formatOracleAlarmWhen(record.fireAt),
    mode: nativeMode ? 'internal-native-fallback' : 'internal',
    reason: nativeFallbackReason
  };
}

function clearOracleAlarms() {
  stopOracleAlarmMusic({ silent: true, closeNotification: true });
  const records = loadOracleAlarmRecords();
  const notificationIds = records
    .map((item) => Number(item?.notificationId || 0))
    .filter((value) => Number.isFinite(value) && value > 0);
  records.forEach((item) => {
    if (oracleAlarmTimers.has(item.id)) {
      clearTimeout(oracleAlarmTimers.get(item.id));
      oracleAlarmTimers.delete(item.id);
    }
  });
  saveOracleAlarmRecords([]);
  if (notificationIds.length) {
    Promise.resolve(cancelOracleAlarmLocalNotificationsByIds(notificationIds)).catch(() => {});
  }
  return records.length;
}

function bootstrapOracleAlarms() {
  const records = loadOracleAlarmRecords();
  saveOracleAlarmRecords(records);
  records.forEach((record) => {
    if (record.fireAt > Date.now()) armOracleAlarmTimer(record);
    else fireOracleAlarm(record);
  });
}

function parseOracleAlarmInput(rawText = '') {
  const text = String(rawText || '').trim();
  const lower = text.toLowerCase();
  if (!text || !/(alarme|despertador)/.test(lower)) return null;

  const now = Date.now();
  let fireAt = 0;
  let whenLabel = '';

  const secMatch = lower.match(/(?:em\s+)?(\d{1,4})\s*(s|seg|segundo|segundos)\b/i);
  const minMatch = lower.match(/(?:em\s+)?(\d{1,4})\s*(m|min|minuto|minutos)\b/i);
  const hourMatch = lower.match(/(?:em\s+)?(\d{1,3})\s*(h|hora|horas)\b/i);
  const clockMatch = lower.match(/\b([01]?\d|2[0-3])[:h]([0-5]\d)\b/);

  if (secMatch) {
    fireAt = now + (Number(secMatch[1]) * 1000);
    whenLabel = `em ${Number(secMatch[1])} segundo(s)`;
  } else if (minMatch) {
    fireAt = now + (Number(minMatch[1]) * 60000);
    whenLabel = `em ${Number(minMatch[1])} minuto(s)`;
  } else if (hourMatch) {
    fireAt = now + (Number(hourMatch[1]) * 3600000);
    whenLabel = `em ${Number(hourMatch[1])} hora(s)`;
  } else if (clockMatch) {
    const hh = Number(clockMatch[1]);
    const mm = Number(clockMatch[2]);
    const target = new Date();
    target.setSeconds(0, 0);
    target.setHours(hh, mm, 0, 0);
    if (target.getTime() <= now + 1000) {
      target.setDate(target.getDate() + 1);
    }
    fireAt = target.getTime();
    whenLabel = `às ${String(hh).padStart(2, '0')}:${String(mm).padStart(2, '0')}`;
  }

  if (!Number.isFinite(fireAt) || fireAt <= now + 500) return null;

  let label = 'Alarme do Assistente';
  const labelMatch = text.match(/(?:para|sobre|lembrar(?: de)?|lembrete(?: de| para)?)\s+(.+)$/i);
  if (labelMatch && labelMatch[1]) {
    label = String(labelMatch[1]).trim();
  } else if (/teste/.test(lower)) {
    label = 'Teste de alarme';
  }

  return {
    fireAt,
    label,
    whenLabel: whenLabel || formatOracleAlarmWhen(fireAt)
  };
}

bootstrapOracleAlarms();

// Recebe mensagens do Service Worker (ex: ação de notificação)
if (navigator.serviceWorker && navigator.serviceWorker.addEventListener) {
  navigator.serviceWorker.addEventListener('message', (evt) => {
    try {
      const d = evt.data;
      if (!d) return;
      if (d.type === 'WORK_TIMER_ACTION' && d.action === 'pause') {
        if (window.WorkTimer && typeof window.WorkTimer.stop === 'function') {
          window.WorkTimer.stop();
        }
      } else if (d.type === 'PLAYER_ROOM_BLESS_ACTION') {
        handleNotificationActionFromPayload(
          String(d.action || PLAYER_ROOM_BLESS_ACCEPT_ACTION || '').trim(),
          d
        );
      } else if (d.type === 'ORACLE_ALARM_ACTION') {
        handleOracleAlarmNotificationAction(d.action || '', d);
      } else if (d.type === 'OPEN_URL' && d.url) {
        try { window.location.href = d.url; } catch (e) { /* ignore */ }
      }
    } catch (e) { /* ignore */ }
  });
}

function openPlayerRoomFromNotificationPayload(payload = {}) {
  let opened = false;
  try {
    if (typeof OracleChat !== 'undefined' && OracleChat && typeof OracleChat.openSectionFromOracle === 'function') {
      opened = !!OracleChat.openSectionFromOracle('room');
    }
  } catch (e) {
    console.warn('Falha ao abrir sala via OracleChat (notificação):', e);
  }

  if (!opened) {
    const btn = document.querySelector('.tab-btn[data-tab="room"]')
      || document.querySelector('.mobile-drawer-item.tab-btn[data-tab="room"]')
      || document.querySelector('[data-tab="room"]');
    if (btn && typeof btn.click === 'function') {
      try {
        btn.click();
        opened = true;
      } catch (e) {
        console.warn('Falha ao clicar na aba da sala (notificação):', e);
      }
    }
  }

  if (!opened) {
    try {
      document.querySelectorAll('.tab-content').forEach((c) => c.classList.remove('active'));
      document.querySelectorAll('[data-tab]').forEach((b) => b.classList.remove('active'));
      document.querySelectorAll('[data-tab="room"]').forEach((b) => b.classList.add('active'));
      const roomTab = document.getElementById('tab-room');
      if (roomTab) {
        roomTab.classList.add('active');
        opened = true;
      }
    } catch (e) {
      console.warn('Falha ao ativar sala manualmente (notificação):', e);
    }
  }

  if (opened) {
    Promise.resolve(ensurePlayerRoomConnection({ silent: false, force: false })).catch((e) => {
      console.warn('Falha ao reconectar sala após toque na notificação:', e);
    });
    const target = String(payload?.target || payload?.type || '').trim().toLowerCase();
    if (target.includes('call')) {
      showToast('📞 Você abriu a notificação de ligação. Toque no card da chamada para entrar.');
    }
  }
  return opened;
}

function handleNativeLaunchPayload(payload = {}) {
  const safe = payload && typeof payload === 'object' ? payload : {};
  const actionId = normalizeNotificationActionId(
    safe.action ||
    safe.actionId ||
    safe.notificationAction ||
    safe.notificationActionId ||
    safe?.data?.action ||
    ''
  );
  if (actionId) {
    const handledAction = handleNotificationActionFromPayload(actionId, safe);
    if (handledAction) return true;
  }

  const target = String(safe.target || safe.type || '').trim().toLowerCase();
  if (!target) return false;
  if (target.includes('oracle-alarm') || target === 'alarm' || target === 'oracle-alarm') {
    if (actionId === ORACLE_ALARM_ACTION_STOP) {
      return handleOracleAlarmNotificationAction(actionId, safe);
    }
    return true;
  }
  if (
    target === 'player-room' ||
    target === 'room-message' ||
    target === 'room-call' ||
    target === 'room' ||
    target === 'call' ||
    target.includes('room') ||
    target.includes('call')
  ) {
    return openPlayerRoomFromNotificationPayload(safe);
  }
  return false;
}

function consumeNativeLaunchPayloadFromBridge() {
  const bridge = getUrNativeBridge();
  if (!bridge || typeof bridge.consumeLaunchPayload !== 'function') return false;
  try {
    const raw = bridge.consumeLaunchPayload();
    const payload = safeParseNativeJson(raw, {});
    if (!payload || typeof payload !== 'object') return false;
    return handleNativeLaunchPayload(payload);
  } catch (e) {
    console.warn('Falha ao consumir payload de abertura nativa:', e);
    return false;
  }
}

window.addEventListener('urnative-launch', (event) => {
  try {
    const detail = event && typeof event === 'object' ? (event.detail || {}) : {};
    handleNativeLaunchPayload(detail);
  } catch (e) {
    console.warn('Falha no evento urnative-launch:', e);
  }
});

window.addEventListener('focus', () => {
  setTimeout(() => { consumeNativeLaunchPayloadFromBridge(); }, 90);
});

document.addEventListener('visibilitychange', () => {
  if (document.visibilityState === 'visible') {
    setTimeout(() => { consumeNativeLaunchPayloadFromBridge(); }, 90);
  }
});

setTimeout(() => { consumeNativeLaunchPayloadFromBridge(); }, 350);

function consumeNotificationActionFromQueryParams() {
  try {
    const search = window.location?.search || '';
    if (!search) return false;
    const params = new URLSearchParams(search);
    const target = String(params.get('target') || '').trim().toLowerCase();
    const action = normalizeNotificationActionId(params.get('action') || '');
    const alarmId = String(params.get('alarmId') || '').trim();
    const blessId = String(params.get('blessId') || '').trim();
    const blessSender = String(params.get('blessSender') || '').trim();
    const blessTargetId = String(params.get('blessTargetId') || '').trim();
    const blessTargetName = String(params.get('blessTargetName') || '').trim();
    if (!target && !action) return false;

    let handled = false;
    if (action) {
      handled = handleNotificationActionFromPayload(action, {
        target,
        type: target,
        alarmId: alarmId || null,
        messageId: blessId || '',
        senderName: blessSender || '',
        targetUserId: blessTargetId || '',
        targetUsername: blessTargetName || ''
      }) || handled;
    }

    if (handled && window.history && typeof window.history.replaceState === 'function') {
      const cleanUrl = `${window.location.pathname}${window.location.hash || ''}`;
      window.history.replaceState({}, document.title, cleanUrl);
    }
    return handled;
  } catch (e) {
    return false;
  }
}

setTimeout(() => { consumeNotificationActionFromQueryParams(); }, 420);


