// -------------------------------
// Navegação móvel interna (previne saída do PWA no mobile)
// -------------------------------
(function(){
  function shouldUseMobileHashRouting() {
    try {
      return window.matchMedia && window.matchMedia('(max-width: 900px)').matches;
    } catch (e) {
      return window.innerWidth <= 900;
    }
  }

  const MOBILE_NAV_VIEWS = new Set(['home', 'oraculo', 'sala', 'tarefas', 'bible', 'financeiro', 'finance', 'ia', 'work', 'trabalho', 'poker', 'arena']);

  function normalizeMobileView(view) {
    const raw = String(view || '').trim().toLowerCase();
    if (raw === 'finance') return 'financeiro';
    if (raw === 'work') return 'trabalho';
    if (raw === 'arena') return 'poker';
    return raw;
  }

  function setMobileNavActive(view) {
    const safeView = normalizeMobileView(view);
    document.querySelectorAll('#mobile-nav .nav-btn').forEach((btn) => {
      const isMore = btn.classList.contains('more-btn');
      if (isMore) {
        btn.classList.remove('active');
        btn.setAttribute('aria-pressed', 'false');
        return;
      }
      const btnView = normalizeMobileView(btn.getAttribute('data-view') || '');
      const isActive = btnView === safeView;
      btn.classList.toggle('active', isActive);
      btn.setAttribute('aria-pressed', isActive ? 'true' : 'false');
    });
  }

  function activateTabFallback(tabId) {
    const safeTabId = String(tabId || '').trim().toLowerCase();
    if (!safeTabId) return false;
    const target = document.getElementById(`tab-${safeTabId}`);
    if (!target) return false;

    try {
      document.querySelectorAll('.tab-content').forEach((c) => c.classList.remove('active'));
      target.classList.add('active');
      document.querySelectorAll(`.tab-btn[data-tab="${safeTabId}"]`).forEach((b) => b.classList.add('active'));
      document.querySelectorAll(`.mobile-drawer-item.tab-btn[data-tab="${safeTabId}"]`).forEach((b) => b.classList.add('active'));
      if (typeof setBibleScrollLock === 'function') {
        setBibleScrollLock(safeTabId === 'bible');
      }
      if (safeTabId === 'dom' && typeof renderWorkTab === 'function') {
        try { renderWorkTab(); } catch (e) {}
      }
      if (safeTabId === 'finance' && typeof renderFinances === 'function') {
        try { renderFinances(); } catch (e) {}
      }
      if (safeTabId === 'room' && typeof ensurePlayerRoomConnection === 'function') {
        ensurePlayerRoomConnection({ silent: false }).catch(() => {});
      }
      return true;
    } catch (e) {
      console.warn('Falha no fallback de ativação de aba:', e);
      return false;
    }
  }

  function openTabViaMainNav(tabId) {
    const safeTabId = String(tabId || '').trim().toLowerCase();
    if (!safeTabId) return false;
    try {
      if (typeof OracleChat !== 'undefined' && OracleChat && typeof OracleChat.openTabFromOracle === 'function') {
        const ok = !!OracleChat.openTabFromOracle(safeTabId);
        if (ok) return true;
      }
    } catch (e) {
      console.warn('Falha ao abrir aba via OracleChat:', e);
    }
    const tab = document.querySelector(`.tab-btn[data-tab="${safeTabId}"]`);
    if (tab && typeof tab.click === 'function') {
      tab.click();
      const target = document.getElementById(`tab-${safeTabId}`);
      if (target?.classList?.contains('active')) return true;
      return activateTabFallback(safeTabId);
    }
    return activateTabFallback(safeTabId);
  }

  try { window.openTabViaMainNav = openTabViaMainNav; } catch (e) {}

  function showSplash(){
      const splash = document.getElementById('splashScreen');
      if (splash) {
        splash.classList.remove('hidden');
        // Esconde automaticamente o splash após um curto período
        setTimeout(() => {
          try { splash.classList.add('hidden'); } catch (e) { /* silencioso */ }
        }, 220);
      }
      const chatModal = document.getElementById('chatModal');
      if (chatModal) chatModal.classList.remove('open');
  }

  // Evita foco automático em dispositivos touch (abre teclado indesejado)
  function shouldAutoFocus() {
    try {
      if (typeof window === 'undefined') return true;
      if ('ontouchstart' in window) return false; // dispositivos touch não devem auto-focar
      if (navigator && /Mobi|Android|iPhone|iPad|iPod|Mobile/i.test(navigator.userAgent)) return false;
      return true;
    } catch (e) { return true; }
  }
  // Tornar disponível globalmente para handlers inline e scripts externos
  try { window.shouldAutoFocus = shouldAutoFocus; } catch(e) {}
  
  // Fecha ferramentas/modais/abas ativas antes de abrir nova ferramenta
  function closeActiveTools() {
    try {
      // Fecha modal de chat se aberto
      const chatModal = document.getElementById('chatModal');
      if (chatModal) { chatModal.classList.remove('open'); chatModal.classList.remove('active'); }
      syncOracleModalVisibilityState();

      // Fecha quaisquer modais abertos
      document.querySelectorAll('.modal.active').forEach(m => m.classList.remove('active'));

      // Remove aba Bíblia da DOM (será reinjetada quando abrir de novo)
      const bible = document.getElementById('tab-bible');
      if (bible) bible.remove();
      setBibleScrollLock(false);

      // Fecha drawer/mobile se houver função
      if (typeof closeDrawer === 'function') {
        try { closeDrawer(); } catch(e){}
      }

      // Esconde ações flutuantes (FAB)
      const fabActions = document.querySelector('.fab-actions') || document.getElementById('fabActions');
      if (fabActions) fabActions.classList.add('hidden');
    } catch (e) { /* silencioso */ }
  }
  // Expõe globalmente para handlers inline (onclick) e código externo
  try { window.closeActiveTools = closeActiveTools; } catch(e) {}
  function openOraculo(){
    if (openOracleChatModal()) return;

    // Fallback de emergência caso a inicialização falhe.
    const chatModal = document.getElementById('chatModal');
    if (chatModal) {
      chatModal.classList.add('open');
      chatModal.classList.add('active');
    }
    syncOracleModalVisibilityState();
    const input = document.getElementById('chatInput');
    if (input && shouldAutoFocus()) input.focus();
  }

  function openTarefas(){
    // troca para a aba de Missões/Tarefas e foca o input de tarefas
    openTabViaMainNav('quests');
    setTimeout(() => {
      const input = document.getElementById('taskInput') || document.querySelector('input[name="task"]');
      if (input && shouldAutoFocus()) input.focus();
    }, 120);
  }

  function openFinanceiro(){
    // troca para a aba de Finanças e foca o campo de descrição
    openTabViaMainNav('finance');
    setTimeout(() => {
      const input = document.getElementById('financeDesc') || document.querySelector('input[name="financeDesc"]');
      if (input && shouldAutoFocus()) input.focus();
    }, 120);
  }

  function openIA(){
    openTabViaMainNav('ia');
    setTimeout(() => {
      const input = document.getElementById('iaPromptInput');
      if (input && shouldAutoFocus()) input.focus();
    }, 120);
  }

  function openSala(){
    openTabViaMainNav('room');
  }

  function openTrabalho(){
    openTabViaMainNav('dom');
  }

  function openPoker(){
    openTabViaMainNav('arena');
  }

  function openBiblia(){
    // abre a aba Bíblia embutida (versão antiga)
    try {
      if (!document.getElementById('tab-bible') && typeof injectBibleTab === 'function') {
        injectBibleTab();
      }
      const opened = openTabViaMainNav('bible');
      if (!opened) {
        // fallback: ativa manualmente a aba se não existir botão
        document.querySelectorAll('.nav-item, .mobile-drawer-item, .mobile-nav-item, .nav-btn').forEach(b => b.classList.remove('active'));
        document.querySelectorAll('.tab-content').forEach(c => c.classList.remove('active'));
        document.querySelectorAll('[data-tab="bible"]').forEach(b => b.classList.add('active'));
        const content = document.getElementById('tab-bible');
        if (content) content.classList.add('active');
        setBibleScrollLock(true);
      }
    } catch (e) {
      console.warn('openBiblia falhou:', e);
    }
  }

    try { console.info('[UI] Aba Bíblia aberta'); } catch (e) {}

  function navigateTo(view, addHistory = true){
    const normalizedView = normalizeMobileView(view || 'home');
    switch(normalizedView){
      case 'home': {
        openTabViaMainNav('hero');
        break;
      }
      case 'oraculo': openOraculo(); break;
      case 'tarefas': openTarefas(); break;
      case 'financeiro': openFinanceiro(); break;
      case 'sala': openSala(); break;
      case 'ia': openIA(); break;
      case 'trabalho': openTrabalho(); break;
      case 'poker': openPoker(); break;
      case 'bible': openBiblia(); break;
      default: openTabViaMainNav('hero'); break;
    }
    if (MOBILE_NAV_VIEWS.has(normalizedView)) {
      setMobileNavActive(normalizedView);
    } else {
      setMobileNavActive('home');
    }
    if (addHistory) {
      try { history.pushState({ view: normalizedView }, '', '#' + normalizedView); } catch(e){}
    }
  }

  window.addEventListener('popstate', function(e){
    if (!shouldUseMobileHashRouting()) return;
    const state = (e.state && e.state.view) ? e.state.view : (location.hash ? location.hash.replace('#','') : 'home');
    navigateTo(state, false);
  });

  document.addEventListener('DOMContentLoaded', function(){
    // delegação de eventos na nav
    const nav = document.getElementById('mobile-nav');
    if (nav){
      nav.querySelectorAll('.nav-btn:not(.more-btn)').forEach((btn) => {
        btn.addEventListener('click', (e) => {
          try { e.preventDefault(); e.stopPropagation(); } catch (err) {}
          const view = btn.getAttribute('data-view') || 'home';
          if (typeof setPlayerRoomKeyboardMode === 'function') {
            try { setPlayerRoomKeyboardMode(false); } catch (err) {}
          }
          navigateTo(view, true);
        });
      });

      nav.addEventListener('click', function(e){
        const btn = e.target.closest && e.target.closest('.nav-btn');
        if (!btn) return;
        // Ignore 'more' button here — it has its own handler that opens the drawer
        if (btn.classList && btn.classList.contains('more-btn')) return;
        try { e.preventDefault(); e.stopPropagation(); } catch (err) {}
        const view = btn.getAttribute('data-view') || 'home';
        navigateTo(view, true);
      });
    }

    // Navegação por hash é exclusiva do layout mobile.
    if (shouldUseMobileHashRouting()) {
      const initial = location.hash ? location.hash.replace('#','') : 'home';
      navigateTo(initial, false);
    } else {
      setMobileNavActive('home');
    }
  });
})();


